  //declaration of function to avoid double function
  public function lookupsetup($config)
  {
    ini_set('memory_limit', '512M');
    $systemtype =  $this->companysetup->getsystemtype($config['params']);
    switch ($config['params']['action']) {
      case 'lookupdocno':
        return $this->lookupdocno($config);
        break;
      case 'lookupinvoice':
        return $this->lookupinvoice($config);
        break;
      case 'lookupclient':
      case 'lookupsqsupplier':
        switch ($config['params']['lookupclass']) {
          case "hbranch":
            if (strpos($systemtype, "HRIS") !== false) {
              return $this->hrislookup->lookuphbranch($config);
            } else {
              return $this->lookupclient($config);
            }

          default:
            return $this->lookupclient($config);
            break;
        }
        break;
      case 'customerlookup':
        return $this->customerlookup($config);
        break;
      case 'lookupconsignee':
        return $this->lookupconsignee($config);
        break;
      case 'lookupshipper':
        return $this->lookupshipper($config);
        break;
      case 'lookupheaddept':
        return $this->lookupheaddept($config);
        break;
      case 'lookupclientmod':
        return $this->lookupclientmod($config);
        break;
      case 'lookupledgerclient':
        if ($config['params']['lookupclass'] == 'lookupapplicant') {
          return $this->hrislookup->lookupledgerapplicant($config);
        } else {
          return $this->lookupledgerclient($config);
        }

        break;
      case 'lookupledger':
        return $this->lookupledger($config);
        break;
      case 'lookupledgerbuilding':
