  // declaration of lookup callback function
  public function lookupcallback($config)
  {
    switch ($config['params']['action']) {
      case 'computeterms':
        return $this->computeterms($config);
        break;
      case 'computetermsso':
        return $this->computetermsso($config);
        break;
      case 'computetermssh':
        return $this->computetermssh($config);
        break;
      case 'getcdsummaryshortcut':
      case 'getposummaryshortcut':
      case 'getsosummaryshortcut':
      case 'getdrsummaryshortcut':
      case 'getopsummaryshortcut':
      case 'getjbsummaryshortcut':
      case 'getqtssummaryshortcut':
      case 'getpcrsummaryshortcut':
      case 'getqtsummaryshortcut':
      case 'getpgsummaryshortcut':
      case 'getprsummaryshortcut':
      case 'getmrsummaryshortcut':
      case 'getbomshortcut':
      case 'sqmakepo':
      case 'makejo':
      case 'makepayment':
      case 'getapplicationform':
      case 'customereappsc':
      case 'getstrsummaryshortcut':
      case 'getplsummaryshortcut':
      case 'getapprovedtrsummary':
      case 'getloanapplication':
      case 'getqspcfsummaryshortcut':
        return $this->othersClass->generateShortcutTransaction($config);
        break;
      case 'statuslist':
        return $this->savestatus($config);
        break;
      case 'getcharges':
        $doc = $config['params']['doc'];
        $config['params']['action2'] = $config['params']['action'];
        $path = 'App\Http\Classes\modules\operation\\' . strtolower($doc);
        $qry = app($path)->headtablestatus($config);
        break;
      case 'getserialoutsingle': //cdo
        $doc = $config['params']['doc'];
        $config['params']['action2'] = $config['params']['action'];
        $path = 'App\Http\Classes\modules\cdo\\' . strtolower($doc);
        return $qry = app($path)->stockstatus($config);
        break;
      case 'getdp':
        $doc = $config['params']['doc'];
        $config['params']['action2'] = $config['params']['action'];
        $path = 'App\Http\Classes\modules\cdo\\' . strtolower($doc);
        return $qry = app($path)->stockstatus($config);
