  public function savestatus($config)
  {
    $config['params']['trno'] = $config['params']['row']['trno'];
    $isposted = $this->othersClass->isposted($config);
    if ($config['params']['row']['statusalias'] == 'ISSUE') { //issue option
      return ['status' => true, 'msg' => 'Status was successfully added.', 'action' => 'customform', 'access' => 'view', 'lookupclass' => 'dtaddstatus'];
    } else {
      if ($isposted) {
        $headtable = 'hdt_dthead';
        $stocktable = 'hdt_dtstock';
      } else {
        $headtable = 'dt_dthead';
        $stocktable = 'dt_dtstock';
      }
      $trno = $config['params']['row']['trno'];
      $userid = $this->coreFunctions->getfieldvalue('useraccess', 'userid', 'username=?', [$config['params']['user']]);
      $usertypeid = $this->coreFunctions->getfieldvalue('useraccess', 'accessid', 'username=?', [$config['params']['user']]);
      $dateid = date('Y-m-d H:i:s');
      $rows = [];

      $line = 0;
      $qry = "select line as value from $stocktable where trno=? order by line desc limit 1";
      $line = $this->coreFunctions->datareader($qry, [$trno]);
      if ($line == '') $line = 0;
      $line = $line + 1;

      $data = [
        'trno' => $trno,
        'line' => $line,
        'userid' => $userid,
        'usertypeid' => $usertypeid,
        'dateid' => $dateid,
        'docstatusid' => $config['params']['row']['id']
      ];
      if ($this->coreFunctions->sbcinsert($stocktable, $data) == 1) {
        $this->coreFunctions->execqry("update $headtable set currentstatusid=?, currentdate=?, currentuserid=?, currentusertypeid=? where trno=?", 'update', [$data['docstatusid'], $data['dateid'], $data['userid'], $data['usertypeid'], $data['trno']]);
        $stock = $this->othersClass->opendtstock($trno);
        return ['reloadgriddata' => ['inventory' => $stock], 'status' => true, 'msg' => 'Status was successfully added.',];
      } else {
        return ['status' => false, 'msg' => 'Add item failed'];
      }
    }
  }



