    if (isset($config['params']['search'])) {
      if ($config['params']['search'] != "") {
        $config['params']['search'] = $this->othersClass->sanitizekeyfield("itemname", $config['params']['search']);
      }
    }

    if (!isset($config['params']['action'])) {
      return ['status' => true, 'msg' => 'Not Allowed to search'];
    }
    switch ($config['params']['action']) {
      case 'clientsearch':
        switch (strtoupper($config['params']['doc'])) {
          case 'SJ':
          case 'CM':
          case 'CR':
          case 'KR':
          case 'RC':
          case 'AR':
            $data = $this->sqlquery->ClientSearch($config, 'customer');
