  //list of functions start here //help //legacy
  // $lookupsetup - array('type' => 'single','title' => 'List of Documents','style' => 'width:900px;max-width:900px;');

  // type - lookup type (string)
  // 1. 'single' - single selection w/ data on first load (more on textbox lookup)
  // 2. 'singlesearch.' - single selection but no data first until enter key press and
  //                     call api and return data to display in grid
  //   2.a 'actionsearch' - call api function - params('search') for search textbox value
  // 3. 'show' - list the data only/listing only, nothing happen during selection
  // 4. 'multi' - multi selection
  //    4.a 'rowkey' - for unique per record (sample trno)
  // title - title of lookup (string)
  // style - lookup style (width,height and etc) (string)
  // 1. sample style - "width:900px;max-width:900px;";

  // sample of $plotsetup - array('plottype'=>'call','action'=>'loadheaddata','callbackfieldhead' => array('dateid'),'callbackfieldlookup' => array('terms','days'),'plotting' => array('terms' => 'terms','due' => 'due'))

  // $plotsetup - regarding plotting (array)
  // plottype - how you want to plot after select  (string)
  // 1. 'plothead' - direct plot after select sa header ng mga module
  // 2. 'plotgrid' -
  // 3. 'plotemit' - plotting not setup(fixed element in quasar, same in enter qty in item lookup)
  // 4. 'callback' - call api after select
  // 5. 'plotledger' - plotting in view textbox
  // 6. 'show' - no action, just for show
  // action - if you select plottype = callback, required for function to execute in server
  // plotting - after select, choose what field to plot and where to plot(array)
  // 1. sample format - array('field1'=>'field2')
  // 1.a field1 - field from your head query(textbox name)(saan iplot)
  // 1.b field2 - field from your lookup query(ano iplot)
  // callbackfieldhead - field na nasa head na ibabato sa api(data and field ung ibabato)
  // callbackfieldlookup - field na nasa lookup qry na ibabato sa api(data and field ung ibabato)

  //01.10.2026
  //if searching ng item,customer,supplier na multiple and may comma- use type =singlesearch, and then actionsearch = qry ng searching base to sa lookupsearch na function

  //A
  public function lookupterms($config)
  {
    $filter = '';
    $lookupsetup = array(
      'type' => 'single',
      'title' => 'List of Terms',
      'style' => 'width:400px;max-width:400px;'
    );

    $callbackfieldhead = array('dateid');
    $defplotting = array('terms' => 'terms');

    switch ($config['params']['lookupclass']) {
      case 'ledgerterms':
      case "termspcf":
        if ($config['params']['companyid'] == 55 && $config['params']['doc'] == 'LE') { //afli
          $defplotting = array('terms' => 'terms', 'interest' => 'interest', 'pf' => 'pfnf', 'nf' => 'nf');
        }

        $plotsetup = array(
          'plottype' => 'plothead',
          'plotting' => $defplotting
        );
        break;
      case 'customterms':
      case 'customtermsaccess':
        $plotsetup = array(
          'plottype' => 'plotledger',
          'plotting' => array('terms' => 'terms')
        );

        if ($config['params']['companyid'] == 10 || $config['params']['companyid'] == 12) { //afti, afti usd
          $plotsetup = array(
            'plottype' => 'plotledger',
            'plotting' => array('terms' => 'terms', 'termsdetails' => 'terms')
          );
        }
        break;

      default:
        if ($config['params']['companyid'] == 19 && $config['params']['doc'] == 'SJ') { //housegem
          $callbackfieldhead = array('deldate');
        }
        $plotsetup = array(
          'plottype' => 'callback',
          'action' => 'computeterms',
          'callbackfieldhead' => $callbackfieldhead,
          'callbackfieldlookup' => array('terms', 'days'),
          'plotting' => array('terms' => 'terms', 'due' => 'due')
        );
        break;
    }

    // lookup columns
    $cols = array(
      array('name' => 'terms', 'label' => 'Terms', 'align' => 'left', 'field' => 'terms', 'sortable' => true, 'style' => 'font-size:16px;')
    );

    if ($config['params']['companyid'] == 10 || $config['params']['companyid'] == 12) { //afti, afti usd
      $allowterms = $this->othersClass->checkAccess($config['params']['user'], 4162);
      if ($config['params']['doc'] == 'QS') {
        if ($allowterms <> 1) {
          $filter = " where isnotallow =0 ";
        }
      }
      $qry = "select '' as terms, 0 as days,0 as line
            union all
            select terms,days,line from terms " . $filter . " order by line";
    } else {
      $qry = "select '' as terms, 0 as days,0 as line, 0 as interest, 0 as pfnf,0 as nf
            union all
            select terms,days,line,interest,pfnf,nf from terms order by line";
    }

    $data = $this->coreFunctions->opentable($qry);
    $btnadd = $this->sqlquery->checksecurity($config, 598, '/tableentries/tableentry/entryterms');
    return ['status' => true, 'msg' => 'ok', 'data' => $data, 'lookupsetup' => $lookupsetup, 'cols' => $cols, 'plotsetup' => $plotsetup, 'btnadd' => $btnadd];
  }

  //B
  public function computeterms($config)
  {
    if (isset($config['params']['deldate'])) {
      $newDate = new DateTime($config['params']['deldate']);
    } else {
      $newDate = new DateTime($config['params']['dateid']);
    }
    $odate = $newDate;
    if ($config['params']['days'] <= 0) {
      $config['params']['days'] = 0;
    }
    $days = preg_replace('/\D/', '', $config['params']['days']);
    $terms = new DateInterval('P' . $days . 'D');
    $newDate->add($terms);
    $data = array('terms' => $config['params']['terms'], 'due' => $newDate->format('Y-m-d'));

    $companyid = $config['params']['companyid'];

    $addedfield = "";
    $addedjoin = "";

    $whfield = ',client.wh';
    switch ($companyid) {
      case 6: //mitsukoshi
        $addedfield = " , ifnull(forwarder.clientid, 0) as truckid, ifnull(forwarder.clientname, '') as forwarder";
        $addedjoin = " left join client as forwarder on forwarder.clientid = client.truckid";
        break;
      case 8: //maxipro
        $addedfield = " , client.accountname, client.accountnum";
        break;
      case 10: //afti 
      case 12: //afti usd
        $addedfield = " , client.contact,client.email,client.tel,client.tax,client.vattype,client.shipcontactid,client.billcontactid,client.industry,client.ewtid,ifnull(ewt.code,'') as ewt,ifnull(ewt.rate,0) as ewtrate,
        concat(client.tax, '~', client.vattype) as dvattype,ifnull(category.cat_name,'') as catname,client.industryid";
        if ($config['params']['doc'] == 'OP') {
          $addedfield = " , client.tax,client.vattype,client.shipcontactid,client.billcontactid,client.industry,client.industryid,
                  concat(cp.salutation,cp.fname,' ',cp.mname,' ',cp.lname) as contact,cp.email,cp.contactno as tel,cp.department,cp.designation, concat(b.addrline1,' ',b.addrline2,' ',b.city,' ',b.province,' ',b.country,' ',b.zipcode) as shipaddr ";
        }
        $addedjoin = " left join contactperson as cp on cp.clientid = client.clientid and cp.line = client.shipcontactid left join billingaddr as b on b.clientid = client.clientid and b.line = client.shipid 
                       left join ewtlist as ewt on ewt.line = client.ewtid  left join category_masterfile as category on client.category = category.cat_id ";
        break;
      case 16: //ati
        $addedfield = ", client.vattype, case when client.vattype='Vat-registered' then 12 else 0 end as tax, client.prefix";
        break;
      case 22: //eipi
        $addedfield = ", ifnull(client.addr2,'') as shipto";
        break;
      case 23: //labsol cebu
      case 41: //labsol manila
      case 52: //technolab
        $addedfield = " , ifnull(ar.acnoname,'') as acnoname,client.tax,client.vattype,client.ass as contra";
        $addedjoin = " left join coa as ar on ar.acno = client.ass";
        break;
      case 26: //bee healthy
        $addedfield = ", client.clientname as label, client.addr as description2 ";
        break;
      case 32: //3m
        if ($config['params']['doc'] == 'SJ') {
          $addedfield = ", wh.clientid as whid, wh.client as wh, wh.clientname as whname";
          $addedjoin = " left join client as wh on wh.client=a.wh";
          $whfield = '';
        }
        break;
      case 36: //rozlab
        $addedfield = ", client.vattype, client.tax ";
        break;
    }

    if (isset($config['params']['client'])) {
      if ($companyid == 20 && $config['params']['doc'] == 'SO') { //proline
        $qry = "select client.clientid, client.client, client.clientname, client.addr, client.wh, ifnull(f.cur,'P') as cur, ifnull(f.curtopeso,1) as forex, client.terms,
        ifnull(a.client,'') as agentcode, ifnull(a.clientname,'') as agentname, '" . $newDate->format('Y-m-d') . "' as due, client.shipid, client.billid, client.tin, head.docno as ourref
        from hqthead as head left join client on client.client=head.client left join forex_masterfile as f on f.line=client.forexid left join client as a on a.client=client.agent
        where client.client='" . $config['params']['client'] . "'";
      } else {
        if ($companyid == 10 || $companyid == 12) { //afti, afti usd
          $qry = "select client.clientid,client.client,client.clientname,client.addr " . $whfield . "
        ,ifnull(f.cur,'P') as cur,ifnull(f.curtopeso,1) as forex,
        client.terms,ifnull(a.client,'') as agentcode, ifnull(a.clientname,'') as agentname,
        '" . $odate->format('Y-m-d') . "' as due, client.shipid, client.billid, client.tin
        " . $addedfield . "
        from client 
        left join forex_masterfile as f on f.line = client.forexid 
        left join client as a on a.client = client.agent 
        " . $addedjoin . "
        where client.client = '" . $config['params']['client'] . "'";
        } else {
          $qry = "select client.clientid,client.client,client.clientname,client.addr " . $whfield . "
        ,ifnull(f.cur,'P') as cur,ifnull(f.curtopeso,1) as forex,
        client.terms,ifnull(a.client,'') as agentcode, ifnull(a.clientname,'') as agentname,
        '" . $newDate->format('Y-m-d') . "' as due, client.shipid, client.billid, client.tin
        " . $addedfield . "
        from client 
        left join forex_masterfile as f on f.line = client.forexid 
        left join client as a on a.client = client.agent 
        " . $addedjoin . "
        where client.client = '" . $config['params']['client'] . "'";
        }
      }
      $data = $this->coreFunctions->opentable($qry);
      $data = $data[0];
    }
    return ['status' => true, 'msg' => 'ok', 'data' => $data];
  }


  //B
  public function computetermsso($config)
  {
    $newDate = new DateTime($config['params']['dateid']);

    $days = preg_replace('/\D/', '', $config['params']['days']);
    $terms = new DateInterval('P' . $days . 'D');
    $newDate->add($terms);
    $sotrno = $config['params']['trno'];
    $data = array('terms' => $config['params']['terms'], 'due' => $newDate->format('Y-m-d'));

    $companyid = $config['params']['companyid'];

    $addedfield = "";
    $addedjoin = "";
    if ($companyid == 6) { //mitsukoshi
      $addedfield = " , ifnull(forwarder.clientid, 0) as truckid, ifnull(forwarder.clientname, '') as forwarder";
      $addedjoin = " left join client as forwarder on forwarder.clientid = client.truckid";
    }

    switch ($config['params']['doc']) {
      case 'SD':
        $sodoc = 'sa';
        break;
      case 'SE':
        $sodoc = 'sb';
        break;
      case 'SF':
        $sodoc = 'sc';
        break;
    }

    if (isset($config['params']['client'])) {
      $qry = "select client.clientid,client.client,head.clientname,head.address as addr,
      client.wh,ifnull(head.cur,'P') as cur,ifnull(head.forex,1) as forex,
      head.terms,ifnull(agent.client,'') as agentcode, ifnull(agent.clientname,'') as agentname,
      '" . $newDate->format('Y-m-d') . "' as due, head.yourref, head.ourref, head.rem,
      head.deliverytype,dtype.name as deliverytypename,head.customername,head.tel
      " . $addedfield . "
      from h" . $sodoc . "head as head 
      left join h" . $sodoc . "stock as stock on stock.trno=head.trno 
      left join client on client.client=head.client 
      left join client as agent on agent.client = head.agent
      left join deliverytype as dtype on dtype.line=head.deliverytype
      " . $addedjoin . "
      where head.trno = '" . $sotrno . "'";
      $data = $this->coreFunctions->opentable($qry);
      $data = $data[0];
    }

    return ['status' => true, 'msg' => 'ok', 'data' => $data, 'qqr' => $qry];
  }

  public function computetermssh($config)
  {
    $newDate = new DateTime($config['params']['dateid']);
    $days = preg_replace('/\D/', '', $config['params']['days']);
    $terms = new DateInterval('P' . $days . 'D');
    $newDate->add($terms);
    $sotrno = $config['params']['trno'];
    $data = array('terms' => $config['params']['terms'], 'due' => $newDate->format('Y-m-d'));

    if (isset($config['params']['client'])) {
      $qry = "select client.clientid,client.client,head.clientname,head.address as addr,client.wh,ifnull(head.cur,'P') as cur,ifnull(head.forex,1) as forex,
      head.terms,ifnull(agent.client,'') as agentcode, ifnull(agent.clientname,'') as agentname,'" . $newDate->format('Y-m-d') . "' as due, head.yourref, head.ourref, head.rem,head.customername,
      head.deliverytype,dtype.name as deliverytypename,head.partreqtypeid,partrequest.name as partreqtype,
      ifnull(coa.acno,'') as contra, ifnull(coa.acnoname,'') as acnoname, concat(ifnull(coa.acno,''),'~',ifnull(coa.acnoname,'')) as dacnoname
      from hsghead as head left join hsgstock as stock on stock.trno=head.trno left join client on client.client=head.client left join client as agent on agent.client = head.agent
      left join deliverytype as dtype on dtype.line=head.deliverytype
      left join partrequest on partrequest.line = head.partreqtypeid
      left join coa on coa.acnoid = partrequest.acnoid
      where head.trno = '" . $sotrno . "'";
      $data = $this->coreFunctions->opentable($qry);
      $data = $data[0];
    }

    return ['status' => true, 'msg' => 'ok', 'data' => $data];
  }



