      array_push($cols, $col);
      $col = array('name' => 'region', 'label' => 'Region', 'align' => 'left', 'field' => 'region', 'sortable' => true, 'style' => 'font-size:16px;');
      array_push($cols, $col);
    } else {
      $col = array('name' => 'addr', 'label' => 'Address', 'align' => 'left', 'field' => 'addr', 'sortable' => true, 'style' => 'font-size:16px;');
      array_push($cols, $col);
    }


    return ['status' => true, 'msg' => 'ok', 'data' => [], 'lookupsetup' => $lookupsetup, 'cols' => $cols, 'plotsetup' => $plotsetup];
  }

