          case "DM":
          case "SO":
          case "SJ":
          case "CM":
          case "IS":
          case "AJ":
          case "TS":
          case "PC":
            $tablestock = app('App\Http\Classes\modules\\' . strtolower($config['params']['moduletype']) . '\\' . strtolower($config['params']['doc']))->stock;
            break;
          case "KR":
          case "CR":
          case "AR":
          case "AP":
          case "CV":
