          array_push($cols, array('name' => 'divname', 'label' => 'Company', 'align' => 'left', 'field' => 'divname', 'sortable' => true, 'style' => 'font-size:16px;'));
        }

        if ($config['params']['companyid'] == 63) { //ericco
          if ($config['params']['lookupclass'] == 'customer') {
            array_push($cols, array('name' => 'groupid', 'label' => 'Group', 'align' => 'left', 'field' => 'groupid', 'sortable' => true, 'style' => 'font-size:16px;'));
            array_push($cols, array('name' => 'agentname', 'label' => 'Agent Name', 'align' => 'left', 'field' => 'agentname', 'sortable' => true, 'style' => 'font-size:16px;'));
            array_push($cols, array('name' => 'area', 'label' => 'Area', 'align' => 'left', 'field' => 'area', 'sortable' => true, 'style' => 'font-size:16px;'));
            array_push($cols, array('name' => 'province', 'label' => 'Province', 'align' => 'left', 'field' => 'province', 'sortable' => true, 'style' => 'font-size:16px;'));
            array_push($cols, array('name' => 'region', 'label' => 'Region', 'align' => 'left', 'field' => 'region', 'sortable' => true, 'style' => 'font-size:16px;'));
          }
        }

        break;
    }

    //lookupquery client
    switch ($config['params']['lookupclass']) {
      case 'customerdr':
        $qry = "select head.trno,head.docno,left(head.dateid,10) as dateid,left(head.due,10) as due,
            client.client,client.clientname,head.address,head.shipto,
            head.yourref,head.ourref,head.terms,head.trnxtype,head.cur,head.forex,head.rem,head.vattype,
            head.agentid,head.tax,ifnull(agent.client,'') as agent,ifnull(agent.clientname,'') as agentname,ifnull(wh.client,'') as wh,head.contra
            from glhead as head
            left join cntnum on cntnum.trno = head.trno
            left join client on client.clientid=head.clientid
            left join client as agent on agent.clientid=head.agentid
            left join client as wh on wh.clientid=head.whid
            where head.doc in ('SJ') and cntnum.svnum=0
            group by head.trno,head.docno,head.dateid,client.client,client.clientname,head.address,head.shipto,head.yourref,head.ourref,head.terms,head.trnxtype,
            head.cur,head.forex,head.rem,head.vattype,head.agentid,head.due,head.tax,agent.client,agent.clientname,wh.client,head.contra";
        break;
      case 'customercor':
        $qry = "select head.trno as keyid ,head.trno as cotrno,head.docno as codocno,client.client,client.clientid,left(head.dateid,10) as dateid,head.clientname,
        ifnull(project.code,'') as projectcode,ifnull(project.name,'') as projectname,
        ph.code as phase,hm.model as housemodel,
        bl.blk as blklot, bl.lot,
        head.projectid, head.phaseid, head.modelid, head.blklotid,item.itemid,item.itemname
        from hcohead as head
        left join hcostock as stock on stock.trno = head.trno
        left join transnum as num on num.trno = head.trno
        left join hcihead as ci on ci.trno = head.citrno
        left join projectmasterfile as project on project.line=head.projectid
        left join phase as ph on ph.line = head.phaseid
        left join housemodel as hm on hm.line = head.modelid
        left join blklot as bl on bl.line = head.blklotid
        left join item on item.itemid = ci.itemid
        left join client on client.client = head.client
        where head.doc='CC' and num.pctrno =0 
        group by head.trno,head.docno,client.client,client.clientid,head.dateid,head.clientname,
        project.code,project.name, ph.code,hm.model,bl.blk, bl.lot,
        head.projectid, head.phaseid, head.modelid, head.blklotid,item.itemid,item.itemname "; //having sum(stock.qty)=sum(stock.miqa)";
        break;
      case 'sdcustomer':
      case 'secustomer':
      case 'sfcustomer':
        switch ($config['params']['lookupclass']) {
          case 'sdcustomer':
            $sodoc = 'sa';
            break;
          case 'secustomer':
            $sodoc = 'sb';
            break;
          case 'sfcustomer':
            $sodoc = 'sc';
            break;
        }
        $qry = "select head.trno,head.docno,date(head.dateid) as dateid,client.clientid,head.client,head.clientname,head.address as addr, head.agent as agentcode,agent.clientname as agentname,head.terms,ifnull(terms.days,0) as days,
            head.ourref,head.rem,head.deliverytype,dtype.name as deliverytypename,head.customername,head.tel,
            transnum.postdate,transnum.postedby
            from h" . $sodoc . "head as head 
            left join h" . $sodoc . "stock as stock on stock.trno=head.trno 
            left join client on client.client=head.client left join client as agent on agent.client=head.agent
            left join terms on terms.terms=head.terms 
            left join deliverytype as dtype on dtype.line = head.deliverytype
            left join transnum on transnum.trno=head.trno
            where stock.iss>stock.qa and stock.void=0 
            group by head.trno,head.docno,head.dateid,client.clientid,head.client,head.clientname,
            head.address,head.agent,agent.clientname,head.terms,terms.days,head.ourref,
            head.rem,head.deliverytype,head.customername,dtype.name,head.tel,transnum.postdate,transnum.postedby
            order by transnum.postdate desc
          ";

        break;
      case 'shcustomer':
        $qry = "select head.trno,head.docno,date(head.dateid) as dateid,client.clientid,head.client,
                       head.clientname,head.address as addr, head.agent as agentcode,agent.clientname as agentname,
                       head.terms,ifnull(terms.days,0) as days,head.ourref,head.rem,head.customername,
                       head.partreqtypeid, partrequest.name as partreqtype, head.deliverytype, 
                       dtype.name as deliverytypename,
                       ifnull(coa.acno,'') as contra, ifnull(coa.acnoname,'') as acnoname, 
                       concat(ifnull(coa.acno,''),'~',ifnull(coa.acnoname,'')) as dacnoname,
                       transnum.postdate,transnum.postedby
                from hsghead as head 
                left join hsgstock as stock on stock.trno=head.trno 
                left join client on client.client=head.client 
                left join client as agent on agent.client=head.agent
                left join terms on terms.terms=head.terms  
                left join deliverytype as dtype on dtype.line = head.deliverytype 
                left join partrequest on partrequest.line = head.partreqtypeid
                left join coa on coa.acnoid = partrequest.acnoid
                left join transnum on transnum.trno=head.trno
                where stock.iss<>stock.qa and stock.void=0
                group by head.trno,head.docno,head.dateid,client.clientid,head.client,head.clientname,head.address,head.agent,agent.clientname,head.terms,terms.days,head.ourref,head.rem,head.customername,
                          head.partreqtypeid,partrequest.name,head.deliverytype,dtype.name,coa.acno,coa.acnoname,transnum.postdate,transnum.postedby
                order by transnum.postdate desc";
        break;

      case 'jpcustomer':
        $qry = "select h.trno, h.clientid, client.client, h.clientname, client.addr, info.itemid, item.itemname, info.uom2 as uom, info.yield as qty, 
          FORMAT(ifnull((select sum(iss * cost)/ifnull(info.batchsize,0) from glstock where trno=h.trno),0),6) as amt, info.lotno
          from glhead as h left join hcntnuminfo as info on info.trno=h.trno left join item on item.itemid=info.itemid left join client on client.clientid=h.clientid
          where h.doc='JP' and h.invtagging=0";
        break;
      case 'pcfcustomer':
        $adminid = $config['params']['adminid'];
        $center = $config['params']['center'];
        $qry = "select head.trno as qtrno, head.docno, left(head.dateid, 10) as dateid,case head.yourref when '' then 'NO PO YET' else head.yourref end as yourref,head.client,head.clientname,agent.clientid as agentid,c.clientid,
        agent.client as agent,agent.clientname as agentname
        from hqshead as head 
        left join transnum as num on num.trno = head.trno
        left join hheadinfotrans as hi on hi.trno = num.trno
        left join client as c on c.client = head.client
        left join client as agent on agent.client = head.agent
        where num.center = $center
        and hi.dtctrno =0  
        group by head.trno, head.docno, head.dateid,head.yourref,head.client,head.clientname,agent.clientid,c.clientid,
        agent.client,agent.clientname 
        union all
        select head.trno as qtrno, head.docno, left(head.dateid, 10) as dateid,case head.yourref when '' then 'NO PO YET' else head.yourref end as yourref,head.client,head.clientname,agent.clientid as agentid,c.clientid,
        agent.client as agent,agent.clientname as agentname
        from qshead as head 
        left join transnum as num on num.trno = head.trno
        left join headinfotrans as hi on hi.trno = num.trno
        left join client as c on c.client = head.client
        left join client as agent on agent.client = head.agent
        where num.center = $center
        and hi.dtctrno =0 
        group by head.trno, head.docno, head.dateid,head.yourref,head.client,head.clientname,agent.clientid,c.clientid,
        agent.client,agent.clientname
        order by dateid desc";
        // and agent.clientid = $adminid
        //and agent.clientid = $adminid
        break;

      case 'sqcustomer':
        $qry = "select
        distinct qt.trno as qtrno, qt.docno, qt.client, qt.terms, qt.cur, qt.forex, 
        qt.yourref, qt.ourref, left(qt.dateid,10) as qtdateid,  qt.clientname, qt.address, qt.shipto, 
        qt.rem, ifnull(qt.agent, '') as agent, ifnull(agent.clientname, '') as agentname,
        '' as dagentname, qt.wh, warehouse.clientname as whname, '' as dwhname, 
        left(qt.due,10) as due,qt.branch,ifnull(b.clientname,'') as branchname,
        ifnull(b.client,'') as branchcode,qt.deptid,ifnull(d.client,'') as dept,
        ifnull(d.clientname,'') as deptname, qt.vattype, qt.tax,qt.deldate,client.tin,ifnull(category.cat_name,'') as businesstype
        from hqshead as qt
        left join client on client.client=qt.client
        left join client as agent on agent.client = qt.agent
        left join client as warehouse on warehouse.client = qt.wh
        left join client as b on b.clientid= qt.branch
        left join client as d on d.clientid = qt.deptid
        left join hqsstock as stock on stock.trno = qt.trno
        left join category_masterfile as category on category.cat_id=client.category
        where qt.sotrno=0 and stock.void =0 and stock.trno is not null";
        break;
      case 'srcustomer':
        $qry = "select qt.trno as srtrno, qt.docno, qt.client, qt.terms, qt.cur, qt.forex, qt.yourref, qt.ourref, left(qt.dateid,10) as qtdateid,  qt.clientname, qt.address, qt.shipto, 
        qt.rem, ifnull(qt.agent, '') as agent, ifnull(agent.clientname, '') as agentname,'' as dagentname, qt.wh, warehouse.clientname as whname, '' as dwhname, left(qt.due,10) as due,
        qt.branch,ifnull(b.clientname,'') as branchname,ifnull(b.client,'') as branchcode,qt.deptid,ifnull(d.client,'') as dept,ifnull(d.clientname,'') as deptname,h.billid,h.shipid,h.shipcontactid,h.billcontactid
        from hsrhead as qt left join client as agent on agent.client = qt.agent left join client as warehouse on warehouse.client = qt.wh left join client as b on b.clientid= qt.branch left join client as d on d.clientid = qt.deptid left join hqshead as h on h.trno = qt.qtrno where qt.sotrno=0";
        break;
      case 'customer10':
        $qry = "select head.sotrno, head.trno, so.docno, date(so.dateid) as dateid, head.docno as qdocno, head.client, head.clientname, date(head.dateid) as qtdateid,
         head.terms, head.due, head.address, head.rem, head.agent, ifnull(agent.clientname, '') as agentname, head.yourref, head.ourref, head.cur, head.forex, head.wh,head.branch,
         ifnull(b.clientname,'') as branchname,ifnull(b.client,'') as branchcode,head.deptid,ifnull(d.client,'') as dept,ifnull(d.clientname,'') as deptname,ifnull(hi.taxdef,0) as taxdef, head.vattype, head.tax, head.billid, head.shipid, head.billcontactid,
          head.shipcontactid,c.ewt,c.ewtrate
        from hsqhead as so left join hqshead as head on head.sotrno=so.trno left join hqsstock as stock on stock.trno=head.trno 
        left join hheadinfotrans as hi on hi.trno = head.trno left join client as b on b.clientid= head.branch 
        left join client as agent on agent.client = head.agent left join client as d on d.clientid = head.deptid
        left join client as c on c.client = head.client
        where stock.iss > (stock.qa + stock.sjqa + stock.voidqty) and stock.void = 0
        group by head.sotrno, head.trno, so.docno, so.dateid, head.docno, head.client, 
        head.clientname, head.dateid, head.terms, head.due, head.address, head.rem, head.agent, head.yourref, head.ourref, head.cur, head.forex, head.wh,head.branch,b.clientname,b.client,agent.clientname,head.deptid,d.client,d.clientname,hi.taxdef, head.vattype, head.tax, head.billid, head.shipid, head.billcontactid,head.shipcontactid,c.ewt,c.ewtrate
        order by so.dateid desc";

        break;
      case 'customereapp':
      case 'customereappsc':
        $qry = "select distinct head.trno,head.trno as cptrno,head.docno,head.clientid,head.clientname,i.clientname as planholder,c.client,sum(ar.bal) as bal,
        c.addr,ag.client as agentcode,ag.clientname as agentname,head.aftrno,ifnull(pt.name,'') as plantype,i.idno from glhead as head
        left join heahead as ea on head.aftrno = ea.trno
        left join heainfo as i on i.trno = head.aftrno left join arledger as ar
        on ar.trno = head.trno left join client as c on c.clientid = head.clientid
        left join client as ag on ag.clientid = head.agentid left join plantype as pt on pt.line = ea.planid and pt.plangrpid = ea.plangrpid    where head.doc ='CP' and ar.bal <>0
        group by head.trno,head.docno,head.clientid,head.clientname,i.clientname,c.client,c.addr,ag.client ,ag.clientname,head.aftrno,pt.name,i.idno ";

        break;
      case 'customer10su':
        $qry = "select
        head.trno,head.docno,date(head.dateid) as dateid,
        head.docno as qdocno,head.client,head.clientname,
        date(head.dateid) as qtdateid,head.terms,head.due,
        head.address as addr, head.rem,head.agent as agentcode,
        ifnull(agent.clientname, '') as agentname, head.yourref, head.ourref,
        head.cur, head.forex, head.wh,
        head.branch,ifnull(b.clientname,'') as branchname,ifnull(b.client,'') as branchcode,
        if(head.vattype = 'NON-VATABLE',head.vattype,'') as vattype, if(head.vattype = 'VATABLE',12,0) as tax, '0' as billid, '0' as shipid,
        '0' as billcontactid, '0' as shipcontactid
        from hprhead as head
        left join hprstock as stock on stock.trno=head.trno
        left join client as b on b.clientid= head.branch
        left join client as agent on agent.client = head.agent
        where stock.qty > (stock.qa + stock.siqa) and stock.void = 0
        group by
        head.trno,
        head.docno, head.client,
        head.clientname, head.dateid, head.terms, head.due, head.address, head.rem,
        head.agent, head.yourref, head.ourref, head.cur, head.forex, head.wh,head.branch,
        b.clientname,b.client,agent.clientname,
        head.vattype";

        break;
      case 'customersi':
        $qry = "select head.sotrno, head.trno, so.docno, date(so.dateid) as dateid, head.docno as qdocno, head.client, head.clientname, date(head.dateid) as qtdateid, head.terms, 
        head.due, head.address, head.rem, head.agent, ifnull(agent.clientname, '') as agentname, head.yourref, head.ourref, head.cur, head.forex, head.wh,head.branch,
        ifnull(b.clientname,'') as branchname,ifnull(b.client,'') as branchcode,head.deptid,ifnull(d.client,'') as dept,ifnull(d.clientname,'') as deptname, head.shipid, 
        head.billid, head.shipcontactid, head.billcontactid, cl.tin,cl.ewt,cl.ewtrate,ifnull(hi.taxdef,0) as taxdef, head.vattype, head.tax
        from hsshead as so left join hsrhead as head on head.sotrno=so.trno left join hsrstock as stock on stock.trno=head.trno left join client as b on b.clientid= head.branch 
        left join client as agent on agent.client = head.agent left join client as d on d.clientid = head.deptid
        left join hheadinfotrans as hi on hi.trno = head.trno
        left join item on item.itemid = stock.itemid
        left join client as cl on cl.client = head.client
        where stock.qa <>0 and stock.iss > (stock.sjqa+stock.voidqty) and stock.void = 0 and item.isnoninv<>1
        group by head.sotrno, head.trno, so.docno, so.dateid, head.docno, head.client, head.clientname, head.dateid, head.terms, head.due, 
        head.address, head.rem, head.agent, head.yourref, head.ourref, head.cur, head.forex, head.wh,head.branch,b.clientname,b.client,agent.clientname,
        head.deptid,d.client,d.clientname, head.shipid, head.billid, head.shipcontactid, head.billcontactid, cl.tin,cl.ewt,cl.ewtrate,hi.taxdef,head.vattype,head.tax
        union all
        select head.sotrno, head.trno, so.docno, date(so.dateid) as dateid, head.docno as qdocno, head.client, head.clientname, date(head.dateid) as qtdateid, head.terms, 
        head.due, head.address, head.rem, head.agent, ifnull(agent.clientname, '') as agentname, head.yourref, head.ourref, head.cur, head.forex, head.wh,head.branch,
        ifnull(b.clientname,'') as branchname,ifnull(b.client,'') as branchcode,head.deptid,ifnull(d.client,'') as dept,ifnull(d.clientname,'') as deptname, head.shipid, 
        head.billid, head.shipcontactid, head.billcontactid, cl.tin,cl.ewt,cl.ewtrate,ifnull(hi.taxdef,0) as taxdef, head.vattype, head.tax
        from hsshead as so left join hsrhead as head on head.sotrno=so.trno left join hsrstock as stock on stock.trno=head.trno left join client as b on b.clientid= head.branch 
        left join client as agent on agent.client = head.agent left join client as d on d.clientid = head.deptid
        left join hheadinfotrans as hi on hi.trno = head.trno 
        left join item on item.itemid = stock.itemid
        left join client as cl on cl.client = head.client
        where item.isnoninv =1 and stock.iss > (stock.sjqa+stock.voidqty) and stock.void = 0
        group by head.sotrno, head.trno, so.docno, so.dateid, head.docno, head.client, head.clientname, head.dateid, head.terms, head.due, head.address, head.rem, 
        head.agent, head.yourref, head.ourref, head.cur, head.forex, head.wh,head.branch,b.clientname,b.client,agent.clientname,head.deptid,d.client,d.clientname,
         head.shipid, head.billid, head.shipcontactid, head.billcontactid, cl.tin,cl.ewt,cl.ewtrate,hi.taxdef,head.vattype,head.tax";
        break;
      case 'wbsupplier':
        $qry = "select client.client, head.clientname, client.addr
        from hwahead as head
        left join client on client.clientid=head.clientid
        left join hwastock as stock on stock.trno = head.trno
        left join transnum on transnum.trno = head.trno
        where stock.qty>stock.qa and stock.void = 0
        group by client.client, head.clientname, client.addr";
        break;
      case 'opportunity':
        $qry = "select client.clientid,client.client,client.clientname,client.addr,client.wh,ifnull(f.cur,'P') as cur,ifnull(f.curtopeso,1) as forex,client.terms,ifnull(a.client,'') as agentcode, ifnull(a.clientname,'') as agentname " . $addonfield . "
        from hlead as lead left join client on client.client = lead.client
        left join forex_masterfile as f on f.line = client.forexid left join client as a on a.client = client.agent " . $leftjoin . $condition;
        break;
      case 'personnel':
        $qry = "select client.clientid,client.client,client.clientname,client.addr,client.wh,ifnull(f.cur,'P') as cur,ifnull(f.curtopeso,1) as forex,client.terms,ifnull(a.client,'') as agentcode, ifnull(a.clientname,'') as agentname, client.shipid, client.billid, client.tin " . $addonfield . "
        from client 
        left join forex_masterfile as f on f.line = client.forexid 
        left join employee as e on e.empid = client.clientid
        left join client as a on a.client = client.agent " . $leftjoin . $condition;
        break;
      case 'prtrans':
        $qry = "select head.client, head.clientname, hinfo.prepared, hinfo.department, head.yourref, head.ourref, head.rem, 
          hinfo.tmpref, head.trno as prtrno, transnum.postdate,transnum.postedby, head.docno
          from hprhead as head
          left join hheadinfotrans as hinfo on head.trno = hinfo.trno
          left join transnum on transnum.trno = head.trno 
          left join hprstock as stock on stock.trno=head.trno
          where stock.qty > stock.qa
          group by head.client, head.clientname, hinfo.prepared, hinfo.department, head.yourref, head.ourref, head.rem, 
          hinfo.tmpref, head.trno, transnum.postdate,transnum.postedby, head.docno
          ";
        break;
      case 'qtcustomer':
        $qry = "select client.clientid, head.client, head.docno, head.docno as ourref, client.clientname, client.addr, client.wh, ifnull(f.cur,'P') as cur, ifnull(f.curtopeso,1) as forex, client.terms, ifnull(a.client,'') as agentcode,
          ifnull(a.clientname, '') as agentname, client.shipid, client.billid, client.tin, client.billcontactid, client.shipcontactid, ifnull(client.deptid,0) as deptid, ifnull(dept.client, ' ') as dept,
          ifnull(dept.clientname,' ') as deptname, client.position, ifnull(terms.days,0) as days from hqthead as head left join client on client.client=head.client
          left join terms on terms.terms=client.terms left join forex_masterfile as f on f.line=client.forexid left join client as a on a.client=client.agent
          left join client as dept on dept.clientid=client.deptid where head.sotrno=0";
        break;
      case 'payors':
      case 'epayors':

        $qry = "
             select '' as clientname, '' as addr, '0' as clientid, '' as client, '' as lname, '' as mname, '' as fname, '' as ext, '' as addressno, '' as street,
            '' as subdistown, '' as city, '' as country, '' as zipcode,'' as tin
            union all
            select c.clientname, c.addr, c.clientid, c.client, ifnull(ci.lname,'') as lname, ifnull(ci.mname,'') as mname, ifnull(ci.fname,'') as fname, ifnull(ci.ext,'') as ext, ifnull(ci.addressno,'') as addressno, ifnull(ci.street,'') as street, ifnull(ci.subdistown,'') as subdistown, ifnull(ci.city,'') as city, ifnull(ci.country,'') as country,
            ifnull(ci.zipcode,'') as zipcode,ifnull(c.tin,'') as tin from client as c  left join clientinfo as ci
            on ci.clientid = c.clientid
            where iscustomer = 1 order by client;
           ";
        break;
      case 'customer_borrower':

        $qry = "
          select 
            '0' as clientid,
            '' as client,
            '' as clientname,
            '' as lname,
            '' as fname,
            '' as mname,

            '' as mmname,

            '' as planid,
            '' as purpose,
            '' as address,
            '' as province,
            '' as addressno,
            '' as contactno,
            '' as street,
            '' as civilstatus,
            '' as sname,
            '' as ename,
            '' as city,
            '' as terms,
            '' as zipcode,
            '' as yourref,
            '' as email,
            '' as pemail,
            '' as current1,
            '' as current2,
            '' as others1,
            '' as others2,
            '' as mincome,
            '' as mexp,
            '' as num,
            '' as voiddate,
            '' as pliss,
            '' as tin,
            '' as sssgsis,
            '' as monthly,

            '' as employer,
            '' as country,
            '' as brgy,
            '' as subdistown,

            '' as amount,
            '' as issameadd,
            '' as isbene,
            '' as ispf,
            '' as dependentsno,
            '' as nationality,
            
            '' as companyaddress,
            '' as pcity,
            '' as pcountry,
            '' as pprovince,
            '' as idno,
            '' as value,
            '' as isdp,
            '' as isotherid,
            '' as bank1,
            '' as pob,
            '' as otherplan
          union all
          select 
            c.clientid,
            c.client,
            c.clientname,
            cinfo.lname,
            cinfo.fname,
            cinfo.mname,
            
            cinfo.mmname,

            cinfo.planid,
            cinfo.purpose,
            cinfo.address,
            cinfo.province,
            cinfo.addressno,
            cinfo.contactno,
            cinfo.street,
            cinfo.civilstatus,
            cinfo.sname,
            cinfo.ename,
            cinfo.city,
            cinfo.terms,
            cinfo.zipcode,
            cinfo.yourref,
            cinfo.email,
            cinfo.pemail,
            cinfo.current1,
            cinfo.current2,
            cinfo.others1,
            cinfo.others2,
            cinfo.mincome,
            cinfo.mexp,
            cinfo.num,
            cinfo.voiddate,
            cinfo.pliss,
            cinfo.tin,
            cinfo.sssgsis,
            cinfo.monthly,

            cinfo.employer,
            cinfo.country,
            cinfo.brgy,
            cinfo.subdistown,

            cinfo.amount,
            cinfo.issameadd,
            cinfo.isbene,
            cinfo.ispf,
            cinfo.dependentsno,
            cinfo.nationality,
            
            cinfo.companyaddress,
            cinfo.pcity,
            cinfo.pcountry,
            cinfo.pprovince,
            cinfo.idno,
            cinfo.value,
            cinfo.isdp,
            cinfo.isotherid,
            cinfo.bank1,
            cinfo.pob,
            cinfo.otherplan
          from client as c
          left join clientinfo as cinfo on cinfo.clientid=c.clientid
          where c.iscustomer = 1 
          order by client
        ";
        break;
      case 'lookupddeptname':
        $condition = " where client.isdepartment=1 and client.isinactive =0 order by client";
        $qry = "
            select
            0 clientid,
            '' as client,
            '' as clientname,
            '' as addr,
            '' as wh,
            '' as cur,
            '' as forex,
            '' as terms,
            '' as agentcode,
            '' as agentname,
            '' as shipid,
            '' as billid,
            '' as tin,
            '' as billcontactid,
            '' as shipcontactid,
            '' as deptid,
            '' as dept,
            '' as deptname,
            '' as position,
            '' as groupid, 
            '' as vattype,
            '' as tax
            union all
            select client.clientid,client.client,client.clientname,client.addr,client.wh,ifnull(f.cur,'P') as cur,
            ifnull(f.curtopeso,1) as forex,client.terms,ifnull(a.client,'') as agentcode, 
            ifnull(a.clientname,'') as agentname, client.shipid, client.billid, client.tin, client.billcontactid,client.shipcontactid,
            ifnull(client.deptid, 0) as deptid,
            ifnull(dept.client, ' ') as dept,
            ifnull(dept.clientname, ' ') as deptname,client.position,client.groupid
            , client.vattype, case when client.vattype='Vat-registered' then 12 else 0 end as tax
            from client 
            left join forex_masterfile as f on f.line = client.forexid 
            left join client as a on a.client = client.agent 
            left join client as dept on dept.clientid = client.deptid
            " . $leftjoin . $condition;
        break;
      default:
        switch ($config['params']['doc']) {
          case 'INCENTIVESGENERATOR':
            switch ($lookupclass) {
              case 'customerdealer':
                $qry = "select 0 clientid,'' as client,'' as clientname union all select client.clientid,client.client,client.clientname
                from client left join forex_masterfile as f on f.line = client.forexid " . $leftjoin . $condition;
                break;

              default:
                $qry = "select 0 clientid,'' as client,'' as clientname union all select client.clientid,client.client,client.clientname
                from client where isagent=1 and isinactive =0 order by client ";
                break;
            }
            break;

          case 'STOCKCARD':
            switch ($config['params']['lookupclass']) {
              case 'whledger':
                $qry = "select 0 as clientid,'' as client,'' as clientname,'' as addr
              union all
                select client.clientid,client.client,client.clientname,client.addr
                
                from client 
                left join forex_masterfile as f on f.line = client.forexid 
                left join client as a on a.client = client.agent 
                left join client as dept on dept.clientid = client.deptid
                " . $leftjoin . " where client.iswarehouse=1 order by client ";
                break;
              case 'stockcardsupplier':
                $qry = "select 0 as clientid, '' as client, '' as clientname, 0 as tax, '' as vattype union all select clientid, client, clientname, 0 as tax, '' as vattype from client where issupplier=1 order by clientname";
                break;
              default:
                goto defaultqryhere;
                break;
            }
            break;

          default:
            defaultqryhere:
            $addqry = "";
            if ($config['params']['companyid'] == 16 && $config['params']['doc'] == 'EMPLOYEE') { //ati
              $addqry = "select '' as clientid, '' as client, '' as clientname, '' as addr,'' as wh,'' as cur,
                        '' as forex, '' as terms, '' as agentcode,
                        '' as agentname, '' as shipid, '' as billid, '' as tin, '' as billcontactid, '' as shipcontactid,
                        '' as deptid,'' as dept,'' as deptname,'' as position, '' as groupid,'' as agentid,
                        '' as vattype, '' as tax union all ";
            }

            if ($config['params']['companyid'] == 8 && $config['params']['doc'] == 'CV') { //maxipro
              $addonfield .= ',client.accountname, client.accountnum ';
            }

            //default qry here 
            $qry = $addqry . "select client.clientid,client.client,client.clientname,client.client as whto,client.clientname as whtoname,client.addr" . $whfield . ",ifnull(f.cur,'P') as cur,
            ifnull(f.curtopeso,1) as forex,client.terms,ifnull(a.client,'') as agentcode, 
            ifnull(a.clientname,'') as agentname, client.shipid, client.billid, client.tin, client.billcontactid,client.shipcontactid,
            ifnull(client.deptid, 0) as deptid,
            ifnull(dept.client, ' ') as dept,
            ifnull(dept.clientname, ' ') as deptname,client.position,client.groupid,ifnull(a.clientid,0) as agentid,ifnull(client.ship, ' ') as ship
            " . $addonfield . "
            from client 
            left join forex_masterfile as f on f.line = client.forexid 
            left join client as a on a.client = client.agent
            
            " . $leftjoin . $leftjoin_department . $condition;
            break;
        }
        break;
    }


    $this->othersClass->logConsole('============');
    $this->othersClass->logConsole($qry);
    $data = $this->coreFunctions->opentable($qry);

    if ($lookupclass == "customereapp") {
      foreach ($data as $d => $v) {
        $q = "select count(distinct trno) as value from(select h.trno from lahead as h left join client as c on c.client = h.client left join cntnuminfo as cnt on cnt.trno = h.trno
        where h.doc ='CR' and c.clientid = " . $data[$d]->clientid . " and cnt.cptrno = " . $data[$d]->trno . "
        union all select h.trno from glhead as h left join hcntnuminfo as cnt on cnt.trno = h.trno where h.clientid  =  " . $data[$d]->clientid . " and cnt.cptrno = " . $data[$d]->trno . ") as a";
        $countcr = $this->coreFunctions->datareader($q);

        if ($countcr == 0) {
          $q = "select format(dp+pf,2) as value from heainfo where trno = " . $data[$d]->aftrno;
          $dppf = $this->coreFunctions->datareader($q);
          $data[$d]->amount = $dppf;
        } else {
          $data[$d]->amount = 0;
        }
      }
    }

    $btnadds = isset($btnadd) ? $btnadd : "";


    switch ($plottype) {
      case 'plotgrid':
        $table = $config['params']['table'];
        $rowindex = $config['params']['index'];
        return ['status' => true, 'msg' => 'ok', 'data' => $data, 'lookupsetup' => $lookupsetup, 'cols' => $cols, 'plotsetup' => $plotsetup, 'table' => $table, 'rowindex' => $rowindex, 'btnadd' => $btnadds];
        break;
      default:
        return ['status' => true, 'msg' => 'ok', 'data' => $data, 'lookupsetup' => $lookupsetup, 'cols' => $cols, 'plotsetup' => $plotsetup, 'btnadd' => $btnadds]; //, 's'=>$qry
        break;
    }
  }

