  //A
  public function additem($config)
  {

    ini_set('memory_limit', '-1');
    ini_set('max_execution_time', 0);


    if ($config['params']['companyid'] == 56) {

      // $msg = 'UOM cannot be blank -' . $item[0]->barcode;

      // 161 - outright
      // 162 - consignment
      // 163 - concession

      if ($config['params']['doc'] != '' && $config['params']['doc'] == 'RR') { // not report 

        $supptype = $this->coreFunctions->datareader("select left(client,3) as value from lahead where trno = " . $config['params']['trno']);
        switch ($supptype) {
          case '161':
            return ['status' => false, 'msg' => 'Cannot add item for Outright suppliers'];
            break;
        }
      }
      // return ['status' => false, 'msg' => $msg];
    }



    $systemtype = $this->companysetup->getsystemtype($config['params']);
    $lookupsetup = array(
      'type' => 'singlesearch',
      'actionsearch' => 'searchitem',
      'title' => 'List of Products',
      'style' => 'width:100%;max-width:100%;height:80%'
    );

    if (isset($config['params']['addedparams'][0])) {
      if ($config['params']['addedparams'][0] == 1) {
        if ($config['params']['companyid'] == 56 && ($config['params']['doc'] == 'PO' || $config['params']['doc'] == 'RR')) { //homeworks
          $lookupsetup['title'] = 'List of Products (Fixed Asset)';
        }
      }
    }

    $data = [];
    switch ($config['params']['doc']) {
      case 'PD':
        if ($config['params']['addedparams'][0] != '') {
          $lookupsetup['type'] = 'single';
          $lookupsetup['actionsearch'] = '';
          $data = $this->coreFunctions->opentable("select item.itemid, item.barcode, item.itemname, item.uom from item left join hpihead as head on head.itemid=item.itemid where head.trno=?", [$config['params']['addedparams'][0]]);
        }
        break;
    }
    switch ($systemtype) {
      case "FAMS":
        if ($config['params']['doc'] == "PF" || $config['params']['doc'] == "RA") {
          $lookupsetup['actionsearch'] = 'generalItemSearch';
        }
        if ($config['params']['lookupclass'] == "genitemlist") {
          $lookupsetup['actionsearch'] = 'generalItemSearch';
        }
        break;
      case "AIMSPAYROLL":
        if ($config['params']['companyid'] == 43) { // MIGHTY
          switch ($config['params']['doc']) {
            case 'EMPLOYEE':
            case 'HS':
            case 'EQ':
              $lookupsetup = array(
                'type' => 'singlesearch',
                'actionsearch' => 'searchitem2',
                'title' => 'List of Truck/Asset',
                'style' => 'width:100%;max-width:100%;'
              );
              break;
          }
        }
        break;
    }

    if ($config['params']['lookupclass'] == "lookupitemfi") {
      $lookupsetup['actionsearch'] = 'Fitemsearch';
      $data = $this->coreFunctions->opentable("select itemname,barcode,itemid from item where isfa=1");
    }

    if ($config['params']['companyid'] == 42 && $config['params']['doc'] == 'TS') { //pdpi mis
      $trno = $config['params']['trno'];
      $wh = $this->coreFunctions->getfieldvalue("lahead", "wh", "trno=?", [$trno]);
      $config['params']['client'] =  $wh;
      $data = $this->coreFunctions->opentable("select item.itemname,item.barcode,item.itemid,grp.stockgrp_name as groupid,item.uom from item 
      left join rrstatus as rr on rr.itemid = item.itemid left join client as wh on wh.clientid = rr.whid left join stockgrp_masterfile as grp on grp.stockgrp_id = item.groupid
       where wh.client ='" . $wh . "' and rr.bal <> 0 group by item.itemname,item.barcode,item.itemid,grp.stockgrp_name,item.uom");
    }


    $cols = array();

    switch ($config['params']['companyid']) {
      case 40: //cdo
        array_push($cols, array('name' => 'barcode', 'label' => 'Barcode', 'align' => 'left', 'field' => 'barcode', 'sortable' => true, 'style' => 'font-size:16px;'));
        array_push($cols, array('name' => 'partno', 'label' => 'Part No.', 'align' => 'left', 'field' => 'partno', 'sortable' => true, 'style' => 'font-size:16px;'));
