  private function itemLookupFilterSetup($config)
  {
    $fields = [];
    switch ($config['params']['companyid']) {
      case 10: //afti
      case 12: //afti usd
        $fields = ['selectprefix'];
        $col = $this->fieldClass->create($fields);
        data_set($col, 'selectprefix.label', 'Search by');
        data_set($col, 'selectprefix.type', 'lookup');
        data_set($col, 'selectprefix.lookupclass', 'lookupsearchby');
        data_set($col, 'selectprefix.action', 'lookupsearchby');

        $fields = ['operator'];
        $col2 = $this->fieldClass->create($fields);
        data_set($col2, 'operator.type', 'lookup');
        data_set($col2, 'operator.lookupclass', 'lookupoperator');
        data_set($col2, 'operator.action', 'lookuprandom');

        $fields = ['docno'];
        $col3 = $this->fieldClass->create($fields);
        data_set($col3, 'docno.type', 'input');
        data_set($col3, 'docno.label', 'Value');


        $itemfield = $this->coreFunctions->opentable("select '' as selectprefix,'' as operator,'' as docno");
        $itemform = array('col' => $col, 'col2' => $col2, 'col3' => $col3, 'itemfield' => $itemfield[0], 'title' => 'Enter Item Entry', 'style' => 'width:400px;max-width:400px;');
        break;

      case 56: //homeworks
        if ($config['params']['doc'] == 'PO' || $config['params']['doc'] == 'RR') {
          //addedparams
          $isfa = isset($config['params']['addedparams'][0]) ? $config['params']['addedparams'][0] : 0;
          $itemfield = $this->coreFunctions->opentable("select " . $isfa . " as isfa");
          $itemform = array('col' => [], 'col2' => [], 'col3' => [], 'itemfield' => $itemfield[0], 'title' => 'Enter Item Entry', 'style' => 'width:400px;max-width:400px;');
        } else {
          goto defaultfilterhere;
        }
        break;


      default:
        defaultfilterhere:
        $fields = [];
        $col = [];
        $itemfield = [];
        $itemform = array('col' => $col, 'itemfield' => $itemfield, 'title' => 'Not Setup', 'style' => 'width:400px;max-width:400px;');
        break;
    }
    return $itemform;
  }


  public function lookupuom($config)
  {
    //default
    $plotting = array('uom' => 'uom');
    $plottype = 'plotemit';
    $title = 'List of Unit of Measurement';

    // $itemid = $config['params']['addedparams'][0];
    // var_dump($config['params']['addedparams']);

    $btnadd = $this->sqlquery->checksecurity($config, 15, '/tableentries/tableentry/entryuom');

    $addonfilter = '';
    //kinggeorge
    if ($config['params']['companyid'] == 21 && $config['params']['doc'] == 'SO') { //kinggeorge
      $addonfilter = ' and issales=1';
    }

    switch ($config['params']['lookupclass']) {

      case 'uomledger':
        $plottype = 'plotledger';
        break;
      case 'bomuom':
        $plottype = 'plothead';
        $plotting = array('uom2' => 'uom');
        break;
      case 'uomstock':
        $plotting = array('uom' => 'uom', 'uomfactor' => 'factor');

        if ($this->companysetup->getisuomamt($config['params'])) {
          if ($config['params']['doc'] == 'SJ' || $config['params']['doc'] == 'SO' || $config['params']['doc'] == 'SO') {
            $plotting['isamt'] = 'amt';
          }

          if ($config['params']['companyid'] == 37 && ($config['params']['doc'] == 'TS' || $config['params']['doc'] == 'PC' || $config['params']['doc'] == 'CM')) { //megacrystal
            $plotting['isamt'] = 'amt';
          }
        }

        if ($this->companysetup->getisrecalcamtchangeuom($config['params'])) {
          switch ($config['params']['doc']) {
            case 'SO':
            case 'SJ':
            case 'CM':
            case 'TS':
            case 'DM':
              $plotting['isamt'] = 'amt';
              break;
            case 'AJ':
            case 'PC':
              $plotting['rrcost'] = 'amt';
              break;
            case 'IS':
              $plotting['rrcost'] = 'amt';
              break;
          }
        }

        $plottype = 'plotgrid';
        break;

      case 'uomstock2':
        $plotting = array('uom2' => 'uom');
        $plottype = 'plotgrid';
        break;

      case 'uomstock3':
        $plotting = array('uom3' => 'uom');
        $plottype = 'plotgrid';
        break;

      case 'uomstockinputuom':
        $plotting = array('inputuom' => 'uom');
        $plottype = 'plotgrid';
        break;

      case 'uoms':
      case 'piuom':
        $plottype = 'plothead';
        break;

      default:
        if ($this->companysetup->getisuomamt($config['params'])) {
          if ($config['params']['doc'] == 'SJ' || $config['params']['doc'] == 'SO') {
            $plotting['amt'] = 'amt';
          }

          if ($config['params']['companyid'] == 37 && ($config['params']['doc'] == 'TS' || $config['params']['doc'] == 'PC' || $config['params']['doc'] == 'CM')) { //mega crystal
            $plotting['amt'] = 'amt';
          }
        }

        if ($this->companysetup->getisrecalcamtchangeuom($config['params'])) {
          switch ($config['params']['doc']) {
            case 'SO':
            case 'SJ':
            case 'CM':
            case 'TS':
            case 'DM':
              $plotting['amt'] = 'amt';
              break;
            case 'AJ':
            case 'PC':
              if (isset($config['params']['row']['trno'])) {
                $plotting['rrcost'] = 'amt';
              } else {
                $plotting['amt'] = 'amt';
              }
              break;
            case 'IS':
              $plotting['amt'] = 'amt';
              break;
          }
        }
        break;
    }
    $lookupsetup = array(
      'type' => 'single',
      'title' => $title,
      'style' => 'width:900px;max-width:900px;'
    );
    $plotsetup = array(
      'plottype' => $plottype,
      'action' => '',
      'plotting' => $plotting
    );
    // lookup columns
    $cols = array();
    array_push($cols, array('name' => 'uom', 'label' => 'Unit of Measurement', 'align' => 'left', 'field' => 'uom', 'sortable' => true, 'style' => 'font-size:16px;'));

    if ($this->companysetup->getisuomamt($config['params'])) {
      array_push($cols, array('name' => 'amt', 'label' => 'Amount', 'align' => 'right', 'field' => 'amt', 'sortable' => true, 'style' => 'font-size:16px;'));
    }

    if ($this->companysetup->getisrecalcamtchangeuom($config['params'])) {
      switch ($config['params']['doc']) {
        case 'SO':
        case 'SJ':
        case 'CM':
        case 'AJ':
        case 'TS':
        case 'PC':
          array_push($cols, array('name' => 'amt', 'label' => 'Amount', 'align' => 'right', 'field' => 'amt', 'sortable' => true, 'style' => 'font-size:16px;'));
          break;
        case 'PO':
        case 'RR':
          if ($config['params']['companyid'] == 21) { //kinggeorge
            array_push($cols, array('name' => 'factor', 'label' => 'Factor', 'align' => 'right', 'field' => 'factor', 'sortable' => true, 'style' => 'aling:right;font-size:16px;'));
            array_push($cols, array('name' => 'amt', 'label' => 'Factor X Retail Price', 'align' => 'right', 'field' => 'amt', 'sortable' => true, 'style' => 'font-size:16px;'));
          }
          break;

        case 'DM':
          if ($config['params']['companyid'] == 21) { //kinggeorge
            array_push($cols, array('name' => 'factor', 'label' => 'Factor', 'align' => 'right', 'field' => 'factor', 'sortable' => true, 'style' => 'aling:right;font-size:16px;'));
            array_push($cols, array('name' => 'amt', 'label' => 'Factor X Latest Cost', 'align' => 'right', 'field' => 'amt', 'sortable' => true, 'style' => 'font-size:16px;'));
          }
          break;
      }
    }

    switch (strtolower($config['params']['lookupclass'])) {
      case 'entrychangeitem':
        $qry = "select uom,factor from uom where itemid=?";
        $itemid = $config['params']['row']['itemid'];
        $data = $this->coreFunctions->opentable($qry, [$itemid]);
        break;
      case 'piuom':
        $qry = "select uom from uom where itemid=?";
        $itemid = $config['params']['addedparams'][0];
        if ($itemid == 0) {
          $data = [];
        } else {
          $data = $this->coreFunctions->opentable($qry, [$itemid]);
        }
        break;

      default:

        if ($this->companysetup->getisrecalcamtchangeuom($config['params'])) {
          switch ($config['params']['doc']) {
            case 'SO':
            case 'SJ':
            case 'CM':
              $path = 'App\Http\Classes\modules\sales\\' . strtolower($config['params']['doc']);
              $config['params']['trno'] = isset($config['params']['trno']) ? $config['params']['trno'] : $config['params']['row']['trno'];
              $config['params']['barcode'] = $config['params']['row']['barcode'];
              $config['params']['client'] = $this->coreFunctions->getfieldvalue(app($path)->head, "client", "trno = ?", [$config['params']['trno']]);
              $getdefprice = app($path)->getlatestprice($config);
              $lastuom = $getdefprice['data'][0]->uom;

              $itemid = isset($config['params']['dataid']) ? $config['params']['dataid'] : $config['params']['itemid'];

              if ($config['params']['companyid'] != 22) { //not eipi
                if ($this->companysetup->getpricetype($config['params']) == 'Stockcard') {
                  $getdefprice['data'][0]->defamt = $this->coreFunctions->getfieldvalue("item", "amt", "itemid=?", [$itemid], '', true);
                  // }
                }
              } else {
                if ($getdefprice['data'][0]->defamt == 0) {
                  $getdefprice['data'][0]->defamt = $this->coreFunctions->getfieldvalue("item", "amt", "itemid=?", [$itemid], '', true);
                }
              }

              //if ($config['params']['doc'] == 'CM') {
              $deffactor = $this->coreFunctions->getfieldvalue("uom", "factor", "itemid=? and uom=?", [$itemid, $getdefprice['data'][0]->uom], '', true);
              $amt = $this->othersClass->sanitizekeyfield("amt", $getdefprice['data'][0]->amt);
              if ($deffactor > 1) $getdefprice['data'][0]->defamt = $amt / $deffactor;
              //}

              $qry = "select uom.uom, uom.factor, FORMAT(" . $getdefprice['data'][0]->defamt .  " * uom.factor," . $this->companysetup->getdecimal('price', $config['params']) . ") as amt from uom left join item on item.itemid=uom.itemid where uom.itemid=? and uom.isinactive = 0" . $addonfilter;

              $data = $this->coreFunctions->opentable($qry, [$itemid]);
              break;
            case 'TS':
              $path = 'App\Http\Classes\modules\inventory\\' . strtolower($config['params']['doc']);
              $config['params']['trno'] = isset($config['params']['trno']) ? $config['params']['trno'] : $config['params']['row']['trno'];
              $config['params']['barcode'] = $config['params']['row']['barcode'];
              $config['params']['client'] = $this->coreFunctions->getfieldvalue(app($path)->head, "client", "trno = ?", [$config['params']['trno']]);
              $itemid = isset($config['params']['dataid']) ? $config['params']['dataid'] : $config['params']['itemid'];
              $defprice = 0;
              $getdefprice = app($path)->getlatestprice($config);
              if ($getdefprice['status']) {
                $defprice = $this->othersClass->sanitizekeyfield("amt", $getdefprice['data'][0]->defamt);
                $factor = $this->coreFunctions->getfieldvalue("uom", "factor", "itemid=? and uom=?", [$itemid, $getdefprice['data'][0]->uom]);
                if ($factor == '') {
                  $factor = 1;
                }
                $defprice = $defprice / $factor;
              }

              $qry = "select uom.uom, uom.factor, FORMAT(" . $defprice . " * uom.factor," . $this->companysetup->getdecimal('price', $config['params']) . ") as amt from uom left join item on item.itemid=uom.itemid where uom.itemid=? and uom.isinactive = 0";

              $data = $this->coreFunctions->opentable($qry, [$itemid]);
              break;
            case 'AJ':
            case 'PC':
              $cost = 0;
              $factor = 1;
              $config['params']['barcode'] = $config['params']['row']['barcode'];
              $config['params']['client'] = '';
              $config['params']['trno'] = isset($config['params']['trno']) ? $config['params']['trno'] : $config['params']['row']['trno'];
              $itemid = isset($config['params']['dataid']) ? $config['params']['dataid'] : $config['params']['itemid'];
              $getlatestcost = app('App\Http\Classes\modules\inventory\\' . strtolower($config['params']['doc']))->getlatestprice($config);
              if ($getlatestcost['status']) {
                $cost = $this->othersClass->sanitizekeyfield("amt", $getlatestcost['data'][0]->amt);
                $factor = $this->coreFunctions->getfieldvalue("uom", "factor", "itemid=? and uom=?", [$itemid, $getlatestcost['data'][0]->uom]);
                if ($factor == '') {
                  $factor = 1;
                }
                $cost = $cost / $factor;
              }
              $qry = "select uom.uom, uom.factor, FORMAT(" . $cost . " * uom.factor," . $this->companysetup->getdecimal('price', $config['params']) . ") as amt from uom left join item on item.itemid=uom.itemid where uom.itemid=? and uom.isinactive = 0 ";
              $data = $this->coreFunctions->opentable($qry, [$itemid]);
              break;
            case 'PO':
            case 'RR':
              if ($config['params']['companyid'] == 21) { //kinggeorge
                $qry = "select uom.uom, uom.factor, FORMAT(item.amt * uom.factor," . $this->companysetup->getdecimal('price', $config['params']) . ") as amt from uom left join item on item.itemid=uom.itemid where uom.itemid=? and uom.isinactive = 0";
                $itemid = isset($config['params']['dataid']) ? $config['params']['dataid'] : $config['params']['itemid'];
                $data = $this->coreFunctions->opentable($qry, [$itemid]);
                $this->othersClass->logConsole($qry);
              } else {
                goto defaulthere;
              }
              break;
            case 'DM':
              $path = 'App\Http\Classes\modules\purchase\\' . strtolower($config['params']['doc']);
              $config['params']['trno'] = isset($config['params']['trno']) ? $config['params']['trno'] : $config['params']['row']['trno'];
              $config['params']['barcode'] = $config['params']['row']['barcode'];
              $config['params']['client'] = $this->coreFunctions->getfieldvalue(app($path)->head, "client", "trno = ?", [$config['params']['trno']]);
              $itemid = isset($config['params']['dataid']) ? $config['params']['dataid'] : $config['params']['itemid'];
              $defprice = 0;
              $getdefprice = app($path)->getlatestprice($config);
              if ($getdefprice['status']) {
                $defprice = $this->othersClass->sanitizekeyfield("amt", $getdefprice['data'][0]->amt);
                $factor = $this->coreFunctions->getfieldvalue("uom", "factor", "itemid=? and uom=?", [$itemid, $getdefprice['data'][0]->uom]);
                if ($factor == '') {
                  $factor = 1;
                }
                $defprice = $defprice / $factor;
              }

              $qry = "select uom.uom, uom.factor, FORMAT(" . $defprice . " * uom.factor," . $this->companysetup->getdecimal('price', $config['params']) . ") as amt from uom left join item on item.itemid=uom.itemid where uom.itemid=? and uom.isinactive = 0";
              $data = $this->coreFunctions->opentable($qry, [$itemid]);
              break;
            case 'IS':
              $qry = "select uom,factor, 0 as amt from uom where itemid=? and isinactive = 0";
              $itemid = isset($config['params']['dataid']) ? $config['params']['dataid'] : $config['params']['itemid'];
              $data = $this->coreFunctions->opentable($qry, [$itemid]);
              break;
            default:
              goto defaulthere;
              break;
          }
          break;
        }

        defaulthere:
        $uomfieldamt = 'amt';
        if ($this->companysetup->getisuomamt($config['params'])) {
          switch ($config['params']['lookupclass']) {
            case 'uomstock':
              if ($config['params']['companyid'] == 37) { //mega crystal
                $config['params']['trno'] = $config['params']['row']['trno'];
                goto getisuomamthere;
              }
              break;
            case 'uomstock2':
            case 'uomstock3':
            case 'uomstockinputuom':
              break;

            default:
              getisuomamthere:
              switch ($config['params']['doc']) {
                case 'SO':
                  $pricegrp = $this->coreFunctions->datareader("select client.class as value from sohead as h left join client on client.client=h.client where h.trno=" . $config['params']['trno']);
                  $pricefield = $this->othersClass->getamtfieldbygrp($pricegrp);
                  $uomfieldamt = $pricefield['amt'];
                  break;
                case 'SJ':
                case 'CM':
                  $pricegrp = $this->coreFunctions->datareader("select client.class as value from lahead as h left join client on client.client=h.client where h.trno=" . $config['params']['trno']);
                  $pricefield = $this->othersClass->getamtfieldbygrp($pricegrp);
                  $uomfieldamt = $pricefield['amt'];
                  break;
              }
              break;
          }
        }
        $qry = "select uom,factor, FORMAT(" . $uomfieldamt . "," . $this->companysetup->getdecimal('price', $config['params']) . ") as amt from uom where itemid=? and isinactive = 0 and itemid<>0";
        if ($config['params']['doc'] == 'BOM') {
          $itemid = $config['params']['trno'];
        } else {

          if (isset($config['params']['addedparams'][0])) {
            $itemid = $config['params']['addedparams'][0]; // po module po history button 
          } else {
            $itemid = isset($config['params']['dataid']) ? $config['params']['dataid'] : $config['params']['itemid'];
          }
        }
        $data = $this->coreFunctions->opentable($qry, [$itemid]);

        if (($config['params']['doc'] == 'CD' || $config['params']['doc'] == 'PO') && $config['params']['companyid'] == 16) { //ati
          if ($config['params']['itemid'] == 0) {
            if ($config['params']['lookupclass'] == 'uomstock' || $config['params']['lookupclass'] == 'uomstockinputuom') {
              $btnadd = $this->sqlquery->checksecurity($config, 4499, '/tableentries/ati/entryuomlist');
              $data = $this->coreFunctions->opentable("select '' as uom,0 as factor,0 as amt union all select uom,factor,0 as amt from uomlist where isuom=1 order by uom", [$itemid]);
            }
          }
          if ($config['params']['lookupclass'] == 'uomstock2' || $config['params']['lookupclass'] == 'uomstock3') {
            $btnadd = $this->sqlquery->checksecurity($config, 4500, '/tableentries/ati/entryconversionuom');
            $data = $this->coreFunctions->opentable("select '' as uom,0 as factor,0 as amt union all select uom,factor,0 as amt from uomlist where isconvert=1 order by uom", [$itemid]);
          }
        }
        break;
    }

    switch ($config['params']['lookupclass']) {
      case 'uomstock':
      case 'uomstock2':
      case 'uomstock3':
      case 'uomstockinputuom':
        $table = $config['params']['table'];
        $rowindex = $config['params']['index'];
        $computefield = false;
        if ($this->companysetup->getisuomamt($config['params']) &&  ($config['params']['doc'] == 'SJ' || $config['params']['doc'] == 'SO')) {
          $computefield = true;
        }

        if ($config['params']['companyid'] == 37 && ($config['params']['doc'] == 'TS' || $config['params']['doc'] == 'PC' || $config['params']['doc'] == 'CM')) { //megacrystal
          $computefield = true;
        }

        if ($this->companysetup->getisrecalcamtchangeuom($config['params'])) {
          switch ($config['params']['doc']) {
            case 'SO':
            case 'SJ':
            case 'CM':
            case 'AJ':
            case 'TS':
            case 'PC':
            case 'IS':
            case 'DM':
              $computefield = true;
              break;
          }
        }

        return ['status' => true, 'msg' => 'ok', 'data' => $data, 'lookupsetup' => $lookupsetup, 'cols' => $cols, 'plotsetup' => $plotsetup, 'table' => $table, 'rowindex' => $rowindex, 'computefield' => $computefield, 'btnadd' => $btnadd];
        break;
      default:
        return ['status' => true, 'msg' => 'ok', 'data' => $data, 'lookupsetup' => $lookupsetup, 'cols' => $cols, 'plotsetup' => $plotsetup];
        break;
    }
  } // end function


  public function lookuploc($config)
  {
    //Existing lookupclass
    //1.locentry
    //2.locstock
    //3.expirystock
    //4.amt
    //default
    $company = $config['params']['companyid'];
    $wh = $this->companysetup->getwh($config['params']);
    $plotting = array('wh' => 'wh', 'loc' => 'loc', 'expiry' => 'expiry');

    if ($company == 22) { //eipi
      $plotting['amt'] = 'amt';
    }

    $plottype = 'plotemit';
    $title = 'List of Available Balance';
    $doc = $config['params']['doc'];
    switch ($config['params']['lookupclass']) {
      case 'locstock':
      case 'expirystock':
        $plottype = 'plotgrid';
        break;
      case 'locs':
        $plottype = 'plothead';
        break;
      case 'replookuploc':
      case 'replookuplocitem':
        $title = 'List of Locations';
        $plotting = array('loc' => 'loc');
        $plottype = 'plothead';
        break;
      case 'batchlookuploc':
        $plotting = array('loc' => 'loc');
        $plottype = 'plotgrid';
        break;
    }
    $lookupsetup = array(
      'type' => 'single',
      'title' => $title,
      'style' => 'width:900px;max-width:900px;'
    );
    $plotsetup = array(
      'plottype' => $plottype,
      'action' => '',
      'plotting' => $plotting
    );
    // lookup columns

    switch ($config['params']['lookupclass']) {
      case 'replookuploc':
      case 'replookuplocitem':
      case 'batchlookuploc':
        $cols = [
          ['name' => 'loc', 'label' => 'Location', 'align' => 'left', 'field' => 'loc', 'sortable' => true, 'style' => 'font-size:16px;'],
        ];
        break;
      default:

        $cols = [
          ['name' => 'wh', 'label' => 'Code', 'align' => 'left', 'field' => 'wh', 'sortable' => true, 'style' => 'font-size:16px;'],
          ['name' => 'loc', 'label' => 'Location', 'align' => 'left', 'field' => 'loc', 'sortable' => true, 'style' => 'font-size:16px;'],
          ['name' => 'expiry', 'label' => 'Expiry', 'align' => 'left', 'field' => 'expiry', 'sortable' => true, 'style' => 'font-size:16px;'],
          ['name' => 'bal', 'label' => 'Balance', 'align' => 'left', 'field' => 'bal', 'sortable' => true, 'style' => 'font-size:16px;']
        ];


        if ($config['params']['companyid'] == 8 || $config['params']['companyid'] == 50) { //maxipro, unitech
          $cols = [
            ['name' => 'wh', 'label' => 'Code', 'align' => 'left', 'field' => 'wh', 'sortable' => true, 'style' => 'font-size:16px;'],
            ['name' => 'loc', 'label' => 'Brand', 'align' => 'left', 'field' => 'loc', 'sortable' => true, 'style' => 'font-size:16px;'],
            ['name' => 'expiry', 'label' => 'Expiry', 'align' => 'left', 'field' => 'expiry', 'sortable' => true, 'style' => 'font-size:16px;'],
            ['name' => 'bal', 'label' => 'Balance', 'align' => 'left', 'field' => 'bal', 'sortable' => true, 'style' => 'font-size:16px;']
          ];
        }

        if ($config['params']['companyid'] == 22) { //eipi
          $cols = [
            ['name' => 'wh', 'label' => 'Code', 'align' => 'left', 'field' => 'wh', 'sortable' => true, 'style' => 'font-size:16px;'],
            ['name' => 'loc', 'label' => 'Location', 'align' => 'left', 'field' => 'loc', 'sortable' => true, 'style' => 'font-size:16px;'],
            ['name' => 'expiry', 'label' => 'Expiry', 'align' => 'left', 'field' => 'expiry', 'sortable' => true, 'style' => 'font-size:16px;'],
            ['name' => 'bal', 'label' => 'Balance', 'align' => 'left', 'field' => 'bal', 'sortable' => true, 'style' => 'font-size:16px;'],
            ['name' => 'cost', 'label' => 'Dealer\'s Price', 'align' => 'left', 'field' => 'cost', 'sortable' => true, 'style' => 'font-size:16px;'],
            ['name' => 'eskuamt', 'label' => 'SKU Amount', 'align' => 'left', 'field' => 'eskuamt', 'sortable' => true, 'style' => 'font-size:16px;']
          ];
        }

        break;
    }

    $joins = '';
    $field = ', rrstatus.cost as cost';
    $grp = '';
    $whfilter = '';
    if ($company == 22 && $doc == 'SJ') { //eipi
      $field = ',sku.amt as eskuamt,(case when ifnull(sku.amt,0) = 0 then rrstatus.cost else sku.amt end) as amt';
      $grp = ',sku.amt';
      $trno = $config['params']['trno'];
      $client = $this->coreFunctions->getfieldvalue('lahead', 'client', 'trno=?', [$trno]);

      $clid = $this->coreFunctions->getfieldvalue('client', 'clientid', 'client=?', [$client]);
      $joins = "left join sku on sku.itemid=rrstatus.itemid and sku.clientid= $clid";
    }

    if ($company == 40) { //cdo
      $whfilter = " and wh.client = '" . $wh . "' ";
    }

    $qry = "select wh.client as wh,rrstatus.loc,rrstatus.expiry,sum(rrstatus.bal) as bal, rrstatus.cost as cost $field
            from rrstatus 
            left join client as wh on wh.clientid=rrstatus.whid $joins
            where rrstatus.itemid=? and rrstatus.bal>0  " . $whfilter . "
            group by wh.client,rrstatus.loc,rrstatus.expiry,rrstatus.cost $grp";

    if ($company == 1) { //vitaline
      if ($doc == 'SJ') {
        if ($config['params']['lookupclass'] == 'locentry') {
          $qry = "select wh.client as wh,rrstatus.loc,rrstatus.expiry,sum(rrstatus.bal) as bal 
          from rrstatus 
          left join client as wh on wh.clientid=rrstatus.whid 
          where rrstatus.itemid=? and rrstatus.bal>0 and wh.clientid<>1831
          group by wh.client,rrstatus.loc,rrstatus.expiry";
        }
      }
    }

    switch ($company) {
      case 27: //nte
      case 36: //rozlab
        if ($doc == 'SJ') {

          $qry = "select wh.client as wh,rrstatus.loc,rrstatus.expiry,format(sum(rrstatus.bal/uom.factor)," . $this->companysetup->getdecimal('price', $config['params']) . ") as bal, rrstatus.cost as cost
        from rrstatus
        left join client as wh on wh.clientid=rrstatus.whid
        left join uom on uom.uom=rrstatus.uom and uom.itemid=rrstatus.itemid
        where rrstatus.itemid=?
        and rrstatus.bal>0
        group by wh.client,rrstatus.loc,rrstatus.expiry,rrstatus.cost";
        }
        break;
    }
    switch ($config['params']['lookupclass']) {
      case 'locstock':
        $itemid = $config['params']['itemid'];
        $data = $this->coreFunctions->opentable($qry, [$itemid]);
        $table = $config['params']['table'];
        $rowindex = $config['params']['index'];
        return ['status' => true, 'msg' => 'ok', 'data' => $data, 'lookupsetup' => $lookupsetup, 'cols' => $cols, 'plotsetup' => $plotsetup, 'table' => $table, 'rowindex' => $rowindex];
        break;
      case 'expirystock':
        $itemid = $config['params']['itemid'];
        $data = $this->coreFunctions->opentable($qry, [$itemid]);
        $table = $config['params']['table'];
        $rowindex = $config['params']['index'];
        return ['status' => true, 'msg' => 'ok', 'data' => $data, 'lookupsetup' => $lookupsetup, 'cols' => $cols, 'plotsetup' => $plotsetup, 'table' => $table, 'rowindex' => $rowindex];
        break;
      case 'replookuploc':
        $qry = "select distinct loc from rrstatus";
        $data = $this->coreFunctions->opentable($qry);

        return ['status' => true, 'msg' => 'ok', 'data' => $data, 'lookupsetup' => $lookupsetup, 'cols' => $cols, 'plotsetup' => $plotsetup];
        break;
      case 'replookuplocitem':
        $qry = "select distinct loc from rrstatus where itemid=" . $config['params']['dataid'];
        $data = $this->coreFunctions->opentable($qry);

        return ['status' => true, 'msg' => 'ok', 'data' => $data, 'lookupsetup' => $lookupsetup, 'cols' => $cols, 'plotsetup' => $plotsetup];
        break;
      case 'batchlookuploc':
        $qry = "select distinct loc from rrstatus";
        $data = $this->coreFunctions->opentable($qry);
        $table = $config['params']['table'];
        $rowindex = $config['params']['index'];

        return ['status' => true, 'msg' => 'ok', 'data' => $data, 'lookupsetup' => $lookupsetup, 'cols' => $cols, 'plotsetup' => $plotsetup, 'table' => $table, 'rowindex' => $rowindex];
        break;
      default:
        $itemid = $config['params']['dataid'];
        $data = $this->coreFunctions->opentable($qry, [$itemid]);
        return ['status' => true, 'msg' => 'ok', 'data' => $data, 'lookupsetup' => $lookupsetup, 'cols' => $cols, 'plotsetup' => $plotsetup];
        break;
    }
  } // end function


