      $qry = "select serialin.serial,serialin.chassis,serialin.color,serialin.pnp,serialin.csr from rrstatus left join serialin on serialin.trno=rrstatus.trno and
      serialin.line=rrstatus.line where rrstatus.itemid=? and rrstatus.whid=? and rrstatus.loc=? and expiry=? and serialin.outline=0 order by serialin.sline limit 60000";
