  //A
  public function lookuplogs($config)
  {
    $user = $config['params']['user'];
    $lookupsetup = array(
      'type' => 'show',
      'title' => 'List of Logs',
      'style' => 'width:100%;max-width:100%;height:90%'
    );

    $plotsetup = array(
      'plottype' => 'show',
      'action' => '',
      'callbackfieldhead' => [],
      'callbackfieldlookup' => [],
      'plotting' => []
    );

    $trno = $config['params']['trno'];

    // add case for masterfile <---
    switch (strtolower($config['params']['doc'])) {
      case 'leavesetup':
      case 'ratesetup':
      case 'shiftsetup':
      case 'earningdeductionsetup':
      case 'batchsetup':
      case 'codeconduct':
      case 'obapplication':
      case 'otapplicationadv':
      case 'loanapplication':
      case 'loanapplicationportal':
      case 'jobtitlemaster':
      case 'leaveapplication':
      case 'leaveapplicationportal':
      case 'advancesetup':
      case 'allowancesetup':
      case 'undertime':
      case 'changeshiftapplication':
        // case 'employee':
      case 'applicantledger':
      case 'applicantledger_acontacts':
      case 'roomtype':
      case 'en_subject':
      case 'en_roomlist':
      case 'en_course':
      case 'locationledger':
      case 'restday':
      case 'workonresday':
      case 'lcc':
      case 'ucc':
      case 'itinerary':

        $cols = array(
          array('name' => 'user', 'label' => 'User', 'align' => 'left', 'field' => 'user', 'sortable' => true, 'style' => 'font-size:16px;'),
          array('name' => 'task', 'label' => 'Task', 'align' => 'left', 'field' => 'task', 'sortable' => true, 'style' => 'font-size:16px;'),
          array('name' => 'dateid', 'label' => 'Date', 'align' => 'left', 'field' => 'dateid', 'sortable' => true, 'style' => 'font-size:16px;'),
        );

        $doc = $config['params']['doc'];
        $filter = " and doc = ?";
        switch (strtolower($config['params']['doc'])) {
          case 'earningdeductionsetup':
          case 'loanapplication':
            $doc = "EARNINGDEDUCTIONSETUP";
            $filter = " and (doc = ? or doc = 'EARNINGDEDUCTIONSETUP_MANUALPAYMENT')";
            break;
          case 'applicantledger':
            $filter = " and (doc = ? or doc = 'APPLICANTLEDGER_ACONTACTS' or doc = 'APP_DEPENDENTS' 
            or doc = 'APP_EDUCATION' or doc = 'APP_EMPLOYMENT' or doc = 'APP_REQ' or doc = 'APP_EMPTEST')";
            break;
          case 'advancesetup':
            $filter = " and (doc = ? or doc = 'ADVANCESETUP_MANUALPAYMENT')";
            break;
          case 'roomtype':
            $filter = " and (doc = ? or doc = 'ENTRYROOMLIST' )";
            break;

          case 'en_subject':
            $filter = " and (doc = ? or doc = 'ENTRYSUBJECT')";
            break;
          case 'en_roomlist':
            $filter = " and (doc = ? or doc = 'ENTRYROOM' )";
            break;
          case 'en_course':
            $filter = " and (doc = ? or doc = 'ENTRYSECTION' )";
            break;
          case 'codeconduct':
            $filter = " and (doc = ? or doc = 'CODECONDUCT_LIST')";
            break;
          case 'shiftsetup':
            $filter = " and (doc = ? or doc = 'SHIFTSETUP_DETAIL')";
            break;
          case 'leaveapplication':
          case 'leaveapplicationportal':
            $filter = " and (doc = ? or doc = 'LEAVEAPPLICATION')";
            break;
        }

        $qry = "
          select trno, doc, task, dateid, user
          from " . $config['docmodule']->tablelogs . "
          where trno = ?
          " . $filter . "
        ";


        if ($config['params']['companyid'] == 58) { //cdo
          switch (strtolower($config['params']['doc'])) {
            case 'applicantledger':
              $qry = $qry . " union all
              select trno, field, oldversion, dateid,log.userid 
              from " . $config['docmodule']->statlogs . " as log
              left join useraccess as u on u.username=log.userid
              where 1=1 and log.trno= $trno";
              break;
          }
        }


        $qry = $qry . " order by dateid desc";

        $data = $this->coreFunctions->opentable($qry, [$trno, $doc]);
        return ['status' => true, 'msg' => $qry, 'data' => $data, 'lookupsetup' => $lookupsetup, 'cols' => $cols, 'plotsetup' => $plotsetup];

        break;

      case 'itemgroupqoutasetup':
        $doc = $config['params']['doc'];
        $lookupsetup = array(
          'type' => 'show',
          'title' => 'Item Group Qouta Logs',
          'style' => 'width:1000px;max-width:1000px;'
        );

        // lookup columns
        $cols = array(
          array('name' => 'user', 'label' => 'User', 'align' => 'left', 'field' => 'user', 'sortable' => true, 'style' => 'font-size:16px;'),
          array('name' => 'task', 'label' => 'Task', 'align' => 'left', 'field' => 'task', 'sortable' => true, 'style' => 'font-size:16px;'),
          array('name' => 'dateid', 'label' => 'Date Occured', 'align' => 'left', 'field' => 'dateid', 'sortable' => true, 'style' => 'font-size:16px;')

        );

        $qry = "
        select trno, doc, task, log.user, dateid, 
        if(pic='','blank_user.png',pic) as pic
        from " . $config['docmodule']->tablelogs . " as log
        left join useraccess as u on u.username=log.user
        where log.doc = '" . $doc . "'
        union all
        select trno, doc, task, log.user, dateid, 
        if(pic='','blank_user.png',pic) as pic
        from  " . $config['docmodule']->tablelogs_del . " as log
        left join useraccess as u on u.username=log.user
        where log.doc = '" . $doc . "' ";

        $qry = $qry . " order by dateid desc";

        $data = $this->coreFunctions->opentable($qry);
        return ['status' => true, 'action' => 'load', 'msg' => 'ok', 'data' => $data, 'lookupsetup' => $lookupsetup, 'cols' => $cols];
        break;

      case 'othercharges':
        $doc = $config['params']['doc'];
        $lookupsetup = array(
          'type' => 'show',
          'title' => 'Logs',
          'style' => 'width:1000px;max-width:1000px;'
        );

        // lookup columns
        $cols = array(
          array('name' => 'user', 'label' => 'User', 'align' => 'left', 'field' => 'user', 'sortable' => true, 'style' => 'font-size:16px;'),
          array('name' => 'task', 'label' => 'Task', 'align' => 'left', 'field' => 'task', 'sortable' => true, 'style' => 'font-size:16px;'),
          array('name' => 'dateid', 'label' => 'Date Occured', 'align' => 'left', 'field' => 'dateid', 'sortable' => true, 'style' => 'font-size:16px;')

        );

        $qry = "
        select trno, doc, task, log.user, dateid, 
        if(pic='','blank_user.png',pic) as pic
        from " . $config['docmodule']->tablelogs . " as log
        left join useraccess as u on u.username=log.user
        where log.doc = '" . $doc . "'
        union all
        select trno, doc, task, log.user, dateid, 
        if(pic='','blank_user.png',pic) as pic
        from " . $config['docmodule']->tablelogs . " as log
        left join useraccess as u on u.username=log.user
        where log.doc = 'chargesbilling'
        union all
        select trno, doc, task, log.user, dateid, 
        if(pic='','blank_user.png',pic) as pic
