  //A
  private function clientlistlookup($config)
  {
    $filter = '';
    switch ($config['params']['addedparams'][0]['value']) {
      case 'ADMIN':
        $filter = " where isadmin=1 ";
        break;
      case 'STUDENT':
        $filter = " where isstudent=1 ";
        break;
      case 'EMPLOYEE':
        $filter = " where isemployee=1 ";
        break;
      default:
        return ['status' => false, 'msg' => 'Please select Group first.'];
        break;
    }

    $lookupsetup = array(
      'type' => 'single',
      'title' => 'List of ' . $config['params']['addedparams'][0]['value'],
      'style' => 'width:400px;max-width:400px;'
    );
    $plotsetup = array(
      'plottype' => 'plothead',
      'plotting' => array('clientid' => 'clientid', 'clientlist' => 'clientname')
    );

    // lookup columns
    $cols = array(
      array('name' => 'client', 'label' => 'Code', 'align' => 'left', 'field' => 'client', 'sortable' => true, 'style' => 'font-size:16px;'),
      array('name' => 'clientname', 'label' => 'Name', 'align' => 'left', 'field' => 'clientname', 'sortable' => true, 'style' => 'font-size:16px;')

    );
    $qry = "select md5(clientid) as clientid,client,clientname from client " . $filter . " and isinactive = 0 order by clientname";
    $data = $this->coreFunctions->opentable($qry);
    return ['status' => true, 'msg' => 'ok', 'data' => $data, 'lookupsetup' => $lookupsetup, 'cols' => $cols, 'plotsetup' => $plotsetup];
  } //end function


  //A
  public function lookupcontra($config)
  {
    $company = $config['params']['companyid'];
    $doc = $config['params']['doc'];

    $lookupsetup = array(
      'type' => 'single',
      'title' => 'List of Chart of Accounts',
      'style' => 'width:100%;max-width:80%;'
    );

    $alias = $config['params']['lookupclass'];
    $plottype = 'plothead';
    $plotting = array();


    switch ($config['params']['lookupclass']) {
      case 'DUESP':
        $plotting = array('rev' => 'acno', 'acnoname' => 'acnoname');
        break;
      case 'DUEMC':
        $plotting = array('ass' => 'acno', 'assetname' => 'acnoname');
        break;
      case 'DEPREDB':
        $plotting = array('depdbcode' => 'acno', 'depdbname' => 'acnoname', 'depdb' => 'acnoid');
        break;
      case 'DEPRECR':
        $plotting = array('depcrcode' => 'acno', 'depcrname' => 'acnoname', 'depcr' => 'acnoid');
        break;
      case 'SA':
        $plotting = array('rev' => 'acno', 'acnoname' => 'acnoname');
        break;
      case 'AR':
        if (strtoupper($doc) == 'CUSTOMER') {
          $plotting = array('ass' => 'acno', 'assetname' => 'acnoname');
        } else {
          $plotting = array('contra' => 'acno', 'acnoname' => 'acnoname', 'acnoid' => 'acnoid');
        }

        break;
      case 'EX':
        if ($config['params']['doc'] == 'SN') {
          $plotting = array('waybill' => 'acno', 'expacnoname' => 'acnoname');
        } else {
          $plotting = array('contra' => 'acno', 'acnoname' => 'acnoname');
          if ($doc == 'RN' || $doc == 'RM') {
            $plotting = array('revenueaccount' => 'acnoname', 'expid' => 'acnoid');
            $plottype = 'plotgrid';
          }
        }

        break;
      case 'CG':
        $plotting = array('waybill' => 'acno', 'expacnoname' => 'acnoname', 'contra2' => 'acno', 'acnoname2' => 'acnoname');
        break;
      default:
        $plotting = array('contra' => 'acno', 'acnoname' => 'acnoname', 'acnoid' => 'acnoid');

        switch ($doc) {
          case 'RM':
            if ($config['params']['lookupclass'] == 'IN') {
              $plotting = array('assetaccount' => 'acnoname', 'invid' => 'acnoid');
              $plottype = 'plotgrid';
            }
            break;
        }

        switch ($company) {
          case 10: //afti
          case 12: //afti usd
            if ($config['params']['lookupclass'] == 'CB') {
              $plotting = array('contra' => 'acno', 'acnoname' => 'acnoname');
            } else {
              // $plotting = array('contra' => 'acnoname', 'contracode' => 'contra', 'acnoid' => 'acnoid');
              $plotting = array('contra' => 'acno', 'acnoname' => 'acnoname', 'acnoid' => 'acnoid', 'contracode' => 'acno');
            }

            break;
          case 55: //afli
            if ($doc == 'CV') {
              $plotting = array('contra' => 'acno', 'acnoname' => 'acnoname', 'acnoid' => 'acnoid', 'checkno' => 'checkno');
            }
            if ($config['params']['lookupclass'] == 'dashboard') {
              $plottype = 'plotledger';
            }
            break;
          case 57: //cdo financing
          case 40: //cdo
            if ($doc == 'DX') {
              $plotting = array('bank' => 'acnoid', 'acnoname' => 'acnoname', 'contra' => 'acno');
            }
            break;
        }

        if ($config['params']['lookupclass'] == 'BANKBOOK') {
          $plottype = 'plotledger';
          $alias = 'CB';
        }
    }

    $plotsetup = array(
      'plottype' => $plottype,
      'plotting' => $plotting
    );

    // lookup columns
    $cols = array(
      array('name' => 'acno', 'label' => 'Acct#', 'align' => 'left', 'field' => 'acno', 'sortable' => true, 'style' => 'font-size:16px;'),
      array('name' => 'acnoname', 'label' => 'Account Name', 'align' => 'left', 'field' => 'acnoname', 'sortable' => true, 'style' => 'font-size:16px;')

    );

    switch ($company) {
      case 3: //conti
        $qry = "select acnoid,acno,acnoname from coa where detail=1";
        $data = $this->coreFunctions->opentable($qry);
        break;
      case 8: //maxipro
        if ($config['params']['doc'] == "CV") {
          $qry = "select acno,acnoname from coa where detail=1 and isinactive=0";
          $data = $this->coreFunctions->opentable($qry);
        } else {
          if ($alias == '') {
            $qry = "select acno,acnoname from coa where detail=1 and isinactive=0";
          } else {
            $qry = "select acnoid, acno,acnoname from coa where left(alias,2)=? and isinactive=0";
          }
          $data = $this->coreFunctions->opentable($qry, [$alias]);
        }
        break;
      case 21: //kinggeorge
        switch ($config['params']['doc']) {
          case "AJ":
          case "RR":
          case "DM":
            $qry = "select acnoid, acno,acnoname from coa where detail = 1 ";
            $data = $this->coreFunctions->opentable($qry);
            break;
          default:
            goto defaulthere;
            break;
        }
        break;
      case 39: //cbbsi
        switch ($doc) {
          case 'SK':
            $qry = "select acnoid, acno,acnoname from coa where left(alias,2) in ('AR','CA','CR')";
            $data = $this->coreFunctions->opentable($qry);
            break;
          case 'DM':
            $qry = "select acnoid, acno,acnoname from coa where left(alias,2) in ('AP','CG')";
            $data = $this->coreFunctions->opentable($qry);
            break;
          default:
            if ($alias == '') {
              $qry = "select acno,acnoname from coa where detail=1";
            } else {
              $qry = "select acnoid, acno,acnoname from coa where left(alias,2)=?";
            }
            $data = $this->coreFunctions->opentable($qry, [$alias]);
            break;
        }
        break;
      case 47: //kitchenstar
        $qry = "select acnoid, acno,acnoname from coa where left(alias,2) in ('CR','CA','CB')";
        $data = $this->coreFunctions->opentable($qry);
        break;
      case 40: //cdo 
      case 57: //cdo financing
        if ($doc == 'MJ') {
          $qry = "select acnoid, acno,acnoname from coa where left(alias,2) in ('CA','AR')";
        } else {
          if ($alias == 'DUEMC' || $alias == 'DUESP') {
            $qry = "select acno,acnoname from coa where detail=1";
          } elseif ($alias == 'lookupdepositto') {
            $qry = "select acnoid, acno,acnoname from coa where left(alias,2) in ('CR','CA','CB')";
          } else {
            $qry = "select acnoid, acno,acnoname from coa where left(alias,2)='" . $alias . "'";
          }
        }

        if ($company == 57) { //financing
          $data = $this->coreFunctions->opentable($qry, [], 'mysql2');
        } else {
          $data = $this->coreFunctions->opentable($qry);
        }

        break;
      case 49: //hotmix
        if ($doc == 'SJ') {
          $qry = "select acnoid, acno,acnoname from coa where left(alias,2) in ('AR','CR')";
          $data = $this->coreFunctions->opentable($qry, [$alias]);
        } else {
          goto defaulthere;
        }
        break;
      default:
        defaulthere:
        if ($alias == '') {
          $qry = "select acno,acnoname from coa where detail=1";
        } else {
          if ($alias == 'DUEMC' || $alias == 'DUESP' || $alias == 'DEPRECR' || $alias == 'DEPREDB') {
            $qry = "select acno,acnoname, acnoid from coa where detail=1";
          } elseif ($alias == 'lookupdepositto') {
            $qry = "select acnoid, acno,acnoname from coa where left(alias,2) in ('CR','CA','CB')";
          } else {
            if ($doc == 'CV' && $company == 55) { //afli
              $qry = "select c.acnoid, c.acno,c.acnoname,case ifnull(ch.current,'') when '' then '' else (case ch.current when 0 then ch.start else ch.current+1 end) end as checkno from coa as c left join checksetup as ch on ch.acnoid = c.acnoid and ch.current <> ch.end where left(c.alias,2)=?";
            } else {
              switch ($company) {
                case 55: //afli
                  if ($alias == 'dashboard') {
                    $qry = "select acnoid, acno,acnoname from coa where left(alias,2) in ('CR','CA','CB')";
                  } else {
                    goto select;
                  }
                  break;
                case 59: //roosevelt
                  if ($doc == 'BE') {
                    $qry = "select acnoid, acno,acnoname from coa where left(alias,2) in ('CR','CA','CB')";
                  } else {
                    goto select;
                  }
                  break;
                default:
                  select:
                  $qry = "select acnoid, acno,acnoname from coa where left(alias,2)=?";
                  break;
              }
            }
          }
        }

        $data = $this->coreFunctions->opentable($qry, [$alias]);
        break;
    }

    $btnadd = $this->sqlquery->checksecurity($config, 2, '/unique/coa');

    switch ($doc) {
      case 'RN':
      case 'RM':
        switch ($config['params']['lookupclass']) {
          case 'IN':
          case 'EX':
            $table = $config['params']['table'];
            $rowindex = $config['params']['index'];
            return ['status' => true, 'msg' => 'ok', 'data' => $data, 'lookupsetup' => $lookupsetup, 'cols' => $cols, 'plotsetup' => $plotsetup, 'table' => $table, 'rowindex' => $rowindex];
            break;
        }
        break;
    }

    return ['status' => true, 'msg' => 'ok', 'data' => $data, 'lookupsetup' => $lookupsetup, 'cols' => $cols, 'plotsetup' => $plotsetup, 'btnadd' => $btnadd];
  }

  //A
  public function pendingcdsummary($config)
  {

    $lookupclass = $config['params']['lookupclass'];
    $btns = ['summary' => ['label' => 'Show Details', 'lookupclass' => 'lookupsetup', 'action' => 'pendingcddetail']];
    $type = 'multi';
    $actioncallback = 'getcdsummary';
    $callbackfieldlookup = array();
    $style = 'width:100%;max-width:100%;';
    $title = 'List of Approved Canvass Sheet Summary';

    if ($config['params']['companyid'] == 3 && $lookupclass == 'pendingcdsummaryshortcut') { //conti
      $btns = $btns;
      $type = 'single';
      $actioncallback = 'getcdsummaryshortcut';
      $callbackfieldlookup = array('trno');
      $title = 'Pending Canvass Sheet Summary';
      $style = 'width:100%;max-width:100%;';
    } else {
      if ($lookupclass == 'pendingcdsummaryshortcut') {
        $btns = $btns;
        $type = 'single';
        $actioncallback = 'getcdsummaryshortcut';
        $callbackfieldlookup = array('client');
        $title = 'List of Approved Suppliers';
        $style = 'width:100%;max-width:100%;';
      }
    }

    $lookupsetup = array(
      'type' => $type,
      'rowkey' => 'trno',
      'title' =>  $title,
      'btns' => $btns,
      'style' => $style
    );

    $plotsetup = array(
      'plottype' => 'callback',
      'action' => $actioncallback,
      'callbackfieldlookup' => $callbackfieldlookup
    );

    // lookup columns
    $cols = array();
    if ($lookupclass == 'pendingcdsummaryshortcut') {
      if ($config['params']['companyid'] == 3) { //conti
        array_push($cols, array('name' => 'docno', 'label' => 'Document#', 'align' => 'left', 'field' => 'docno', 'sortable' => true, 'style' => 'font-size:16px;'));
