  //A
  public function pendingprsummary($config)
  {
    $type = 'multi';
    $callbackfieldlookup = array();
    $doc = $config['params']['doc'];
    switch ($config['params']['lookupclass']) {
      case 'pendingprsummaryshortcut':
        $summary = [];
        $type = 'single';
        $actioncallback = 'getprsummaryshortcut';
        $callbackfieldlookup = array('trno');

        if (isset($config['params']['addedparams'][0])) {
          if ($config['params']['addedparams'][0] != "") {
            if (floatval($config['params']['addedparams'][0]) != 0) {
              $poseq = $config['params']['addedparams'][1]['value'] . $config['params']['addedparams'][0];
              $checkdocno  = $this->othersClass->PadJ($poseq, $this->companysetup->getdocumentlength($config['params']));
              $existtrno = $this->coreFunctions->getfieldvalue(app('App\Http\Classes\modules\purchase\\' . strtolower($config['params']['doc']))->tablenum, "trno", "docno=?", [$checkdocno]);
              if ($existtrno != '') {
                if (floatval($existtrno) != 0) {
                  return ['status' => false, 'msg' => $checkdocno . ' already exist.'];
                }
              }
            }
          }
        }

        break;
      default:
        $actioncallback = 'getprsummary';
        break;
    }

    $title = 'Purchase Requisition';

    if ($doc == 'JO') {
      $title = 'Job Requisition';
    }

    $lookupsetup = array(
      'type' => $type,
      'rowkey' => 'trno',
      'title' => 'List of Pending ' . $title . ' Summary',
      'btns' => ['summary' => ['label' => 'Show Details', 'lookupclass' => 'lookupsetup', 'action' => 'pendingprdetail']],
      'style' => 'width:100%;max-width:100%;'
    );
    $plotsetup = array(
      'plottype' => 'callback',
      'action' =>  $actioncallback,
      'callbackfieldlookup' =>  $callbackfieldlookup
    );

    // lookup columns
    $cols = array(
      array('name' => 'docno', 'label' => 'Document#', 'align' => 'left', 'field' => 'docno', 'sortable' => true, 'style' => 'font-size:16px;'),
      array('name' => 'dateid', 'label' => 'Date', 'align' => 'left', 'field' => 'dateid', 'sortable' => true, 'style' => 'font-size:16px;'),
      array('name' => 'client', 'label' => 'Code', 'align' => 'left', 'field' => 'client', 'sortable' => true, 'style' => 'font-size:16px;'),
      array('name' => 'clientname', 'label' => 'Name', 'align' => 'left', 'field' => 'clientname', 'sortable' => true, 'style' => 'font-size:16px;')
    );
    if ($config['params']['lookupclass'] == 'pendingdrsummaryshortcut') {
      $data = $this->sqlquery->getpendingprsummaryshortcut($config);
    } else if ($config['params']['lookupclass'] == 'pendingprsummaryshortcut') {
      $data = $this->sqlquery->getpendingprsummaryshortcut($config);
    } else {
      $data = $this->sqlquery->getpendingprsummary($config);
    }
    return ['status' => true, 'msg' => 'ok', 'data' => $data, 'lookupsetup' => $lookupsetup, 'cols' => $cols, 'plotsetup' => $plotsetup];
