  public function pendingcidetail($config)
  {
    $center = $config['params']['center'];

    $lookupsetup = array(
      'type' => 'multi',
      'rowkey' => 'keyid',
      'title' => 'List of Pending Construction Instruction',
      'style' => 'width:100%;max-width:100%;'
    );

    $plotsetup = array(
      'plottype' => 'callback',
      'action' => 'getcidetails'
    );

    // lookup columns
    $cols = array(
      array('name' => 'docno', 'label' => 'Document#', 'align' => 'left', 'field' => 'docno', 'sortable' => true, 'style' => 'font-size:16px;'),
      array('name' => 'dateid', 'label' => 'Date', 'align' => 'left', 'field' => 'dateid', 'sortable' => true, 'style' => 'font-size:16px;'),
      array('name' => 'barcode', 'label' => 'Barcode', 'align' => 'left', 'field' => 'barcode', 'sortable' => true, 'style' => 'font-size:16px;'),
      array('name' => 'itemname', 'label' => 'Itemname', 'align' => 'left', 'field' => 'itemname', 'sortable' => true, 'style' => 'font-size:16px;'),
      array('name' => 'rrqty', 'label' => 'Request Qty', 'align' => 'left', 'field' => 'rrqty', 'sortable' => true, 'style' => 'font-size:16px;'),
      array('name' => 'qa', 'label' => 'Served', 'align' => 'left', 'field' => 'qa', 'sortable' => true, 'style' => 'font-size:16px;'),
      array('name' => 'pending', 'label' => 'Pending', 'align' => 'left', 'field' => 'pending', 'sortable' => true, 'style' => 'font-size:16px;'),
    );


    if ($config['params']['lookupclass'] == "pendingcidetail") {
      $citrno = isset($config['params']['addedparams'][0]) ? $config['params']['addedparams'][0] : 0;
    }

    $qry = "select concat(stock.trno,stock.line) as keyid,stock.trno,stock.line,head.docno,left(head.dateid,10) as dateid,stock.barcode,stock.itemname,stock.uom,
                  FORMAT(stock.rrqty," . $this->companysetup->getdecimal('qty', $config['params']) . ") as rrqty,
                  FORMAT(stock.qty," . $this->companysetup->getdecimal('qty', $config['params']) . ") as qty,
                  FORMAT(((stock.qa) / case when ifnull(uom.factor,0)=0 then 1 else uom.factor end)," . $this->companysetup->getdecimal('qty', $config['params']) . ") as qa,
                  FORMAT(((stock.qty-(stock.qa))/ case when ifnull(uom.factor,0)=0 then 1 else uom.factor end)," . $this->companysetup->getdecimal('qty', $config['params']) . ") as pending
            from hcistock as stock
            left join hcihead as head on head.trno=stock.trno
            left join item on item.barcode=stock.barcode
            left join uom on uom.itemid=item.itemid and uom.uom=stock.uom
            left join transnum on transnum.trno = head.trno
            where stock.trno = $citrno and transnum.center = ? and stock.void = 0 
            order by stock.line";
    $data = $this->coreFunctions->opentable($qry, [$center]);

    return ['status' => true, 'msg' => 'ok', 'data' => $data, 'lookupsetup' => $lookupsetup, 'cols' => $cols, 'plotsetup' => $plotsetup];
  }



