  //A
  public function pendingprdetail($config)
  {
    ini_set('max_execution_time', 180);
    $systemtype = $this->companysetup->getsystemtype($config['params']);
    $doc = $config['params']['doc'];
    $companyid = $config['params']['companyid'];

    $title = "List of Pending Purchase Requisition Details";
    $btns = ['summary' => ['label' => 'Show Summary', 'lookupclass' => 'lookupsetup', 'action' => 'pendingprsummary']];

    if ($this->companysetup->getsystemtype($config['params']) == 'ATI' && $doc == 'SS') {
      $btns = [];
      $title = "List of Pending PR Details (" . $config['params']['client'] . ")";
    }

    $lookupsetup = array(
      'type' => 'multi',
      'rowkey' => 'keyid',
      'title' => $title,
      'btns' => $btns,
      'style' => 'width:100%;max-width:100%;'
    );

    switch ($systemtype) {
      case 'CAIMS':
        $title = 'Purchase Requisition';
        if ($doc == 'JO') {
          $title = 'Job Order';
        }

        if ($doc == "JO" || $doc == "PO" || $doc == 'MT') {
          $lookupsetup = array(
            'type' => 'multi',
            'rowkey' => 'keyid',
            'title' => 'List of Pending ' . $title . ' Details',
            'style' => 'width:100%;max-width:100%;'
          );
        }
        break;
    }

    $plotsetup = array(
      'plottype' => 'callback',
      'action' => 'getprdetails'
    );

    // lookup columns
    $cols = array();
    array_push($cols, array('name' => 'docno', 'label' => 'Document#', 'align' => 'left', 'field' => 'docno', 'sortable' => true, 'style' => 'font-size:16px;'));

    if ($this->companysetup->getsystemtype($config['params']) == 'ATI' && $doc == 'OQ') {
      array_push($cols, array('name' => 'category', 'label' => 'Category', 'align' => 'left', 'field' => 'category', 'sortable' => true, 'style' => 'font-size:16px;'));
