  public function pendingbom($config)
  {
    $actioncallback = 'getbomshortcut';
    $callbackfieldlookup = array('trno');

    $yield = 0;
    if (isset($config['params']['addedparams'][0])) {
      $yield = $config['params']['addedparams'][0];
      array_push($callbackfieldlookup, 'qty');
    }

    $lookupsetup = array(
      'type' => 'singlesearch',
      'rowkey' => 'trno',
      'title' => 'List of Finished Goods - BOM',
      'btns' => [],
      'style' => 'width:100%;max-width:100%;'
    );

    $plotsetup = array(
      'plottype' => 'callback',
      'action' => $actioncallback,
      'callbackfieldlookup' => $callbackfieldlookup
    );

    // lookup columns
    $cols = array();
    array_push($cols, array('name' => 'barcode', 'label' => 'Barcode', 'align' => 'left', 'field' => 'barcode', 'sortable' => true, 'style' => 'font-size:16px;'));
    array_push($cols, array('name' => 'itemname', 'label' => 'Itemname', 'align' => 'left', 'field' => 'itemname', 'sortable' => true, 'style' => 'font-size:16px;'));
    array_push($cols, array('name' => 'uom', 'label' => 'UOM', 'align' => 'left', 'field' => 'uom', 'sortable' => true, 'style' => 'font-size:16px;'));
    array_push($cols, array('name' => 'client', 'label' => 'Code', 'align' => 'left', 'field' => 'client', 'sortable' => true, 'style' => 'font-size:16px;'));
    array_push($cols, array('name' => 'clientname', 'label' => 'Customer Name', 'align' => 'left', 'field' => 'clientname', 'sortable' => true, 'style' => 'font-size:16px;'));
    array_push($cols, array('name' => 'batchsize', 'label' => 'Batch Size', 'align' => 'left', 'field' => 'batchsize', 'sortable' => true, 'style' => 'font-size:16px;'));
    array_push($cols, array('name' => 'yield', 'label' => 'Yield', 'align' => 'left', 'field' => 'yield', 'sortable' => true, 'style' => 'font-size:16px;'));

    $qry = "select item.itemid, item.itemid as trno, item.barcode, item.itemname, item.uom, client.client, client.clientname , bom.batchsize, bom.yield, bom.uom2, bom.rem, client.addr as address, " . $yield . " as qty
         from item left join bom on bom.itemid=item.itemid left join client on client.clientid=bom.bclientid 
        where item.isinactive=0 and item.fg_isfinishedgood=1 and bom.itemid is not null order by item.itemname";
    $data = $this->coreFunctions->opentable($qry);

    return ['status' => true, 'msg' => 'ok', 'data' => $data, 'lookupsetup' => $lookupsetup, 'cols' => $cols, 'plotsetup' => $plotsetup];
  }

