    array_push($cols, array('name' => 'dateid', 'label' => 'Date', 'align' => 'left', 'field' => 'dateid', 'sortable' => true, 'style' => 'font-size:16px;'));
    array_push($cols, array('name' => 'barcode', 'label' => 'Barcode', 'align' => 'left', 'field' => 'barcode', 'sortable' => true, 'style' => 'font-size:16px;'));
    array_push($cols, array('name' => 'itemname', 'label' => 'Itemname', 'align' => 'left', 'field' => 'itemname', 'sortable' => true, 'style' => 'font-size:16px;'));
    array_push($cols, array('name' => 'rrcost', 'label' => 'Amount', 'align' => 'left', 'field' => 'rrcost', 'sortable' => true, 'style' => 'font-size:16px;'));
    array_push($cols, array('name' => 'disc', 'label' => 'Disc', 'align' => 'left', 'field' => 'disc', 'sortable' => true, 'style' => 'font-size:16px;'));
    array_push($cols, array('name' => 'rrqty', 'label' => 'OrderQty', 'align' => 'left', 'field' => 'rrqty', 'sortable' => true, 'style' => 'font-size:16px;'));
    array_push($cols, array('name' => 'qa', 'label' => 'Served', 'align' => 'left', 'field' => 'qa', 'sortable' => true, 'style' => 'font-size:16px;'));
    array_push($cols, array('name' => 'pending', 'label' => 'Pending', 'align' => 'left', 'field' => 'pending', 'sortable' => true, 'style' => 'font-size:16px;'));

    $filterclient = '';
    if ($client != '') {
      $filterclient = " and head.client = '" . $client . "'";
    }

    $qry = "select concat(stock.trno,stock.line) as keyid,stock.trno,stock.line,item.itemname,head.docno,left(head.dateid,10) as dateid,item.barcode,
      FORMAT(stock.rrqty," . $this->companysetup->getdecimal('qty', $config['params']) . ") as rrqty,
      FORMAT(stock.qty," . $this->companysetup->getdecimal('qty', $config['params']) . ") as qty,
      FORMAT(stock.rrcost," . $this->companysetup->getdecimal('price', $config['params']) . ") as rrcost,stock.disc,
      FORMAT(stock.cost," . $this->companysetup->getdecimal('price', $config['params']) . ") as cost,
      FORMAT(stock.ext," . $this->companysetup->getdecimal('currency', $config['params']) . ") as ext,wh.client as wh,stock.uom,item.itemid,
      FORMAT((stock.qa / 1)," . $this->companysetup->getdecimal('qty', $config['params']) . ") as qa,
      FORMAT(((stock.qty-stock.qa) / 1)," . $this->companysetup->getdecimal('qty', $config['params']) . ") as pending,stock.loc,head.yourref
      from hpfhead as head
      right join hpfstock as stock on stock.trno = head.trno
      left join item on item.itemid=stock.itemid
      left join transnum on transnum.trno = head.trno
      left join client as wh on wh.clientid=stock.whid
      where transnum.center = ? and stock.qty>stock.qa and stock.void = 0 " . $filterclient;
    $data = $this->coreFunctions->opentable($qry, [$center]);
    return ['status' => true, 'msg' => 'ok', 'data' => $data, 'lookupsetup' => $lookupsetup, 'cols' => $cols, 'plotsetup' => $plotsetup];
  }

