  public function pendingsqsummary($config)
  {
    $companyid = $config['params']['companyid'];
    $lookupclass = 'pendingsqsummary';
    $action = 'pendingsqdetail';
    switch ($config['params']['doc']) {
      case 'PO':
        break;
      case 'CD':
        $lookupclass = 'pendingsqcdsummary';
        $action = 'pendingsqcddetail';
        break;
    }



    if ($config['params']['doc'] == 'PO') {
      if ($config['params']['lookupclass'] == 'pendingsqpohsummary') {
        $lookupsetup = array(
          'actionsearch' => 'searchso_num',
          'type' => 'singlesearch',
          'title' => 'List of Pending Sales Order Summary',
          'style' => 'width:800px;max-width:800px;'
        );
      } else {
        $lookupsetup = array(
          'type' => 'multi',
          'rowkey' => 'trno',
          'title' => 'List of Pending Sales Order',
          'style' => 'width:800px;max-width:800px;'
        );
      }
    } else {
      $lookupsetup = array(
        'type' => 'multi',
        'rowkey' => 'trno',
        'title' => 'List of Pending Sales Order Summary',
        'btns' => ['summary' =>
        ['label' => 'Show Details', 'lookupclass' => $lookupclass, 'action' => $action]],
        'style' => 'width:800px;max-width:800px;'
      );
    }

    if ($config['params']['lookupclass'] == 'pendingsqpohsummary') {
      if ($companyid == 12) { //afti usd
        $plotsetup = array(
          'plottype' => 'plothead',
          'plotting' => array(
            'sodocno' => 'docno',
            'sotrno' => 'sotrno',
            'yourref' => 'yourref',
            'branch' => 'branch',
            'branchcode' => 'branchcode',
            'branchname' => 'branchname',
            'deptid' => 'deptid',
            'dept' => 'dept',
            'deptname' => 'deptname',
            'due' => 'deldate',
            'cur' => 'cur',
            'forex' => 'forex',
            'tax' => 'tax',
            'vattype' => 'vattype'
          )
        );
      } else {
        $plotsetup = array(
          'plottype' => 'plothead',
          'plotting' => array(
            'sodocno' => 'docno',
            'sotrno' => 'sotrno',
            'yourref' => 'yourref',
            'branch' => 'branch',
            'branchcode' => 'branchcode',
            'branchname' => 'branchname',
            'deptid' => 'deptid',
            'dept' => 'dept',
            'deptname' => 'deptname',
            'due' => 'deldate'
          )
        );
      }
    } else {
      $plotsetup = array(
        'plottype' => 'callback',
        'action' => 'getsqsummary'
      );
    }

    // lookup columns
