      array('name' => 'totalamt', 'label' => 'Amount', 'align' => 'left', 'field' => 'totalamt', 'sortable' => true, 'style' => 'font-size:16px;')
    );

    if ($config['params']['lookupclass'] == 'pendingsqpohsummary') {
