  //A   JAC
  public function pendingsosummary($config)
  {
    $type = 'multi';
    $actioncallback = 'getsosummary';
    $callbackfieldlookup = array();
    $companyid = $config['params']['companyid'];

    $summary = ['summary' => ['label' => 'Show Details', 'lookupclass' => 'lookupsetup', 'action' => 'pendingsodetail']];

    switch ($config['params']['lookupclass']) {
      case 'pendingsosummaryshortcut':
        $summary = [];
        $type = 'single';
        $actioncallback = 'getsosummaryshortcut';
        $callbackfieldlookup = array('trno');

        if ($this->companysetup->getisshortcutso($config['params'])) {

          array_push($callbackfieldlookup, 'sjprefix', 'sjseq');

          if ($config['params']['addedparams'][0] != "") {
            if (floatval($config['params']['addedparams'][0]) != 0) {
              $poseq = $config['params']['addedparams'][1]['value'] . $config['params']['addedparams'][0];
              $checkdocno  = $this->othersClass->PadJ($poseq, $this->companysetup->getdocumentlength($config['params']));

              $existtrno = $this->coreFunctions->getfieldvalue(app('App\Http\Classes\modules\sales\\' . strtolower($config['params']['doc']))->tablenum, "trno", "docno=?", [$checkdocno]);
              if ($existtrno != '') {
                if (floatval($existtrno) != 0) {
                  return ['status' => false, 'msg' => $checkdocno . ' already exist.'];
                }
              }
            }
          }
        }
        break;
      case 'pendingsorosummary':
        $summary = ['summary' => ['label' => 'Show Details', 'lookupclass' => 'pendingsorodetail', 'action' => 'pendingsodetail']];
        break;
      case 'pendingtsso':
        $summary = ['summary' => ['label' => 'Show Details', 'lookupclass' => 'pendingtsso', 'action' => 'pendingsodetail']];
        break;
    }

    $lookupsetup = array(
      'type' => $type,
      'rowkey' => 'trno',
      'title' => 'List of Pending Sales Order Summary',
      'btns' => $summary,
      'style' => 'width:100%;max-width:100%;'
    );

    $plotsetup = array(
      'plottype' => 'callback',
      'action' =>  $actioncallback,
      'callbackfieldlookup' =>  $callbackfieldlookup
    );

    // lookup columns
    $cols = array();
    array_push($cols, array('name' => 'docno', 'label' => 'Document#', 'align' => 'left', 'field' => 'docno', 'sortable' => true, 'style' => 'font-size:16px;'));
    array_push($cols, array('name' => 'dateid', 'label' => 'Date', 'align' => 'left', 'field' => 'dateid', 'sortable' => true, 'style' => 'font-size:16px;'));
    if ($config['params']['lookupclass'] == 'pendingsosummaryshortcut') {
      array_push($cols, array('name' => 'clientname', 'label' => 'Customer', 'align' => 'left', 'field' => 'clientname', 'sortable' => true, 'style' => 'font-size:16px;'));
      array_push($cols, array('name' => 'yourref', 'label' => 'Your Ref', 'align' => 'left', 'field' => 'yourref', 'sortable' => true, 'style' => 'font-size:16px;'));
      array_push($cols, array('name' => 'ourref', 'label' => 'Our Ref', 'align' => 'left', 'field' => 'ourref', 'sortable' => true, 'style' => 'font-size:16px;'));
      array_push($cols, array('name' => 'ren', 'label' => 'Remarks', 'align' => 'left', 'field' => 'rem', 'sortable' => true, 'style' => 'font-size:16px;'));
    }
    if ($config['params']['lookupclass'] == 'pendingsorosummary') {
      array_push($cols, array('name' => 'clientname', 'label' => 'Customer', 'align' => 'left', 'field' => 'clientname', 'sortable' => true, 'style' => 'font-size:16px;'));
    }
    if ($companyid == 19) { //housegem
      array_push($cols, array('name' => 'yourref', 'label' => 'Your Ref', 'align' => 'left', 'field' => 'yourref', 'sortable' => true, 'style' => 'font-size:16px;'));
    }
    if ($companyid != 24) { //not goodfound
      array_push($cols, array('name' => 'totalamt', 'label' => 'Amount', 'align' => 'left', 'field' => 'totalamt', 'sortable' => true, 'style' => 'font-size:16px;'));
    }
    if ($companyid == 16) { //ati
      array_push($cols, array('name' => 'sadesc', 'label' => 'SA #', 'align' => 'left', 'field' => 'sadesc', 'sortable' => true, 'style' => 'font-size:16px;'));
      array_push($cols, array('name' => 'podesc', 'label' => 'PO #', 'align' => 'left', 'field' => 'podesc', 'sortable' => true, 'style' => 'font-size:16px;'));
    }

    if ($config['params']['doc'] == 'PO') {
      $data = $this->sqlquery->getpendingsoposummary($config);
    } else {
      $data = $this->sqlquery->getpendingsosummary($config);
    }

    return ['status' => true, 'msg' => 'ok', 'data' => $data, 'lookupsetup' => $lookupsetup, 'cols' => $cols, 'plotsetup' => $plotsetup];
  }

