    $company = $config['params']['companyid'];
    $doc = $config['params']['doc'];
    switch ($config['params']['lookupclass']) {
      case 'pendingdrsummaryshortcut':
      case 'pendingdrretsummaryshortcut':
      case 'drtaggedshortcut':
      case 'drrfshortcut':
        $summary = [];
        $type = 'single';
        $actioncallback = 'getdrsummaryshortcut';
        $callbackfieldlookup = array('trno');

        if ($this->companysetup->getisshortcutdr($config['params'])) {
          // array_push($callbackfieldlookup, 'sjprefix', 'sjseq');
          if (isset($config['params']['addedparams'][0]) && $config['params']['addedparams'][0] != "") {
            if (floatval($config['params']['addedparams'][0]) != 0) {
              $poseq = $config['params']['addedparams'][1]['value'] . $config['params']['addedparams'][0];
              $checkdocno  = $this->othersClass->PadJ($poseq, $this->companysetup->getdocumentlength($config['params']));
              $existtrno = $this->coreFunctions->getfieldvalue(app('App\Http\Classes\modules\sales\\' . strtolower($config['params']['doc']))->tablenum, "trno", "docno=?", [$checkdocno]);
              if ($existtrno != '') {
                if (floatval($existtrno) != 0) {
                  return ['status' => false, 'msg' => $checkdocno . ' already exist.'];
                }
              }
            }
          }
        }
        break;
      default:
        $actioncallback = 'getdrsummary';
        break;
    }
    if ($company == 39 && $doc == 'DP') {
      $lookupsetup = array(
        'type' => $type,
        'rowkey' => 'trno',
        'title' => 'List of Delivery Receipt Summary',
        'style' => 'width:800px;max-width:800px;'
      );
    } else {
      $lookupsetup = array(
        'type' => $type,
        'rowkey' => 'trno',
        'title' => 'List of Delivery Receipt Summary',
        'btns' => ['summary' =>
        ['label' => 'Show Details', 'lookupclass' => 'lookupsetup', 'action' => 'pendingdrdetail']],
        // 'style' => 'width:800px;max-width:800px;'
        'style' => 'width:100%;max-width:100%;'

      );
    }


    $plotsetup = array(
      'plottype' => 'callback',
      'action' =>  $actioncallback,
      'callbackfieldlookup' =>  $callbackfieldlookup
    );

    // lookup columns
    $cols = array(
      array('name' => 'docno', 'label' => 'Document#', 'align' => 'left', 'field' => 'docno', 'sortable' => true, 'style' => 'font-size:16px;'),
      array('name' => 'dateid', 'label' => 'Date', 'align' => 'left', 'field' => 'dateid', 'sortable' => true, 'style' => 'font-size:16px;'),
      array('name' => 'clientname', 'label' => 'Name', 'align' => 'left', 'field' => 'clientname', 'sortable' => true, 'style' => 'font-size:16px;'),
      array('name' => 'totalamt', 'label' => 'Amount', 'align' => 'left', 'field' => 'totalamt', 'sortable' => true, 'style' => 'font-size:16px;')
    );

    if ($config['params']['lookupclass'] == 'pendingdrsummaryshortcut' || $config['params']['lookupclass'] == 'drtaggedshortcut' || $config['params']['lookupclass'] ==  'pendingdrretsummaryshortcut') {
      $data = $this->sqlquery->getpendingdrsummaryshortcut($config);
    } else {
      $data = $this->sqlquery->getpendingdrsummary($config);
    }

    return ['status' => true, 'msg' => 'ok', 'data' => $data, 'lookupsetup' => $lookupsetup, 'cols' => $cols, 'plotsetup' => $plotsetup];
  }

