  //A
  public function lookupvattype($config)
  {
    $lookupsetup = array(
      'type' => 'single',
      'title' => 'Vat Types',
      'style' => 'width:400px;max-width:400px;'
    );

    switch ($config['params']['lookupclass']) {
      case 'customvattype':
        $plotsetup = array(
          'plottype' => 'plotledger',
          'plotting' => array('tax' => 'tax', 'vattype' => 'vat')
        );
        break;
      case 'lookuppostedvattype':
        $plotsetup = array(
          'plottype' => 'plotledger',
          'plotting' => array('tax' => 'tax', 'vattype' => 'vat')
        );
        break;
      default:
        $plotsetup = array(
          'plottype' => 'plothead',
          'plotting' => array('tax' => 'tax', 'vattype' => 'vat')
        );
        break;
    }

    // lookup columns
    $cols = array(
      array('name' => 'vat', 'label' => 'VAT', 'align' => 'left', 'field' => 'vat', 'sortable' => true, 'style' => 'font-size:16px;')
    );

    switch ($config['params']['doc']) {
      case 'QS':
      case 'SJ':
        switch ($config['params']['companyid']) {
          case 10: //afti
            $qry = "
            select 'VATABLE' as vat, '12' as tax 
            union all 
            select 'ZERO-RATED', '0' ";
            break;
          default:
            $qry = "
            select 'NON-VATABLE' as vat, '0' as tax 
            union all 
            select 'VATABLE','12' 
            union all 
            select 'ZERO-RATED', '0' ";
            break;
        }

        break;
      default:
        switch ($config['params']['companyid']) {
          case 16: //ati
            $qry = "
                select 'Non-vat' as vat, '0' as tax 
                union all 
                select 'Vat-registered','12' 
                union all 
                select 'Zero-rated', '0' ";
            break;

          default:
            if ($config['params']['doc'] == '') {
              //from report filter

              switch ($config['params']['name']) {
                case 'sales_summary_per_vat_type':
                  $qry = "
              select 'VATABLE' as vat, '12' as tax 
              union all 
              select 'ZERO-RATED', '0' ";
                  break;
                default:
                  goto defaulthere;
                  break;
              }
            } else {
              defaulthere:
              $qry = "
                select 'NON-VATABLE' as vat, '0' as tax 
                union all 
                select 'VATABLE','12' 
                union all 
                select 'ZERO-RATED', '0' ";
            }
            break;
        }


        break;
    }

    $data = $this->coreFunctions->opentable($qry);
    return ['status' => true, 'msg' => 'ok', 'data' => $data, 'lookupsetup' => $lookupsetup, 'cols' => $cols, 'plotsetup' => $plotsetup];
  }


