  //A
  public function showbalance($config)
  {
    $companyid = $config['params']['companyid'];
    $doc = $config['params']['doc'];
    $lookupsetup = array(
      'type' => 'show',
      'title' => 'Show Item Balance',
      'style' => 'width:1000px;max-width:1000px;'
    );

    $plotsetup = array(
      'plottype' => 'show',
      'action' => '',
      'callbackfieldhead' => [],
      'callbackfieldlookup' => [],
      'plotting' => []
    );

    switch ($companyid) {
      case '40': //CDO
        if ($doc == 'MC') {
          // lookup columns
          $cols = array();
          array_push($cols, array('name' => 'partno', 'label' => 'SKU/Part No.', 'align' => 'left', 'field' => 'partno', 'sortable' => true, 'style' => 'font-size:16px;'));
          array_push($cols, array('name' => 'itemdescription', 'label' => 'Item Description', 'align' => 'left', 'field' => 'itemdescription', 'sortable' => true, 'style' => 'font-size:16px;'));
          array_push($cols, array('name' => 'isqty', 'label' => 'Quantity', 'align' => 'right', 'field' => 'isqty', 'sortable' => true, 'style' => 'font-size:16px;'));
          array_push($cols, array('name' => 'isamt', 'label' => 'Price', 'align' => 'right', 'field' => 'isamt', 'sortable' => true, 'style' => 'font-size:16px;'));
          array_push($cols, array('name' => 'disc', 'label' => 'Discount', 'align' => 'right', 'field' => 'disc', 'sortable' => true, 'style' => 'font-size:16px;'));
          array_push($cols, array('name' => 'ext', 'label' => 'Total', 'align' => 'right', 'field' => 'ext', 'sortable' => true, 'style' => 'font-size:16px;'));

          $trno = $config['params']['trno'];
          $qry = "select 
          i.partno,i.itemname as itemdescription,
          FORMAT(stock.isamt,2) as isamt,
          FORMAT(stock.isqty,2) as isqty,
          FORMAT(stock.iss,2) as iss,
          stock.disc,
          FORMAT(stock.ext,2) as ext
          from glhead as head 
          left join glstock as stock on stock.trno = head.trno 
          left join item as i on i.itemid=stock.itemid
          where head.doc in ('MJ','CI') and stock.trno in (select distinct refx from mcdetail where trno=$trno)";
          $data = $this->coreFunctions->opentable($qry);
          return ['status' => true, 'msg' => 'ok', 'data' => $data, 'lookupsetup' => $lookupsetup, 'cols' => $cols, 'plotsetup' => $plotsetup];
        }
        break;

      default:
        // lookup columns
        $cols = array();
        array_push($cols, array('name' => 'wh', 'label' => 'Code', 'align' => 'left', 'field' => 'wh', 'sortable' => true, 'style' => 'font-size:16px;'));
        array_push($cols, array('name' => 'whname', 'label' => 'Warehouse', 'align' => 'left', 'field' => 'whname', 'sortable' => true, 'style' => 'font-size:16px;'));

        if ($this->companysetup->getispallet($config['params'])) {
          array_push($cols, array('name' => 'location', 'label' => 'Location', 'align' => 'left', 'field' => 'location', 'sortable' => true, 'style' => 'font-size:16px;'));
          array_push($cols, array('name' => 'pallet', 'label' => 'Pallet', 'align' => 'left', 'field' => 'pallet', 'sortable' => true, 'style' => 'font-size:16px;'));
        } else {
          array_push($cols, array('name' => 'loc', 'label' => 'Location', 'align' => 'left', 'field' => 'loc', 'sortable' => true, 'style' => 'font-size:16px;'));
          array_push($cols, array('name' => 'expiry', 'label' => 'Expiry', 'align' => 'left', 'field' => 'expiry', 'sortable' => true, 'style' => 'font-size:16px;'));
        }

        array_push($cols, array('name' => 'bal', 'label' => 'Balance', 'align' => 'right', 'field' => 'bal', 'sortable' => true, 'style' => 'font-size:16px;'));
        array_push($cols, array('name' => 'min', 'label' => 'Minimum', 'align' => 'right', 'field' => 'min', 'sortable' => true, 'style' => 'font-size:16px;'));
        array_push($cols, array('name' => 'max', 'label' => 'Maximum', 'align' => 'right', 'field' => 'max', 'sortable' => true, 'style' => 'font-size:16px;'));
        array_push($cols, array('name' => 'uom', 'label' => 'UOM', 'align' => 'left', 'field' => 'uom', 'sortable' => true, 'style' => 'font-size:16px;'));

        $qry = "select coa.acno,coa.acnoname,gldetail.db,gldetail.cr,gldetail.fdb,gldetail.fcr from gldetail left join coa on coa.acnoid=gldetail.acnoid where gldetail.trno=?";
        $trno = isset($config['params']['trno']) ? $config['params']['trno'] : 0;
        $config['params']['itemid'] = isset($config['params']['itemid']) ? $config['params']['itemid'] : (isset($config['params']['row']) ? $config['params']['row']['itemid'] : 0);
        $data =  $this->sqlquery->itembalance($config);
        return ['status' => true, 'msg' => 'ok', 'data' => $data, 'lookupsetup' => $lookupsetup, 'cols' => $cols, 'plotsetup' => $plotsetup];
        break;
    }
  }


