  //A
  public function lookupproject($config)
  {
    $systemtype = $this->companysetup->getsystemtype($config['params']);
    //default
    $companyid = $config['params']['companyid'];
    $plottype = 'plothead';
    switch ($config['params']['lookupclass']) {
      case 'dproject':
        $plotting = [
          'projectid' => 'line',
          'project' => 'code',
          'projectname' => 'name'
        ];
        if ($config['params']['doc'] == 'MR' && $systemtype == 'REALESTATE') {
          $plotting = array(
            'projectid' => 'line',
            'project' => 'name'
          );
        }
        $plottype = 'plotgrid';
        break;
      case 'userproject':
        $plotting = ['project' => 'code'];
        break;
      case 'projectcode':
        if ($config['params']['doc'] == 'PB') {
          $plotting = array(
            'projectid' => 'projectid',
            'projectcode' => 'code',
            'projectname' => 'name'
          );
        } else {
          if ($this->companysetup->isconstruction($config['params'])) {
            if ($config['params']['doc'] == 'MT') {
              $plotting = array(
                'projectid' => 'projectid',
                'projectcode' => 'code',
                'projectname' => 'name',
                'subproject' => 'sid',
                'subprojectname' => 'subproject'
              );
            }
          } else {
            $plotting = array(
              'projectid' => 'projectid',
              'projectcode' => 'code',
              'projectname' => 'name',
              'subproject' => 'sid',
              'subprojectname' => 'subproject',
              'wh' => 'wh',
              'whname' => 'whname'
            );
          }
        }
        break;
      case 'projectcode2':
        $plotting = array(
          'projectid2' => 'projectid',
          'projectcode2' => 'code',
          'projectname2' => 'name'

        );
        break;
      case 'projectcodets':
        if ($this->companysetup->isconstruction($config['params'])) {
          if ($config['params']['doc'] == 'MT') {
            $plotting = array(
              'projectto' => 'projectid',
              'projectcode2' => 'code',
              'projectname2' => 'name',
              'subprojectto' => 'sid',
              'subprojectname2' => 'subproject'
            );
          }
        } else {
          $plotting = array(
            'projectto' => 'projectid',
            'projectcode2' => 'code',
            'projectname2' => 'name',
            'subprojectto' => 'sid',
            'subprojectname2' => 'subproject',
            'client' => 'wh',
            'clientname' => 'whname'
