              $qry = "select s.line as sid,s.subproject,p.code,head.projectid,p.name,head.wh,wh.clientname as whname from pmhead as head left join projectmasterfile as p on p.line = head.projectid left join subproject as s on s.trno = head.trno left join client as wh on wh.client = head.wh
              union all
