          ['name' => 'liabilityname', 'label' => 'Liability', 'align' => 'left', 'field' => 'liabilityname', 'sortable' => true, 'style' => 'font-size:16px;'],
          ['name' => 'revenuename', 'label' => 'Revenue', 'align' => 'left', 'field' => 'revenuename', 'sortable' => true, 'style' => 'font-size:16px;'],
          ['name' => 'expensename', 'label' => 'Revenue', 'align' => 'left', 'field' => 'expensename', 'sortable' => true, 'style' => 'font-size:16px;'],
        ];

        $qry = "
        select 0 as line, '' as code, '' as name, 
