        asset.acnoname as assetname,
        lia.acno as liability,
        lia.acnoname as liabilityname,
        rev.acno as revenue,
        rev.acnoname as revenuename,
        exp.acno as expense,
        exp.acnoname as expensename
        from projectmasterfile as prj
        left join coa as asset on asset.acnoid = prj.assetid
        left join coa as lia on lia.acnoid = prj.liabilityid
        left join coa as rev on rev.acnoid = prj.revenueid
        left join coa as exp on exp.acnoid = prj.expenseid
        order by line";
        $data = $this->coreFunctions->opentable($qry);
