          ['name' => 'name', 'label' => 'Name', 'align' => 'left', 'field' => 'name', 'sortable' => true, 'style' => 'font-size:16px;']
        ];

        $qry = "
          select 0 as line, ' ' as code, ' ' as name, 0 as phaseid, '' as phase, 0 as blklotid, '' as blklot, '' as lot, 0 as modelid, '' as housemodel
          union all
          select line,code,name, 0 as phaseid, '' as phase, 0 as blklotid, '' as blklot, '' as lot, 0 as modelid, '' as housemodel
          from projectmasterfile 
          order by line";

        if ($config['params']['doc'] != 'FS') {
          $cols = [
            ['name' => 'code', 'label' => 'Code', 'align' => 'left', 'field' => 'code', 'sortable' => true, 'style' => 'font-size:16px;'],
