            ['name' => 'housemodel', 'label' => 'House Model', 'align' => 'left', 'field' => 'housemodel', 'sortable' => true, 'style' => 'font-size:16px;'],
            ['name' => 'phase', 'label' => 'Phase', 'align' => 'left', 'field' => 'phase', 'sortable' => true, 'style' => 'font-size:16px;'],
            ['name' => 'blklot', 'label' => 'Block', 'align' => 'left', 'field' => 'blklot', 'sortable' => true, 'style' => 'font-size:16px;'],
            ['name' => 'lot', 'label' => 'Lot', 'align' => 'left', 'field' => 'lot', 'sortable' => true, 'style' => 'font-size:16px;']
          ];

          $client = $this->coreFunctions->getfieldvalue("client", "clientid", "client = '" . $config['params']['addedparams'][0] . "'");

          if ($config['params']['doc'] == 'CR') {
            $qry = "
            select 0 as line, ' ' as code, ' ' as name, 0 as phaseid, '' as phase, 0 as blklotid, '' as blklot, '' as lot, 0 as modelid, '' as housemodel,'' as ptype,0 as pamount
            union all
            select p.line,p.code,p.name, ph.line as phaseid, ph.code as phase, b.line as blklotid, b.blk as blklot, b.lot, m.line as modelid, m.model as housemodel,
            (select case coa.alias when 'ARDP' then 'Down Payment' when 'ARRF' then 'Reservation' when 'AR1' then 'Monthly Amortization' else '' end as ptype from gldetail as d
            left join hdetailinfo as di on di.trno = d.trno and di.line = d.line left join coa on coa.acnoid=d.acnoid where di.ortrno=0 and d.clientid =" . $client . " 
             and d.projectid = p.line and d.phaseid = ph.line and d.modelid = m.line and d.blklotid = b.line  order by di.line limit 1) as ptype,
             (select d.db from gldetail as d
            left join hdetailinfo as di on di.trno = d.trno and di.line = d.line left join coa on coa.acnoid=d.acnoid where di.ortrno=0 and d.clientid =" . $client . " 
             and d.projectid = p.line and d.phaseid = ph.line and d.modelid = m.line and d.blklotid = b.line  order by di.line limit 1) as pamount
            from projectmasterfile as p left join phase as ph on ph.projectid = p.line left join housemodel as m on m.projectid = p.line 
            left join blklot as b on b.projectid = p.line and b.phaseid = b.phaseid and b.clientid = " . $client . " where b.blk is not null order by line";
          } else {
            $qry = "
            select 0 as line, ' ' as code, ' ' as name, 0 as phaseid, '' as phase, 0 as blklotid, '' as blklot, '' as lot, 0 as modelid, '' as housemodel,'' as ptype,0 as pamount
            union all
            select p.line,p.code,p.name, ph.line as phaseid, ph.code as phase, b.line as blklotid, b.blk as blklot, b.lot, m.line as modelid, m.model as housemodel ,'' as ptype,0 as pamount
            from projectmasterfile as p left join phase as ph on ph.projectid = p.line left join housemodel as m on m.projectid = p.line and m.phaseid = ph.line
            left join blklot as b on b.projectid = p.line and b.phaseid = b.phaseid and b.modelid = m.line and b.clientid = " . $client . " where b.blk is not null order by line";
          }
        }

        $data = $this->coreFunctions->opentable($qry);
        $btnadd = $this->sqlquery->checksecurity($config, 859, '/tableentries/tableentry/entryproject');

        break;
      default:
        $cols = [
          ['name' => 'code', 'label' => 'Code', 'align' => 'left', 'field' => 'code', 'sortable' => true, 'style' => 'font-size:16px;'],
          ['name' => 'name', 'label' => 'Name', 'align' => 'left', 'field' => 'name', 'sortable' => true, 'style' => 'font-size:16px;']
        ];

        $qry = "
          select 0 as line, ' ' as code, ' ' as name
          union all
          select line,code,name 
          from projectmasterfile  where isinactive =0
          order by line";

        if ($config['params']['doc'] == 'PX') {
          $qry = "
          select 0 as line, 'VARIOUS' as code, 'VARIOUS' as name
          union all
          select line,code,name 
          from projectmasterfile  where isinactive =0
          order by line";
        }


        $data = $this->coreFunctions->opentable($qry);
        $btnadd = $this->sqlquery->checksecurity($config, 859, '/tableentries/tableentry/entryproject');
        break;
    }

    switch ($config['params']['lookupclass']) {
      case 'dproject':
