  //A
  public function lookupcenter($config)
  {
    //default    
    $plottype = 'plothead';
    $filter = '';
    $companyid = $config['params']['companyid'];
    $center = $config['params']['center'];

    if ($companyid == 40 || $companyid == 56 || $companyid == 29) { //cdo, homeworks and sbc
      $title = 'List of Branches';
    } else {
      $title = 'List of Project';
    }


    switch ($config['params']['lookupclass']) {
      case 'branchpr':
        $plotting = array('client' => 'code', 'clientname' => 'name');
        break;
      case 'trbranch':
        $plotting = array('client' => 'code', 'clientname' => 'name', 'wh2' => 'warehouse');
        break;
      case 'stbranch':
        $plotting = array('deptid' => 'line', 'dept' => 'code', 'clientname' => 'name', 'client' => 'warehouse', 'wh2' => 'whname');
        if ($companyid == 40) { //cdo
          $filter = " and c.code <> '$center'";
        }
        break;
      default:
        $plotting = array('center' => 'code', 'centername' => 'name');
        break;
    }

    $lookupsetup = array(
      'type' => 'single',
      'title' => $title,
      'style' => 'width:900px;max-width:900px;'
    );
    $plotsetup = array(
      'plottype' => $plottype,
      'action' => '',
      'plotting' => $plotting
    );
    // lookup columns
    $cols = [
      ['name' => 'code', 'label' => 'Code', 'align' => 'left', 'field' => 'code', 'sortable' => true, 'style' => 'font-size:16px;'],
      ['name' => 'name', 'label' => 'Name', 'align' => 'left', 'field' => 'name', 'sortable' => true, 'style' => 'font-size:16px;']
    ];

    if ($this->companysetup->getmultibranch($config['params'])) {
      array_push($cols, ['name' => 'shortname', 'label' => 'Shortname', 'align' => 'left', 'field' => 'shortname', 'sortable' => true, 'style' => 'font-size:16px;']);
    }



    $user = $config['params']['user'];
    if ($this->companysetup->getmultibranch($config['params'])) {
      switch ($config['params']['lookupclass']) {
        case 'getmultibranch':
          if ($config['params']['logintype'] == '62608e08adc29a8d6dbc9754e659f125') {
            $userid = $this->coreFunctions->getfieldvalue("client", "userid", "email=?", [$user]);
          } else {
            $userid = $this->coreFunctions->getfieldvalue("useraccess", "userid", "username=?", [$user]);
          }
          $qry = "select access.center as code,center.name,center.shortname from center 
          left join centeraccess as access on access.center = center.code
          left join useraccess as user on user.userid = access.userid
          where access.userid = $userid";
          break;
        case 'stbranch':
          $qry = "select center.line,center.code,center.name,center.shortname,center.warehouse,wh.clientname as whname from center left join client as wh on wh.client = center.warehouse order by center.line";
          break;

        default:
          $qry = "select c.line,c.code,c.name,c.warehouse,wh.clientname as whname,c.shortname from center as c left join centeraccess as ca on ca.center=c.code 
          left join useraccess as u on u.userid=ca.userid left join client as wh on wh.client = c.warehouse where u.username='$user' $filter order by c.line";
          break;
      }
    } else {
      $qry = "select line,code,name,shortname from center order by line";
    }
    $data = $this->coreFunctions->opentable($qry);
    return ['status' => true, 'msg' => 'ok', 'data' => $data, 'lookupsetup' => $lookupsetup, 'cols' => $cols, 'plotsetup' => $plotsetup];
  } //end function

  public function lookupcenter_reports($config)
  {
    //default
    $plotting = array('center' => 'code', 'centername' => 'name');
    $plottype = 'plothead';
    $title = 'List of Project';

    $lookupsetup = array(
      'type' => 'single',
      'title' => $title,
      'style' => 'width:900px;max-width:900px;'
    );
    $plotsetup = array(
      'plottype' => $plottype,
      'action' => '',
      'plotting' => $plotting
    );
    // lookup columns
    $cols = [
      ['name' => 'code', 'label' => 'Code', 'align' => 'left', 'field' => 'code', 'sortable' => true, 'style' => 'font-size:16px;'],
      ['name' => 'name', 'label' => 'Name', 'align' => 'left', 'field' => 'name', 'sortable' => true, 'style' => 'font-size:16px;']
    ];

    if ($this->companysetup->getmultibranch($config['params'])) {
      array_push($cols, ['name' => 'shortname', 'label' => 'Shortname', 'align' => 'left', 'field' => 'shortname', 'sortable' => true, 'style' => 'font-size:16px;']);
    }

    $limitview = $this->othersClass->checkAccess($config['params']['user'], 4165);

    $user = $config['params']['user'];
    if ($this->companysetup->getmultibranch($config['params'])) {

      if ($limitview) {
        $qry = "
        select 0 as line, '0' as code, 'ALL' as name, '' as shortname
        union all
        select c.line,c.code,c.name from center as c
        left join centeraccess as ca on ca.center=c.code
        left join useraccess as u on u.userid=ca.userid
        where u.username='$user'
        order by line
        ";
      } else {
        $qry = "
        select c.line,c.code,c.name, c.shortname from center as c
        left join centeraccess as ca on ca.center=c.code
        left join useraccess as u on u.userid=ca.userid
        where u.username='$user'
        order by line
        ";
      }
    } else {
      if ($limitview) {
        $qry = "
        select 0 as line, '0' as code, 'ALL' as name, '' as shortname
        union all
        select line,code,name,shortname from center
        order by line
        ";
      } else {
        $qry = "
        select line,code,name from center
