  public function lookuppreparedby($config)
  {
    $companyid = $config['params']['companyid'];
    $lclass = $config['params']['lookupclass'];
    $doc = $config['params']['doc'];

    //default
    $plotting = array('preparedbyid' => 'clientid', 'preparedby' => 'clientname');
    $plottype = 'plothead';
    $title = 'Prepared By';
    $filter = "and dept.client = 'DEP0000001'";

    if ($companyid == 10 || $companyid == 12) { //afti, afti usd
      switch ($lclass) {
        case 'powh_receiver':
          $title = "Warehouse Receiver List";
          $plotting = array('whreceiver' => 'clientid', 'whreceivername' => 'clientname');
          break;
        case 'prepared':
          $title = ucfirst($lclass) . ' By';
          $plotting = array('prepared' => 'clientname');
          $filter = "and dept.client in ('DEP0000001')";
          break;
        case 'approved':
          $title = ucfirst($lclass) . ' By';
          $plotting = array('approved' => 'clientname');
          if ($doc == 'PO' || $doc == 'JB') {
            $filter = " and (dept.client = 'DEP0000005' and emp.client = 'EM00000001') or cl.client = 'EM00000001' or cl.client='EM00000030' ";
          }
          break;
        case 'noted':
          $title = ucfirst($lclass) . ' By';
          $plotting = array('noted' => 'clientname');

          if ($doc == 'PO' || $doc == 'JB' || $doc == 'MC') {
            $filter = " and (dept.client = 'DEP0000005' and emp.client = 'EM00000001') or cl.client = 'EM00000001' or cl.client='EM00000030' ";
          }
          break;
        case 'checked':
          $title = ucfirst($lclass) . ' By';
          $plotting = array('checked' => 'clientname');
          if ($doc == 'PO' || $doc == 'JB') {
            $filter = "and dept.client = 'DEP0000001' and emp.client = 'EM00000001'";
          }
          break;
        case 'payor':
          $title = ucfirst($lclass) . ' By';
          $plotting = array('payor' => 'clientname');
          break;
      }
      if ($doc == 'GJ') {
        $filter = '';
      }
    }

    $lookupsetup = array(
      'type' => 'single',
      'title' => $title,
      'style' => 'width:900px;max-width:900px;'
    );
    $plotsetup = array(
      'plottype' => $plottype,
      'action' => '',
      'plotting' => $plotting
    );
    // lookup columns
    $cols = [
      ['name' => 'client', 'label' => 'Code', 'align' => 'left', 'field' => 'client', 'sortable' => true, 'style' => 'font-size:16px;'],
      ['name' => 'clientname', 'label' => 'Name', 'align' => 'left', 'field' => 'clientname', 'sortable' => true, 'style' => 'font-size:16px;']
    ];


    $qry = "select cl.deptid, cl.clientid, cl.client, cl.clientname, dept.clientname as deptname
    from client as cl
    left join client as dept on dept.clientid = cl.deptid
    left join client as emp on cl.empid = emp.clientid
    where cl.isemployee = 1 $filter";
    $data = $this->coreFunctions->opentable($qry);
    return ['status' => true, 'msg' => 'ok', 'data' => $data, 'lookupsetup' => $lookupsetup, 'cols' => $cols, 'plotsetup' => $plotsetup];
  } //end function


