  public function lookupreqcategory($config)
  {
    //default
    $plotting = array();
    $plottype = 'plothead';
    $title = 'List of Category';
    $companyid = $config['params']['companyid'];

    if ($companyid == 58) { //cdo
      $condition = ' iscat =1 and isreassigned=1';
    } else {
      $condition = ' iscat =1';
    }

    switch ($config['params']['lookupclass']) {
      case 'lookupreqcategoryposted':
      case 'rscategory':
        $plottype = 'plotledger';
        break;
    }

    switch ($config['params']['lookupclass']) {
      case 'lookuptasktype':
        $title = 'Task Type';
        $condition = ' istasktype = 1';
        $plotting = array('tasktype' => 'category', 'taskid' => 'line');
        break;
      case 'lookuploan':
        $title = 'Type of Loan';
        $condition = ' isloantype = 1';
        $plotting = array('categoryname' => 'reqtype', 'planid' => 'line');
        break;
      case 'lookuppurpose':
        $line = isset($config['params']['addedparams'][0]) ? $config['params']['addedparams'][0] : ''; // planid
        $title = 'Loan Purpose';
        $condition = "ispurpose = 1 and category = '" . $line . "'";
        $plotting = array('purpose' => 'reqtype', 'plangrpid' => 'category');
        break;
      case 'lookuptaskcategory':
        $title = 'Task Category';
        $condition = ' istaskcat = 1';
        $plotting = array('category' => 'category', 'taskcatid' => 'line');
        break;
      default:
        if ($companyid == 58) { //cdo
          $plotting = array('categoryname' => 'category', 'category' => 'line');
        } else {
          $plotting = array('categoryname' => 'category', 'ourref' => 'line');
        }
        break;
    }

    $lookupsetup = array(
      'type' => 'single',
      'title' => $title,
      'style' => 'width:900px;max-width:900px;'
    );
    $plotsetup = array(
      'plottype' => $plottype,
      'action' => '',
      'plotting' => $plotting
    );
    // lookup columns
    switch ($config['params']['lookupclass']) {
      case 'lookuploan':
        $cols = [
          ['name' => 'category', 'label' => 'Code', 'align' => 'left', 'field' => 'category', 'sortable' => true, 'style' => 'font-size:16px;'],
          ['name' => 'reqtype', 'label' => 'Loan Type', 'align' => 'left', 'field' => 'reqtype', 'sortable' => true, 'style' => 'font-size:16px;']
        ];
        break;
      case 'lookuppurpose':
        $cols = [['name' => 'reqtype', 'label' => 'Purpose', 'align' => 'left', 'field' => 'reqtype', 'sortable' => true, 'style' => 'font-size:16px;']];
        break;
      case 'lookuptasktype':
        $cols = [['name' => 'category', 'label' => 'Task Type', 'align' => 'left', 'field' => 'category', 'sortable' => true, 'style' => 'font-size:16px;']];
        break;
      default:
        $cols = [['name' => 'category', 'label' => 'Category', 'align' => 'left', 'field' => 'category', 'sortable' => true, 'style' => 'font-size:16px;']];
        break;
    }

    $qry = "select line, category,reqtype from reqcategory where  $condition";
    $data = $this->coreFunctions->opentable($qry);

    $btnadd = [];

    if ($companyid == 58) { //cdo
      if ($config['params']['doc'] == 'RS') {
        // $index = $config['params']['index'];
        $btnadd = $this->sqlquery->checksecurity($config, 3742, '/tableentries/othersettings/entryrequestcategory');
      }
    }



    return ['status' => true, 'msg' => 'ok', 'data' => $data, 'lookupsetup' => $lookupsetup, 'cols' => $cols, 'plotsetup' => $plotsetup, 'btnadd' => $btnadd];
  } //end function


