  public function lookupcoa($config)
  {
    $lookupsetup = array(
      'type' => 'single',
      'title' => 'List of Chart of Accounts',
      'style' => 'width:100%;max-width:80%;'
    );

    $filteralias = '';

    switch ($config['params']['lookupclass']) {
      case 'asset':
        $plotsetup = array(
          'plottype' => 'plothead',
          'plotting' => array('asset' => 'acno', 'assetname' => 'acnoname')
        );
        break;

      case 'liability':
        $plotsetup = array(
          'plottype' => 'plothead',
          'plotting' => array('liability' => 'acno', 'liabilityname' => 'acnoname')
        );
        break;

      case 'revenue':
        $plotsetup = array(
          'plottype' => 'plothead',
          'plotting' => array('revenue' => 'acno', 'revenuename' => 'acnoname')
        );
        break;

      case 'expense':
        $plotsetup = array(
          'plottype' => 'plothead',
          'plotting' => array('expense' => 'acno', 'expensename' => 'acnoname')
        );
        break;

      case 'salesreturn':
        $plotsetup = array(
          'plottype' => 'plothead',
          'plotting' => array('salesreturn' => 'acno', 'salesreturnname' => 'acnoname')
        );
        $filteralias = " and left(alias,2)='SR'";
        break;


      case 'detail2':
        $plotsetup = array(
          'plottype' => 'plothead',
          'plotting' => array('contra2' => 'acno', 'acnoname2' => 'acnoname', 'acnoid2' => 'acnoid')
        );
        break;
      case 'detail3':
        $plotsetup = array(
          'plottype' => 'plothead',
          'plotting' => array('contra3' => 'acno', 'acnoname3' => 'acnoname', 'acnoid3' => 'acnoid')
        );
        break;

      case 'detail4':
        $plotsetup = array(
          'plottype' => 'plothead',
          'plotting' => array('contra4' => 'acno', 'acnoname4' => 'acnoname', 'acnoid4' => 'acnoid')
        );
        break;
      case 'acctadvances': //detail1
        $plotsetup = array(
          'plottype' => 'plothead',
          'plotting' => array('acctadvances' => 'acnoname')
        );
        break;
      case 'banklookup':
        $plotsetup = array(
          'plottype' => 'plothead',
          'plotting' => array('contra5' => 'acno', 'acnoname5' => 'acnoname', 'acnoid5' => 'acnoid')
        );
        $filteralias = " left(alias,2)='CB'";
        break;

      default:
        $plotsetup = array(
          'plottype' => 'plothead',
          'plotting' => array('contra' => 'acno', 'acnoname' => 'acnoname')
        );
        if (isset($config['params']['name'])) {
          if ($config['params']['name'] == 'subsidiary_ledger') {
            $plotsetup['plotting']['acnoid'] = 'acnoid';
            $plotsetup['plotting']['cat'] = 'cat';
          }
        }
        break;
    }

    $blank = '';
    switch ($config['params']['lookupclass']) {
      case 'asset':
      case 'liability':
      case 'revenue':
      case 'expense':
      case 'detail':
      case 'detail2':
      case 'detail3':
      case 'detail4':
      case 'salesreturn':
      case 'acctadvances':
        $condition = 'where detail = 1 ' . $filteralias;
        $blank = "select '' as acno, '' as acnoname, 0 as acnoid, '' as cat union all";
        break;
      case 'banklookup': //'`'
        $blank = "select '' as acno, paymode.category as acnoname, paymode.line as  acnoid, '' as cat from
                  reqcategory as paymode where paymode.ispaymode =1 and paymode.category not in ('Cash','Check','Bank')
                  union all";

        $condition = 'where ' . $filteralias;
        break;

      default: // levelid default
        $condition = 'where levelid = 1';
        break;
    }
    // lookup columns

    $cols = array(
      array('name' => 'acno', 'label' => 'Acct#', 'align' => 'left', 'field' => 'acno', 'sortable' => true, 'style' => 'font-size:16px;'),
      array('name' => 'acnoname', 'label' => 'Account Name', 'align' => 'left', 'field' => 'acnoname', 'sortable' => true, 'style' => 'font-size:16px;')
    );


    switch ($config['params']['lookupclass']) {
      case 'replookupcoa':
        $qry = "select acno, acnoname,acnoid,cat from coa";
        break;
      default:
        $qry = " " . $blank . " select acno,acnoname,acnoid,cat from coa " . $condition . " ";
        break;
    }
    $data = $this->coreFunctions->opentable($qry);
    $btnadd = $this->sqlquery->checksecurity($config, 5, '/unique/coa');

    return ['status' => true, 'msg' => 'ok', 'data' => $data, 'lookupsetup' => $lookupsetup, 'cols' => $cols, 'plotsetup' => $plotsetup, 'btnadd' => $btnadd];
  }

