  public function viewitemvoid($config)
  {
    $lookupsetup = array(
      'type' => 'multi',
      'rowkey' => 'keyid',
      'title' => 'List of Items to Void',
      'style' => 'width:1200px;max-width:1200px;'
    );

    $plotsetup = array(
      'plottype' => 'callback',
      'action' => 'updateitemvoid'
    );

    // lookup columns
    $cols = array(
      array('name' => 'barcode', 'label' => 'Barcode', 'align' => 'left', 'field' => 'barcode', 'sortable' => true, 'style' => 'font-size:16px;'),
      array('name' => 'itemname', 'label' => 'Item Name', 'align' => 'left', 'field' => 'itemname', 'sortable' => true, 'style' => 'font-size:16px;'),
      array('name' => 'uom', 'label' => 'UOM', 'align' => 'left', 'field' => 'uom', 'sortable' => true, 'style' => 'font-size:16px;'),
      array('name' => 'wh', 'label' => 'Warehouse', 'align' => 'left', 'field' => 'wh', 'sortable' => true, 'style' => 'font-size:16px;'),
      array('name' => 'qty', 'label' => 'Quantity', 'align' => 'left', 'field' => 'qty', 'sortable' => true, 'style' => 'font-size:16px;'),
      array('name' => 'qa', 'label' => 'Pending', 'align' => 'left', 'field' => 'qa', 'sortable' => true, 'style' => 'font-size:16px;')

    );

    $trno = $config['params']['trno'];
    $qry = "select concat(trno,line) as keyid,trno,line,barcode,itemname,uom,wh,rrqty as qty from hpostock where void<>1 and trno =?
            union all
            select concat(trno,line) as keyid,trno,line,barcode,itemname,uom,wh,isqty as qty from hsostock where qa<>iss and void<>1 and trno =?";
    $data = $this->coreFunctions->opentable($qry, [$trno, $trno]);

    return ['status' => true, 'msg' => 'ok', 'data' => $data, 'lookupsetup' => $lookupsetup, 'cols' => $cols, 'plotsetup' => $plotsetup];
