  // GLEN 09.16.2020
  public function lookupusers($config)
  {
    //default
    $companyid = $config['params']['companyid'];
    $plotting = array();
    $plottype = '';

    if ($companyid == 8 && $config['params']['lookupclass'] == 'useraccess') { //maxipro
      $title = 'List of Levels';
    } else {
      $title = 'List of User';
    }

    switch ($config['params']['lookupclass']) {
      case 'getusername':
        $plotting = array('username' => 'username');
        $plottype = 'plotledger';
      case 'lookupusers':
        switch ($companyid) {
          case 29:
            $plotting = array('userid' => 'userid', 'username' => 'name', 'project' => 'project');
            $plottype = 'plothead';
            break;
          default:
            $plotting = array('userid' => 'userid', 'username' => 'username', 'project' => 'project');
            $plottype = 'plothead';
            break;
        }
        break;
      case 'lookuplevel':
        $plotting = array('userid' => 'userid', 'userlevel' => 'username');
        $plottype = 'plotledger';
        break;
      case 'useremplevel':
        $plotting = array('userid' => 'userid', 'userlevel' => 'username');
        $plottype = 'plothead';
        break;
      case 'lookupreqby':
        $plotting = array('userid' => 'userid', 'requestby' => 'username');
        $plottype = 'plothead';
        break;
      case 'dylookupusers':
        $plotting = array('assignedid' => 'userid', 'username' => 'name');
        $plottype = 'plotledger';
        break;  
      default:
        $plotting = array('userid' => 'userid', 'username' => 'username');
        $plottype = 'plothead';
        break;
    }

    $lookupsetup = array(
      'type' => 'single',
      'title' => $title,
      'style' => 'width:900px;max-width:900px;'
    );
    $plotsetup = array(
      'plottype' => $plottype,
      'action' => '',
      'plotting' => $plotting
    );
    // lookup columns
    switch ($companyid) {
      case 29:
      case 16:
        $cols = [
          ['name' => 'username', 'label' => 'Username', 'align' => 'left', 'field' => 'username', 'sortable' => true, 'style' => 'font-size:16px;'],
          ['name' => 'name', 'label' => 'Name', 'align' => 'left', 'field' => 'name', 'sortable' => true, 'style' => 'font-size:16px;']
        ];
        break;
      default:
        $cols = [
          ['name' => 'username', 'label' => 'Username', 'align' => 'left', 'field' => 'username', 'sortable' => true, 'style' => 'font-size:16px;']
        ];
        break;
    }


    switch ($config['params']['lookupclass']) {
      case 'getusername':
      case 'lookupusers':
      case 'user':
      case 'lookupreqby':
        $qry = "select '' as userid,'' as accessid, '' as username,'' as name,'' as project
                union all
                select userid, accessid, username, name,project
                from useraccess
                union all
                select clientid as userid, 0 as accessid, email as username, clientname as name, '' as project
                from client where isemployee=1 and email <> ''";
        break;
      case 'lookupcollector':

        $qry = "select distinct cc.userid, 0 as accessid, cc.email as username, '' as name, '' as project
             from client as c left join client as cc on cc.clientid = c.collectorid where c.collectorid<>0";

        break;
      case 'lookupusers2':
        $qry = "select '' as userid,'' as accessid, '' as username,'' as name,'' as project
                union all
                select userid, accessid, username, name,project
                from useraccess";
        break;

      case 'lookuplevel':
        $qry = "select 0 as userid, '' as username union all select idno as userid, username from users";
        break;
      case 'dylookupusers':
         $qry = "select '0' as userid,'0' as accessid, '' as username,'' as name,'' as project
            union all
            select clientid as userid, 0 as accessid, email as username, clientname as name, '' as project
            from client where isemployee=1 and email <> ''";
        break;  
      default:
        $qry = "select idno as userid, username from users";
        break;
    }

    $data = $this->coreFunctions->opentable($qry);
    return ['status' => true, 'msg' => 'ok', 'data' => $data, 'lookupsetup' => $lookupsetup, 'cols' => $cols, 'plotsetup' => $plotsetup];
  } //end function


