        $plotting = ['ewtcode' => 'ewtcode', 'ewtrate' => 'ewtrate'];
        $plottype = 'plotledger';
        break;
      case 'lookuppostedewt':
        $plotting = ['ewt' => 'ewtcode', 'ewtrate' => 'ewtrate', 'ewtid' => 'line', 'ewtcode' => 'ewtcode'];
        $plottype = 'plotledger';
        break;
      default:
        $plotting = ['ewtcode' => 'ewtcode', 'ewtrate' => 'ewtrate'];
        $plottype = 'plotgrid';
        break;
    }

    $title = 'List of EWT';

    $lookupsetup = [
      'type' => 'single',
      'title' => $title,
      'style' => 'width:100%;max-width:100%;'
    ];

    $plotsetup = [
      'plottype' => $plottype,
      'action' => '',
      'plotting' => $plotting
    ];

    $cols = [
      ['name' => 'ewtcode', 'label' => 'Code', 'align' => 'left', 'field' => 'ewtcode', 'sortable' => true, 'style' => 'font-size:16px;'],
      ['name' => 'ewtrate', 'label' => 'Rate', 'align' => 'left', 'field' => 'ewtrate', 'sortable' => true, 'style' => 'font-size:16px;'],
      ['name' => 'description', 'label' => 'Description', 'align' => 'left', 'field' => 'description', 'sortable' => true, 'style' => 'font-size:16px;']
    ];


    $qry = "select 0 as line,'' as ewtcode,0 as ewtrate,'' as description union all select line,code as ewtcode,rate as ewtrate,description from ewtlist";
    $data = $this->coreFunctions->opentable($qry);
    $btnadd = $this->sqlquery->checksecurity($config, 854, '/tableentries/tableentry/entryewt');

    switch ($config['params']['lookupclass']) {
      case 'ewt':
      case 'hewt':
      case 'lookuppostedewt':
      case 'excess':
        return ['status' => true, 'msg' => 'ok', 'data' => $data, 'lookupsetup' => $lookupsetup, 'cols' => $cols, 'plotsetup' => $plotsetup, 'btnadd' => $btnadd];
        break;

      default:
        $table = $config['params']['table'];
        $rowindex = $config['params']['index'];
        return ['status' => true, 'msg' => 'ok', 'data' => $data, 'lookupsetup' => $lookupsetup, 'cols' => $cols, 'plotsetup' => $plotsetup, 'table' => $table, 'rowindex' => $rowindex, 'btnadd' => $btnadd];
        break;
    }
  } //end function

