    } elseif ($config['params']['companyid'] == 47) { //kitchenstar
      $qry = "select 'R' as class,'Standard' as pricetype
          union all
          select 'W' as class,'Distributor' as pricetype";
    } else if ($config['params']['companyid'] == 59) { //roosevelt
      $qry = "select 'R' as class, 'DEALER' as pricetype, 'R~DEALER' as dpricegroup
        union all
        select 'W' as class, 'DEALER 2' as pricetype, 'W~DEALER 2' as dpricegroup
        union all
        select 'A' as class, 'INDUSTRIAL' as pricetype, 'A~INDUSTRIAL' as dpricegroup
        union all
        select 'B' as class, 'WALK-IN' as pricetype, 'B~WALK-IN' as dpricegroup
        union all
        select 'C' as class, '' as pricetype, 'C' as dpricegroup
        union all
        select 'D' as class, '' as pricetype, 'D' as dpricegroup
        union all
        select 'E' as class, '' as pricetype, 'E' as dpricegroup
        union all
        select 'F' as class, '' as pricetype, 'F' as dpricegroup
        union all
        select 'G' as class, '' as pricetype, 'G' as dpricegroup";
    } else {
      $qry = "select 'R' as class
          union all
          select 'W' as class
          union all
          select 'A' as class
          union all
          select 'B' as class
          union all
          select 'C' as class
          union all
          select 'D' as class
          union all
          select 'E' as class
          union all
          select 'F' as class
          union all
          select 'G' as class";
    }
    $data = $this->coreFunctions->opentable($qry);
    return ['status' => true, 'msg' => 'ok', 'data' => $data, 'lookupsetup' => $lookupsetup, 'cols' => $cols, 'plotsetup' => $plotsetup];
  } //end function

