      $title = 'List of Modules';
      $plotting = ['modulename' => 'doc', 'labelname' => 'modulename'];
      $index = $config['params']['index'];
    }

    if ($config['params']['lookupclass'] == 'barcodeassigning') {
      $plotting = array('moduledoc' => 'doc', 'moduledesc' => 'modulename');
      $plottype = 'plotledger';
    }

    $plotsetup = array(
      'plottype' => $plottype,
      'action' => '',
      'plotting' => $plotting
    );
    // lookup columns
    $cols = [
      ['name' => 'modulename', 'label' => 'Group', 'align' => 'left', 'field' => 'modulename', 'sortable' => true, 'style' => 'font-size:16px;']
    ];

    $sodoc = "SO";
    if ($config['params']['companyid'] == 10) { //afti
      $sodoc = "SQ";
    }

    $jodoc = "JO";
    if ($config['params']['companyid'] == 36) { //rozlab
      $jodoc = "JP";
    }
    $addunion = "";
    if ($config['params']['companyid'] == 39) { //cbbsi
      $addunion = " 
          union all
          select 'DR' as doc, 'DR' as pdoc, 'Delivery Receipt' as modulename
          union all
          select 'SK' as doc, 'SK' as pdoc, 'Sales Invoice' as modulename";
    }

    if ($config['params']['companyid'] == 58) { //cdo
      $addunion = "union all
        select 'OB' as doc, 'OB' as pdoc, 'OB Application' as modulename,'pendingobapplications' as sbcpendingapp
        union all
        select 'LEAVE' as doc, 'LEAVE' as pdoc, 'Leave Application' as modulename,'pendingleaveapplications' as sbcpendingapp
        union all
        select 'LOAN' as doc, 'LOAN' as pdoc, 'Loan Application' as modulename,'pendingloanapplications' as sbcpendingapp
        union all
        select 'OT' as doc, 'OT' as pdoc, 'OT Application' as modulename,'pendingotapplications' as sbcpendingapp
        union all
        select 'UNDERTIME' as doc, 'UNDERTIME' as pdoc, 'UNDERTIME Application' as modulename,'pendingutapplications' as sbcpendingapp";
    }

    if ($config['params']['lookupclass'] == 'barcodeassigning') {
      $qry = "
          select 'PR' as doc, 'Purchase Requisition' as modulename
          union all
          select 'CD' as doc, 'Canvass Sheet' as modulename
          union all
          select 'PO' as doc, 'Purchase Order' as modulename
          union all
          select 'RR' as doc, 'Receiving Report' as modulename
          union all
          select 'RR2' as doc, 'Temporary Barcode' as modulename
        ";
      // 2024.01.09 - FRED
      // for test link only, once test will update to live
      // union all
      // select 'RR2' as doc, 'Temporary Barcode' as modulename
    } else {
      $alloweddoc = $this->coreFunctions->opentable('select doc from left_menu');
      $filter = '';
      foreach ($alloweddoc as $key => $value) {
        switch ($value->doc) {
          case 'customer':
            $value->doc = 'CL';
            break;
          case 'supplier':
            $value->doc = 'SL';
            break;
          case 'warehouse':
            $value->doc = 'WH';
            break;
          case 'employee':
          case 'employeemasterfile':
            $value->doc = 'EM';
            break;
          case 'department':
            $value->doc = 'DE';
            break;
          case 'agent':
            $value->doc = 'AG';
            break;
          case 'stockcard':
            $value->doc = 'IT';
            break;
        }
        if ($filter == '') {
          $filter = "'" . $value->doc . "'";
        } else {
          $filter .= ",'" . $value->doc . "'";
        }
      }

      $strfilter = '';
      if ($filter != '') {
        $strfilter = " and psection in (" . $filter . ")";
      }

      $qry = "select doc,psection as pdoc, master as modulename from profile where doc='SED' " . $strfilter . " " . $addunion;
    }

    $data = $this->coreFunctions->opentable($qry);
    return ['status' => true, 'msg' => 'ok', 'data' => $data, 'lookupsetup' => $lookupsetup, 'cols' => $cols, 'plotsetup' => $plotsetup, 'index' => $index];
  } //end function

