  public function lookupmenulist($config)
  {
    //default
    $plotting = array('code' => 'code', 'modulename' => 'description');
    $plottype = 'plothead';
    $title = 'List of Modules';

    $lookupsetup = array(
      'type' => 'single',
      'title' => $title,
      'style' => 'width:900px;max-width:900px;'
    );
    $plotsetup = array(
      'plottype' => $plottype,
      'action' => '',
      'plotting' => $plotting
    );
    // lookup columns
    $cols = [
      ['name' => 'description', 'label' => 'Description', 'align' => 'left', 'field' => 'description', 'sortable' => true, 'style' => 'font-size:16px;']
    ];


    $qry = "select attribute,description,code
          from attributes
          where parent='\\\' and parentid=0 and allowed <> 1 order by code";
    $data = $this->coreFunctions->opentable($qry);
    return ['status' => true, 'msg' => 'ok', 'data' => $data, 'lookupsetup' => $lookupsetup, 'cols' => $cols, 'plotsetup' => $plotsetup];
  } //end function

  public function lookupaccesslist($config)
  {
    //default
    $plotting = array('accesscode' => 'code', 'accessname' => 'description');
    $plottype = 'plothead';
    $title = 'List of Access Lists';

    $lookupsetup = array(
      'type' => 'single',
      'title' => $title,
      'style' => 'width:900px;max-width:900px;'
    );
    $plotsetup = array(
      'plottype' => $plottype,
      'action' => '',
      'plotting' => $plotting
    );
    // lookup columns
    $cols = [
      ['name' => 'description', 'label' => 'Description', 'align' => 'left', 'field' => 'description', 'sortable' => true, 'style' => 'font-size:16px;']
    ];


    $qry = "select distinct child.description, child.code
          from attributes as parent
          left join attributes as child on parent.code = child.parent
          where parent.parent = '\\\'";
    $data = $this->coreFunctions->opentable($qry);
    return ['status' => true, 'msg' => 'ok', 'data' => $data, 'lookupsetup' => $lookupsetup, 'cols' => $cols, 'plotsetup' => $plotsetup];
  } //end function

