        ['name' => 'dollartocur', 'label' => 'Dollar To Cur', 'align' => 'left', 'field' => 'dollartocur', 'sortable' => true, 'style' => 'font-size:16px;']
      ];
    }

    $qry = "select 0 as line,'' as cur,0.00 as curtopeso,0.00 as dollartocur,'" . $config['params']['user'] . "' as editby,now() as editdate
            union all
