  public function lookupgender($config)
  {

    $style = 'width:900px;max-width:900px;';
    switch ($config['params']['lookupclass']) {
      case 'gpref':
        $plotting = array('gpref' => 'gender');
        break;
      case 'sex':
        $plotting = array('sex' => 'gender');
        break;

      default:
        if ($config['params']['doc'] == 'CA') { //ticket
          $plotting = array('gendercaller' => 'gender');
          $style = 'width:500px;max-width:500px;';
        } else {
          $plotting = array('gender' => 'gender');
          $style = 'width:900px;max-width:900px;';
        }
        break;
    }

    $plottype = 'plothead';
    $title = 'List of Gender';


    $lookupsetup = array(
      'type' => 'single',
      'title' => $title,
      'style' => $style
    );
    $plotsetup = array(
      'plottype' => $plottype,
      'action' => '',
      'plotting' => $plotting
    );
    // lookup columns
    $cols = [
      ['name' => 'gender', 'label' => 'Gender', 'align' => 'left', 'field' => 'gender', 'sortable' => true, 'style' => 'font-size:16px;'],
    ];

    $qry = "select 'Male' as gender union all select 'Female' union all select 'LGBT'";

    if ($config['params']['doc'] == 'CA' || $config['params']['doc'] == 'BG') { //ticket and brgy
      $qry = "select 'Male' as gender union all select 'Female' as gender ";
    }

    $data = $this->coreFunctions->opentable($qry);

    return ['status' => true, 'msg' => 'ok', 'data' => $data, 'lookupsetup' => $lookupsetup, 'cols' => $cols, 'plotsetup' => $plotsetup];
  } //end function

