      ['name' => 'clientname', 'label' => 'Students', 'align' => 'left', 'field' => 'clientname', 'sortable' => true, 'style' => 'font-size:16px;'],
    ];
    switch ($config['params']['doc']) {
      case 'EK':
        $trno = $config['params']['dataid'];
        $qry = "select periodid, syid, courseid, yr, adviserid, sectionid from en_srchead where trno=? union all select periodid, syid, courseid, yr, adviserid, sectionid from en_glhead where trno=?";
        $head = $this->coreFunctions->opentable($qry, [$trno, $trno]);
        if (!empty($head)) {
          $qry = "select distinct " . $trno . " as trno, qg.clientid, client.client, client.clientname from en_gequartergrade as qg left join client on client.clientid=qg.clientid left join en_glhead as head on head.trno=qg.trno where head.periodid=? and syid=? and courseid=? and yr=? and adviserid=? and sectionid=?";
          $data = $this->coreFunctions->opentable($qry, [$head[0]->periodid, $head[0]->syid, $head[0]->courseid, $head[0]->yr, $head[0]->adviserid, $head[0]->sectionid]);
        } else {
          $data = [];
        }
        break;
      default:
        $qry = "select student.clientid,client.client, client.clientname
              from en_studentinfo as student
              left join client on student.clientid = client.clientid
              order by client.client";
        $data = $this->coreFunctions->opentable($qry);
        break;
    }

    return ['status' => true, 'msg' => 'ok', 'data' => $data, 'lookupsetup' => $lookupsetup, 'cols' => $cols, 'plotsetup' => $plotsetup];
  } //end function

