  public function lookupcivilstatus($config)
  {
    switch ($config['params']['lookupclass']) {
      case 'lookupmstatus':
        $plotting = array('status' => 'civilstatus');
        break;
      case 'lookuplestatus':
        $plotting = array(
          'civilstat' => 'civilstatus',
          'empfirst' => 'empfirst',
          'pstreet' => 'pstreet',
          'emplast' => 'emplast',
          'rcity' => 'rcity',
          'paddressno' => 'paddressno',
          'dp' => 'dp',
          'psubdistown' => 'psubdistown',
          'othersource' => 'othersource'
        );
        break;
      case 'lookuples':
        $plotting = array(
          'civilstatus' => 'civilstatus',
          'sname' => 'sname',
          'companyaddress' => 'companyaddress',
          'ename' => 'mmoq',
          'city' => 'city',
          'pcity' => 'pcity',
          'pcountry' => 'pcountry',
          'pprovince' => 'pprovince',
          'monthly' => 'leasecontract'
        );
        break;

      case 'lookupbcivilstat':
        $plotting = array(
          'civilstatus' => 'civilstatus',
          'sname' => 'sname',
          'attainment2' => 'attainment2',
          'bday2' => 'bday2',
          'occupation2' => 'occupation2',
          'skill2' => 'skill2'
        );
        break;
      default:
        $plotting = array('civilstatus' => 'civilstatus');
        break;
    }

    $plottype = 'plothead';
    $title = 'List of Civil Status';

    $lookupsetup = array(
      'type' => 'single',
      'title' => $title,
      'style' => 'width:900px;max-width:900px;'
    );
    $plotsetup = array(
      'plottype' => $plottype,
      'action' => '',
      'plotting' => $plotting
    );
    // lookup columns
    $cols = [
      ['name' => 'civilstatus', 'label' => 'Description', 'align' => 'left', 'field' => 'civilstatus', 'sortable' => true, 'style' => 'font-size:16px;'],
    ];

    $systemtype = $this->companysetup->getsystemtype($config['params']);
    if ($config['params']['companyid'] == 55) { //afli
      switch ($config['params']['lookupclass']) {
        case 'lookuples':
          $name = $config['params']['addedparams'][0];
          $birth = $config['params']['addedparams'][1];
          $mmoq = $config['params']['addedparams'][2];
          $city = $config['params']['addedparams'][3];
          $pcity = $config['params']['addedparams'][4];
          $pcountry = $config['params']['addedparams'][5];
          $province = $config['params']['addedparams'][6];
          $leasecontract = $config['params']['addedparams'][7];

          $qry = "select 'Single' as civilstatus, 'N/A' as sname, 'N/A' as companyaddress, 
                                              'N/A' as mmoq,'N/A' as  city,'N/A' as pcity, 'N/A' as pcountry,
                                              'N/A' as pprovince, '0.00' as leasecontract
              union all
              select 'Married' , '$name' as sname, '$birth' as companyaddress,
                                              '$mmoq' as mmoq, '$city' as  city,'$pcity' as pcity, '$pcountry' as pcountry,
                                              '$province' as pprovince, '$leasecontract' as leasecontract

              union all 
              select 'Divorced', '$name' as sname,'$birth' as companyaddress,
                                              '$mmoq' as mmoq, '$city' as  city,'$pcity' as pcity, '$pcountry' as pcountry,
                                              '$province' as pprovince, '$leasecontract' as leasecontract
              union all 
              select 'Widowed','$name' as sname,'$birth' as companyaddress,
                                              '$mmoq' as mmoq, '$city' as  city,'$pcity' as pcity, '$pcountry' as pcountry,
                                              '$province' as pprovince, '$leasecontract' as leasecontract";

          break;
        case 'lookuplestatus':
          $empfirst = $config['params']['addedparams'][0];
          $pstreet = $config['params']['addedparams'][1];
          $emplast = $config['params']['addedparams'][2];
          $rcity = $config['params']['addedparams'][3];
          $paddressno = $config['params']['addedparams'][4];
          $dp = $config['params']['addedparams'][5];
          $psubdistown = $config['params']['addedparams'][6];
          $othersource = $config['params']['addedparams'][7];

          $qry = "select 'Single' as civilstatus, 'N/A' as empfirst, 'N/A' as pstreet, 
                                              'N/A' as emplast,'N/A' as  rcity,'N/A' as paddressno, '0.00' as dp,
                                              'N/A' as psubdistown, 'N/A' as othersource
              union all
              select 'Married' , '$empfirst' as empfirst, '$pstreet' as pstreet,
                                              '$emplast' as emplast, '$rcity' as  rcity,'$paddressno' as paddressno, '$dp' as dp,
                                              '$psubdistown' as psubdistown, '$othersource' as othersource

              union all 
              select 'Divorced', '$empfirst' as empfirst,'$pstreet' as pstreet,
                                              '$emplast' as emplast, '$rcity' as  rcity,'$paddressno' as paddressno, '$dp' as dp,
                                              '$psubdistown' as psubdistown, '$othersource' as othersource
              union all 
              select 'Widowed','$empfirst' as empfirst,'$pstreet' as pstreet,
                                              '$emplast' as emplast, '$rcity' as  rcity,'$paddressno' as paddressno, '$dp' as dp,
                                              '$psubdistown' as psubdistown, '$othersource' as othersource";


          break;
      }
    } else {

      if ($config['params']['lookupclass'] == 'lookupbcivilstat') {
        $sname = $config['params']['addedparams'][0];
        $attainment2 = $config['params']['addedparams'][1];
        $bday2 = $config['params']['addedparams'][2];
        $occupation2 = $config['params']['addedparams'][3];
        $skill2 = $config['params']['addedparams'][4];

        $bdays = $this->othersClass->getCurrentDate();

        $qry = " select 'Single' as civilstatus, 'N/A' as sname, 'N/A' as attainment2, 
                        '$bdays' as bday2,'N/A' as  occupation2,'N/A' as skill2
                union all
                 select 'Married' , '$sname' as sname, '$attainment2' as attainment2,
                        '$bday2' as bday2, '$occupation2' as  occupation2,'$skill2' as skill2
        
                union all
                select 'Widowed' , '$sname' as sname, '$attainment2' as attainment2,
                        '$bday2' as bday2, '$occupation2' as  occupation2,'$skill2' as skill2

                union all
                select 'Separated' , '$sname' as sname, '$attainment2' as attainment2,
                        '$bday2' as bday2, '$occupation2' as  occupation2,'$skill2' as skill2

                union all
                select 'Divorced' , '$sname' as sname, '$attainment2' as attainment2,
                        '$bday2' as bday2, '$occupation2' as  occupation2,'$skill2' as skill2";
      } else {
        $qry = "select 'Single' as civilstatus union all select 'Married'  
              union all select 'Divorced' union all select 'Widowed' union all select 'Living in Common Law'";
      }
    }

    $data = $this->coreFunctions->opentable($qry);

    return ['status' => true, 'msg' => 'ok', 'data' => $data, 'lookupsetup' => $lookupsetup, 'cols' => $cols, 'plotsetup' => $plotsetup];
  } //end function

