  public function lookupledgerempndahistory($config)
  {
    $lookupsetup = array(
      'type' => 'singlesearch',
      'actionsearch' => '',
      'title' => 'Employee List',
      'style' => 'width:900px;max-width:900px;'
    );

    $plotsetup = array(
      'plottype' => 'callback',
      'action' => 'loadledgerdata'
    );
    // lookup columns
    $cols = [
      ['name' => 'empcode', 'label' => 'Code', 'align' => 'left', 'field' => 'empcode', 'sortable' => true, 'style' => 'font-size:16px;'],
      ['name' => 'empname', 'label' => 'Description', 'align' => 'left', 'field' => 'empname', 'sortable' => true, 'style' => 'font-size:16px;'],
    ];

    $emplvl = $this->othersClass->checksecuritylevel($config);

    $qry = "select e.empid as clientid, client.client as empcode,
            concat(e.empfirst,' ',e.empmiddle, ' ', e.emplast) as empname,
            jt.docno as jobcode, jt.jobtitle,c.client as deptcode, c.clientname as deptname,
            jt.line as jobid,
            date(e.hired) as hireddate
          from employee as e
          left join client on client.clientid=e.empid
          left join app as a on e.aplid=a.empid
          left join client as c on c.clientid=e.deptid
          left join jobthead as jt on a.jobcode=jt.docno
          where e.level IN $emplvl";
    $data = $this->coreFunctions->opentable($qry);

    return ['status' => true, 'msg' => 'ok', 'data' => $data, 'lookupsetup' => $lookupsetup, 'cols' => $cols, 'plotsetup' => $plotsetup];
  } //end function


