    $plotsetup = array(
      'plottype' => 'callback',
      'action' => 'loadledgerdata'
    );

    // lookup columns
    $cols = [
      ['name' => 'client', 'label' => 'Code', 'align' => 'left', 'field' => 'client', 'sortable' => true, 'style' => 'font-size:16px;'],
      ['name' => 'clientname', 'label' => 'Name', 'align' => 'left', 'field' => 'clientname', 'sortable' => true, 'style' => 'font-size:16px;'],
      ['name' => 'acnoname', 'label' => 'Leave Type', 'align' => 'left', 'field' => 'acnoname', 'sortable' => true, 'style' => 'font-size:16px;'],
    ];

    $emplvl = $this->othersClass->checksecuritylevel($config, true);

    $qry = "
      select s.trno, e.empid, s.trno as clientid,
      client.client,
      client.client as empcode, date(now()) as dateid,
      CONCAT(e.emplast,', ',e.empfirst,' ',e.empmiddle) AS clientname,
      s.empid, CONCAT(e.emplast,', ',e.empfirst,' ',e.empmiddle) AS empname,
      p.codename as acnoname, s.acnoid,
      p.`code` as acno, s.days, s.bal,
      s.docno, s.prdstart, s.prdend, '' as
      remarks, null as effectivity, '' as `status`, '' as hours
      from leavesetup as s
      left join employee as e on e.empid=s.empid
      left join paccount as p on p.line=s.acnoid
      left join client on client.clientid=e.empid
      where e.level in " . $emplvl . "
    ";
    $data = $this->coreFunctions->opentable($qry);

    return ['status' => true, 'msg' => 'ok', 'data' => $data, 'lookupsetup' => $lookupsetup, 'cols' => $cols, 'plotsetup' => $plotsetup];
