  public function lookupyear($config)
  {
    $lookupsetup = array(
      'type' => 'single',
      'title' => 'Year',
      'style' => 'width:900px;max-width:900px;'
    );

    $plottype = 'plothead';
    $plotting = array(
      'year' => 'year'
    );

    $plotsetup = array(
      'plottype' => $plottype,
      'plotting' => $plotting
    );


    // lookup columns
    $cols = array();
    $col = array('name' => 'year', 'label' => 'Year', 'align' => 'left', 'field' => 'year', 'sortable' => true, 'style' => 'font-size:16px;');
    array_push($cols, $col);
    $starting_year  = date('Y') - 1;
    $ending_year = date('Y', strtotime('+10 year'));
    $i = 0;
    $data = [];

    for ($starting_year; $starting_year <= $ending_year; $starting_year++) {
      $data[$i]['year'] = $starting_year;
      $i++;
    }

    return ['status' => true, 'msg' => 'ok', 'data' => $data, 'lookupsetup' => $lookupsetup, 'cols' => $cols, 'plotsetup' => $plotsetup];
  }


