  public function lookupearningdeduction($config)
  {
    $plottype = 'plothead';
    $title = 'List of Earning and Deduction';

    $lookupsetup = array(
      'type' => 'singlesearch',
      'actionsearch' => 'searchdocno',
      'title' => $title,
      'style' => 'width:900px;max-width:900px;'
    );

    $plotsetup = array(
      'plottype' => 'callback',
      'action' => 'loadledgerdata'
    );

    // lookup columns
    $cols = [
      ['name' => 'client', 'label' => 'Code', 'align' => 'left', 'field' => 'client', 'sortable' => true, 'style' => 'font-size:16px;'],
      ['name' => 'clientname', 'label' => 'Employee Name', 'align' => 'left', 'field' => 'clientname', 'sortable' => true, 'style' => 'font-size:16px;'],
      ['name' => 'acnoname', 'label' => 'Account Name', 'align' => 'left', 'field' => 'acnoname', 'sortable' => true, 'style' => 'font-size:16px;']
    ];

    if ($config['params']['doc'] == "LOANAPPLICATIONPORTAL") {
      $empid = $config['params']['adminid'];
      $qry = "
        select s.trno as clientid, s.docno as client, s.docno,
        s.dateid, s.empid, s.remarks, pac.code as acno, s.amt, s.paymode,
        w1,w2,w3,w4,w5,w13,halt,s.priority, s.earnded, s.amortization, s.effdate,s.payment,
        concat(e.emplast,', ',e.empfirst,' ',e.empmiddle) as empname,
        concat(e.emplast,', ',e.empfirst,' ',e.empmiddle) as clientname,
        pac.codename as acnoname, client.client as empcode,
        balance, s.acnoid
        from loanapplication as s
          left join employee as e on s.empid = e.empid
          left join client on client.clientid = e.empid
          left join paccount as pac on pac.line = s.acnoid
        where s.empid = $empid";
    } else {
      array_push($cols, ['name' => 'remarks', 'label' => 'Remarks', 'align' => 'left', 'field' => 'remarks', 'style' => 'font-size:16px;']);
      $qry = "
        select s.trno as clientid, s.docno as client, s.docno,
        s.dateid, s.empid, s.remarks, pac.code as acno, s.amt, s.paymode,
        w1,w2,w3,w4,w5,w13,halt,s.priority, s.earnded, s.amortization, s.effdate,s.payment,
        concat(e.emplast,', ',e.empfirst,' ',e.empmiddle) as empname,
        concat(e.emplast,', ',e.empfirst,' ',e.empmiddle) as clientname,
        pac.codename as acnoname, client.client as empcode,
        balance, s.acnoid
        from standardsetup as s
          left join employee as e on s.empid = e.empid
          left join client on client.clientid = e.empid
          left join paccount as pac on pac.line = s.acnoid";
    }

    $data = $this->coreFunctions->opentable($qry);

    return ['status' => true, 'msg' => 'ok', 'data' => $data, 'lookupsetup' => $lookupsetup, 'cols' => $cols, 'plotsetup' => $plotsetup];
  } //end function

