  public function lookupwshipping($config)
  {
    $companyid = $config['params']['companyid'];
    $doc = $config['params']['doc'];
    $lookupsetup = array(
      'type' => 'single',
      'title' => 'Shipping Address',
      'style' => 'width:100%;max-width:70%;'
    );



    if ($companyid == 19 && $doc == 'SO') { //housegem
      $plotsetup = array(
        'plottype' => 'plothead',
        'plotting' => array(
          // 'subproject' => 'line',
          'shipto' => 'addr'
        )
      );
    } else {
      $plotsetup = array(
        'plottype' => 'plotledger',
        'plotting' => array(
          'shipid' => 'line',
          'shipping' => 'shipping',
          'contact' => 'contact',
          'mobileno' => 'contactno',
          'tasktitle' => 'addrtype',
          'leadfrom' => 'addrline1',
          'industry' => 'addrline2',
          'partno' => 'city',
          'year' => 'province',
          'payor' => 'country',
          'prepared' => 'fax'
        )
      );
    }
    // lookup columns
    if ($companyid == 19) { //housegem
      $cols = array(
        array('name' => 'addr', 'label' => 'Address Title', 'align' => 'left', 'field' => 'addr', 'sortable' => true, 'style' => 'font-size:16px;')
      );
    } else {
      $cols = array(
        array('name' => 'addr', 'label' => 'Address Title', 'align' => 'left', 'field' => 'addr', 'sortable' => true, 'style' => 'font-size:16px;'),
        array('name' => 'shipping', 'label' => 'Address', 'align' => 'left', 'field' => 'shipping', 'sortable' => true, 'style' => 'font-size:16px;')
      );
    }

    // ito iconcat// sir ung sige
    $qry = "select line, addr, addr as addr2, contact,contactno,
      addrtype, addrline1, addrline2, city, province, country, fax,
      ifnull(concat(s.addrline1,' ',s.addrline2,' ',s.city,' ',s.province,' ',s.country,' ',s.zipcode),'') as shipping
      from billingaddr as s 
      where s.isinactive <> 1  and s.clientid=?";

    $systemtype = $this->companysetup->getsystemtype($config['params']);
    switch (strtoupper($systemtype)) {
      case 'VSCHED':
      case 'ATI':
        $qry = "select line, addr, addr as addr2, contact,contactno,
      addrtype, addrline1, addrline2, city, province, country, fax,
      ifnull(s.addr,'') as shipping
      from billingaddr as s 
      where s.isinactive <> 1 and s.isshipping = 1 and s.clientid = ?";
        break;
    }

    if (isset($config['params']['trno'])) {
      $clientid = $this->othersClass->getclientid($config);
    } else {
      $clientid = $config['params']['clientid'];
    }

    $data = $this->coreFunctions->opentable($qry, [$clientid]);
    $fields = ['line', 'addr', 'addr2'];

