  public function lookuppolatesttrans($config)
  {
    $itemid = $config['params']['itemid'];
    $client = $this->coreFunctions->getfieldvalue('pohead', 'client', 'trno=?', [$config['params']['trno']]);
    $clientid = $this->coreFunctions->getfieldvalue('client', 'clientid', 'client=?', [$client]);
    $lookupsetup = array(
      'type' => 'single',
      'title' => 'Last 10 Transactions',
      'style' => 'width:100%;max-width:90%;'
    );

    $plotsetup = array(
      'plottype' => 'plothead',
      'plotting' => array()
    );

    $cols = array(
      array('name' => 'docno', 'label' => 'Docno #', 'align' => 'left', 'field' => 'docno', 'sortable' => true, 'style' => 'font-size:16px;'),
      array('name' => 'transtype', 'label' => 'Trans. Type', 'align' => 'left', 'field' => 'transtype', 'sortable' => true, 'style' => 'font-size:16px;'),
      array('name' => 'dateid', 'label' => 'Date', 'align' => 'left', 'field' => 'dateid', 'sortable' => true, 'style' => 'font-size:16px;'),
      array('name' => 'clientname', 'label' => 'Supplier', 'align' => 'left', 'field' => 'clientname', 'sortable' => true, 'style' => 'font-size:16px;'),
      array('name' => 'rrqty', 'label' => 'Qty', 'align' => 'right', 'field' => 'rrqty', 'sortable' => true, 'style' => 'font-size:16px;'),
      array('name' => 'rrcost', 'label' => 'Amount', 'align' => 'right', 'field' => 'rrcost', 'sortable' => true, 'style' => 'font-size:16px;'),
      array('name' => 'disc', 'label' => 'Discount', 'align' => 'left', 'field' => 'disc', 'sortable' => true, 'style' => 'font-size:16px;'),
      array('name' => 'ext', 'label' => 'Total Amount', 'align' => 'right', 'field' => 'ext', 'sortable' => true, 'style' => 'font-size:16px;')
    );

    $qry = "
      select h.docno, date(h.dateid) as dateid, h.clientname, 'Receiving Report' as transtype,
      round(s.rrqty," . $this->companysetup->getdecimal('qty', $config['params']) . ") as rrqty, 
      round(s.rrcost," . $this->companysetup->getdecimal('price', $config['params']) . ") as rrcost, s.disc, 
      round(s.ext," . $this->companysetup->getdecimal('price', $config['params']) . ") as ext
      from lahead as h left join lastock as s on s.trno=h.trno where h.doc='RR' and h.client=? and s.itemid=?
      union all
      select h.docno, date(h.dateid) as dateid, h.clientname, 'Receiving Report' as transtype,
      round(s.rrqty," . $this->companysetup->getdecimal('qty', $config['params']) . ") as rrqty, 
      round(s.rrcost," . $this->companysetup->getdecimal('price', $config['params']) . ") as rrcost, s.disc, 
      round(s.ext," . $this->companysetup->getdecimal('price', $config['params']) . ") as ext
      from glhead as h left join glstock as s on s.trno=h.trno where h.doc='RR' and h.clientid=? and s.itemid=?
      union all
      select h.docno, date(h.dateid) as dateid, client.clientname, 'Packing List RR' as transtype,
      round(s.rrqty," . $this->companysetup->getdecimal('qty', $config['params']) . ") as rrqty, 
      round(s.rrcost," . $this->companysetup->getdecimal('price', $config['params']) . ") as rrcost, s.disc, 
      round(s.ext," . $this->companysetup->getdecimal('price', $config['params']) . ") as ext
      from lahead as h left join lastock as s on s.trno=h.trno left join client on client.clientid=s.suppid 
      where h.doc='RP' and s.suppid=? and s.itemid=?
      union all
      select h.docno, date(h.dateid) as dateid, client.clientname, 'Packing List RR' as transtype,
      round(s.rrqty," . $this->companysetup->getdecimal('qty', $config['params']) . ") as rrqty, 
      round(s.rrcost," . $this->companysetup->getdecimal('price', $config['params']) . ") as rrcost, s.disc, 
      round(s.ext," . $this->companysetup->getdecimal('price', $config['params']) . ") as ext
      from glhead as h left join glstock as s on s.trno=h.trno left join client on client.clientid=s.suppid 
      where h.doc='RP' and s.suppid=? and s.itemid=?
      order by dateid desc limit 10
      ";

    $data = $this->coreFunctions->opentable($qry, [$client, $itemid, $clientid, $itemid, $clientid, $itemid, $clientid, $itemid]);

    return ['status' => true, 'msg' => 'ok', 'data' => $data, 'lookupsetup' => $lookupsetup, 'cols' => $cols, 'plotsetup' => $plotsetup];
  }

  public function lookupobtype($config)
  {
