      array('name' => 'type', 'label' => 'Type', 'align' => 'left', 'field' => 'type', 'sortable' => true, 'style' => 'font-size:16px;')
    );

    switch ($companyid) {
      case 51: // ulitc
        $qry = "select 'Time-In' as type union all select 'Time-Out' as type union all select 'ECOM-In' union all select 'ECOM-Out' union all select 'Official Business' ";
        break;
