  public function lookup_ratecategory($config)
  {
    $lookupsetup = array(
      'type' => 'single',
      'title' => 'Rate Category List',
      'style' => 'width:400px;max-width:400px;'
    );

    $plotsetup = array(
      'plottype' => 'plothead',
      'plotting' => array('categoryid' => 'categoryid', 'ratecategory' => 'category')
    );

    switch ($config['params']['lookupclass']) {
      case 'lookup_water_ratecategory':
        $modtype = $config['params']['moduletype'];
        $plottype = 'plothead';
        if ($modtype == 'MASTERFILE') {
          $plottype = 'plotledger';
        }

        $plotsetup = array(
          'plottype' => $plottype,
          'plotting' => array('wratecat' => 'categoryid', 'wratecatname' => 'category')
        );
        break;
      case 'lookup_elect_ratecategory':
        $modtype = $config['params']['moduletype'];
        $plottype = 'plothead';
        if ($modtype == 'MASTERFILE') {
          $plottype = 'plotledger';
        }

        $plotsetup = array(
          'plottype' => $plottype,
          'plotting' => array('eratecat' => 'categoryid', 'eratecatname' => 'category')
        );
        break;
    }

    // lookup columns
    $cols = array(
      array('name' => 'category', 'label' => 'Category', 'align' => 'left', 'field' => 'category', 'sortable' => true, 'style' => 'font-size:16px;')
    );

    $addedfilter = "";

    switch ($config['params']['lookupclass']) {
      case 'lookup_ratecategory_water':
      case 'lookup_water_ratecategory':
        $addedfilter .= " and iswater = 1";
        break;
      case 'lookup_ratecategory_electricity':
      case 'lookup_ratecategory_storage_electricity':
      case 'lookup_elect_ratecategory':
        $addedfilter .= " and iselec = 1";
        break;
    }

    $qry = "
      select cat.line as categoryid, cat.category, cat.iselec, cat.iswater
      from ratecategory as cat
      where 1 =1 " . $addedfilter . "";

    $data = $this->coreFunctions->opentable($qry);

    return ['status' => true, 'msg' => 'ok', 'data' => $data, 'lookupsetup' => $lookupsetup, 'cols' => $cols, 'plotsetup' => $plotsetup];
  }

