  public function lookupsourcename($config)
  {
    $params = strtolower($config['params']['addedparams'][0]);

    $lookupsetup = array(
      'type' => 'single',
      'title' => 'List of  ' . ucwords($params) . ' ',
      'style' => 'width:400px;max-width:400px;'
    );

    $plotsetup = array(
      'plottype' => 'plothead',
      'plotting' => array('sourceid' => 'sourceid', 'sourcename' => 'sourcename')
    );

    // lookup columns
    $cols = array(
      array('name' => 'sourcename', 'label' => ucwords($params), 'align' => 'left', 'field' => 'sourcename', 'sortable' => true, 'style' => 'font-size:16px;')
    );

    switch ($params) {
      case 'principal leads':
        $qry = "select line as sourceid, name as sourcename from projectmasterfile";
        break;

      case 'exhibit':
      case 'seminar':
        $qry = "select line as sourceid, title as sourcename from " . $params . " ";
        break;
      case 'others':
        $qry = "select line as sourceid, description as sourcename from source ";
        break;
      case 'call - inbound':
        $qry = "select 0 as sourceid, 'New' as sourcename union all select 0 as sourceid, 'Old' as sourcename ";
        break;
      case 'call - outbound':
        $qry = "select 0 as sourceid, 'Follow-up' as sourcename union all select 0 as sourceid, 'Prospecting' as sourcename union all select 0 as sourceid, 'Others' as sourcename ";
        break;

      default:
        return ['status' => false, 'msg' => 'Source  ' . $params . ' is not yet in Lookupsetup '];
        break;
    }

    $data = $this->coreFunctions->opentable($qry);
    return ['status' => true, 'msg' => 'ok', 'data' => $data, 'lookupsetup' => $lookupsetup, 'cols' => $cols, 'plotsetup' => $plotsetup];
  }

  public function lookupparticipant($config)
  {
    $source = strtolower($config['params']['addedparams'][0]);
    $sourceid = strtolower($config['params']['addedparams'][1]);

    $lookupsetup = array(
      'type' => 'single',
      'title' => 'List of  ' . ucwords($source) . ' Attendee',
      'style' => 'width:1000px;max-width:1000px;'
    );

    $plotsetup = array(
      'plottype' => 'plothead',
      'plotting' => array(
        'participantid' => 'participantid',
        'participant' => 'companyname',
        'clientid' => 'clientid',
        'client' => 'client',
        'clientname' => 'companyname',
        'contactname' => 'contactname',
        'tel' => 'contactno',
        'ourref' => 'department',
        'designation' => 'designation',
        'email' => 'email',
        'rem' => 'mrktremarks'

      )
    );

    // lookup columns
    $cols = array(
      array('name' => 'companyname', 'label' => 'Company Name', 'align' => 'left', 'field' => 'companyname', 'sortable' => true, 'style' => 'font-size:16px;'),
      array('name' => 'contactname', 'label' => 'Contact Name', 'align' => 'left', 'field' => 'contactname', 'sortable' => true, 'style' => 'font-size:16px;'),
      array('name' => 'contactno', 'label' => 'Contact #', 'align' => 'left', 'field' => 'contactno', 'sortable' => true, 'style' => 'font-size:16px;'),
      array('name' => 'department', 'label' => 'Department', 'align' => 'left', 'field' => 'department', 'sortable' => true, 'style' => 'font-size:16px;'),
      array('name' => 'designation', 'label' => 'Designation', 'align' => 'left', 'field' => 'designation', 'sortable' => true, 'style' => 'font-size:16px;'),
      array('name' => 'email', 'label' => 'Email', 'align' => 'left', 'field' => 'email', 'sortable' => true, 'style' => 'font-size:16px;'),
    );


    $filter = "";

    switch ($source) {
      case 'exhibit':
        $filter .= " and isexhibit = 1";
        break;
      case 'seminar':
        $filter .= " and isseminar = 1";
        break;
      case 'others':
        $filter .= " and issource = 1";
        break;
      default:
        return ['status' => false, 'msg' => 'Source  ' . $source . ' is not yet in Lookupsetup '];
        break;
    }

    $qry = "select 
          att.line as participantid, att.exhibitid, att.clientid, 
          att.contactno, att.department, att.designation, att.email,
          cl.client, cl.clientname,
          att.contactid,
          case
            when att.contactid != 0 then concat(cp.lname,', ',cp.fname,' ',cp.mname)
            else att.contactname
          end as contactname,
          case 
            when att.clientid = 0 then att.companyname
            else cl.clientname
          end as companyname,att.mrktremarks
        from attendee as att
        left join client as cl on cl.clientid = att.clientid
        left join contactperson as cp on cp.line = att.contactid
        where att.exhibitid = '" . $sourceid . "' and att.optrno = 0
        " . $filter . "";

    $data = $this->coreFunctions->opentable($qry);
    return ['status' => true, 'msg' => 'ok', 'data' => $data, 'lookupsetup' => $lookupsetup, 'cols' => $cols, 'plotsetup' => $plotsetup];
  }

