  public function lookupcustomercontact($config)
  {
    $class = $config['params']['lookupclass'];
    $lbl = ucwords($class);

    switch ($class) {
      case 'shipping': // shipping
        $line = 'shipcontactid';
        $name = 'shipcontactname';
        $cno = 'shipcontactno';
        $mob = 'shipmobile';
        $email = 'shipemail';
        break;

      default: // billing default
        $line = 'billcontactid';
        $name = 'billcontactname';
        $cno = 'billcontactno';
        $mob = 'billmobile';
        $email = 'billemail';
        break;
    }

    $lookupsetup = array(
      'type' => 'single',
      'title' => '' . $lbl . ' Contact List',
      'style' => 'width:100%;max-width:70%;'
    );

    $plotsetup = array(
      'plottype' => 'plotledger',
      'plotting' => array($line => 'line', $name => 'name', $cno => 'contactno', $mob => 'mobile', $email => 'email')
    );

    // lookup columns
    $cols = array(
      array('name' => 'name', 'label' => '' . $lbl . ' Contact Name', 'align' => 'left', 'field' => 'name', 'sortable' => true, 'style' => 'font-size:16px;'),
      array('name' => 'contactno', 'label' => '' . $lbl . ' Contact #', 'align' => 'left', 'field' => 'contactno', 'sortable' => true, 'style' => 'font-size:16px;'),
      array('name' => 'mobile', 'label' => '' . $lbl . ' Mobile #', 'align' => 'left', 'field' => 'mobile', 'sortable' => true, 'style' => 'font-size:16px;'),
      array('name' => 'email', 'label' => 'Email Address', 'align' => 'left', 'field' => 'email', 'sortable' => true, 'style' => 'font-size:16px;')
    );

    $qry = "select c.line, concat(c.lname,', ',c.fname,' ',c.mname) as name, contactno, email ,mobile
    from contactperson as c where c.clientid=?";

    if (isset($config['params']['trno'])) {
      $clientid = $this->othersClass->getclientid($config);
    } else {
      $clientid = $config['params']['clientid'];
    }

    $data = $this->coreFunctions->opentable($qry, [$clientid]);
    $btnadd = $this->sqlquery->checksecurity($config, 24, '/ledger/masterfile/customer');
    return ['status' => true, 'msg' => 'ok', 'data' => $data, 'lookupsetup' => $lookupsetup, 'cols' => $cols, 'plotsetup' => $plotsetup, 'btnadd' => $btnadd];
  }

