        select 'Online' as field1
        union all
        select 'Credit Card' as field1
        ";
        break;
      case 'paymentmode':
        $plotting = array('ourref' => 'field1');
        $plottype = 'plothead';
        $title = 'List of Mode of Payments';
        $label = 'Mode of Payment';

        $qry = "select 'Cash' as field1 
        union all 
        select 'Cheque' as field1
        union all
        select 'Deposit' as field1
        union all
        select 'Online' as field1
        union all
        select 'Credit Card' as field1";
        break;
      case 'lookupyesno':
        $plotting = array('isshipmentnotif' => 'field1');
        $plottype = 'plotledger';
        $title = '';
        $label = '';
        $qry = "
          select 'Yes' as field1
          union all 
          select 'No' as field1
        ";
        break;
      case 'lookuprvoter':
        $plotting = array('rvoter' => 'field1');
        $plottype = 'plothead';
        $title = '';
        $label = '';
        $qry = "
          select 'Yes' as field1
          union all 
          select 'No' as field1
        ";
        break;
      case 'lookuptstatus':
        $plotting = array('status' => 'field1');
        $plottype = 'plotledger';
        $title = 'List of Status';
        $label = 'Type';

        $qry = " 
        select 'Renewable' as field1
        union all 
        select 'Non-Renewable' as field1
        union all 
        select 'Extended' as field1";
        break;
      case 'lookup_staylength1': //borrower
      case 'lookup_staylength2': //comaker
      case 'lookup_staylength3': //borrowers spouse
      case 'lookup_staylength4': //comaker spouse
        switch ($config['params']['lookupclass']) {
          case 'lookup_staylength1':
            $plotting = array('brgy' => 'field1');
            break;
          case 'lookup_staylength2':
            $plotting = array('psubdistown' => 'field1');
            break;
          case 'lookup_staylength3':
            $plotting = array('pcountry' => 'field1');
            break;
          case 'lookup_staylength4':
            $plotting = array('rbrgy' => 'field1');
            break;
        }

        $plottype = 'plothead';
        $title = 'Length of Stay';
        $label = 'Type';
        $qry = "
        select 'Less than 1 year' as field1
        union all
        select '1 - 3 years' as field1
        union all
        select '3 - 5 years' as field1
        union all
        select '5 - 10 years' as field1
        union all
        select '10 - 20 years' as field1
        union all
        select '20 - 30 years' as field1
        union all
        select '30+ years' as field1";
        break;
      case 'modeofpayment':
        $plotting = array('modeofpayment' => 'field1', 'line' => 'line', 'modeofsales' => 'field1');
        $plottype = 'plothead';
        $title = 'List of Mode of Payments';
        $label = 'Mode of Payment';
        switch ($doc) {
          case 'MJ':
            $title = 'List of Mode of Sales';
            $label = 'Mode of Sales';
            $qry = "select m.name as field1,m.line,ifnull(m.clientid,0) as clientid,ifnull(c.client,'') as client,ifnull(c.clientname,'') as clientname from mode_masterfile as m left join client as c on c.clientid = m.clientid where m.ismc = 1 and m.isactive = 0";
            $plotting = array('modeofpayment' => 'field1', 'line' => 'line', 'modeofsales' => 'field1', 'fp' => 'client', 'fpid' => 'clientid', 'fpname' => 'clientname');
            break;
          case 'MC':
            $qry = "
            select 'Cash' as field1 
            union all
            select 'Check' as field1
            union all
            select 'Bank Transfer' as field1 
            union all
            select 'Palawan' as field1
            union all
            select 'Debit Card' as field1 
            union all
            select 'Credit Card' as field1 ";
            break;
          default:
            $qry = "select 'Cash' as field1 
                union all
                select 'Debit Card' as field1 
                union all
                select 'Credit Card' as field1 
                union all
                select 'Gcash' as field1 
                union all
                select 'Credit' as field1";
            break;
        }
        break;
      case 'lookupindustry':
        $plotting = array('industry' => 'field1', 'industryid' => 'line');
        $plottype = 'plothead';
        $title = 'List of Industry';
        $label = 'Industry';

        $qry = "
          select case reqtype when '' then category else concat(category,'~',reqtype) end as field1,line from reqcategory where isindustry =1";

        $btnadd = $this->sqlquery->checksecurity($config, 4476, '/tableentries/tableentry/entryclientindustry');
        break;

      default:
        break;
    }

    $lookupsetup = array(
      'type' => 'single',
      'title' => $title,
      'style' => 'width:900px;max-width:900px;'
    );
    $plotsetup = array(
      'plottype' => $plottype,
      'action' => '',
      'plotting' => $plotting
    );

    $cols = [
      ['name' => 'field1', 'label' => $label, 'align' => 'left', 'field' => 'field1', 'sortable' => true, 'style' => 'font-size:16px;']
    ];

    $data = $this->coreFunctions->opentable($qry);

    return ['status' => true, 'msg' => 'ok', 'data' => $data, 'lookupsetup' => $lookupsetup, 'cols' => $cols, 'plotsetup' => $plotsetup, 'index' => $index, 'rowindex' => $index, 'table' => $table, 'btnadd' => $btnadd];
  } //end function

  public function pendingqtn($config)
  {
    $lookupsetup = array(
      'type' => 'single',
      'title' => 'List of Pending Qoutations',
      'style' => 'width:800px;max-width:800px;'
    );

    $lookupclass = $config['params']['lookupclass'];

    switch ($lookupclass) {
      case 'lookupqtn_detail':
        $plotsetup = array(
          'plotting' => ['qttrno' => 'trno', 'qtref' => 'docno'],
          'plottype' => 'plotgrid',
          'action' => ''
        );
        break;
      default:
        $plotsetup = array(
          'plotting' => ['qttrno' => 'trno', 'yourref' => 'docno'],
          'plottype' => 'plothead',
          'action' => ''
        );
        break;
    }


    // lookup columns
    $cols = array(
      array('name' => 'docno', 'label' => 'Document#', 'align' => 'left', 'field' => 'docno', 'sortable' => true, 'style' => 'font-size:16px;'),
      array('name' => 'dateid', 'label' => 'Date', 'align' => 'left', 'field' => 'dateid', 'sortable' => true, 'style' => 'font-size:16px;'),
      array('name' => 'yourref', 'label' => 'PO#', 'align' => 'left', 'field' => 'yourref', 'sortable' => true, 'style' => 'font-size:16px;')
    );


    switch ($lookupclass) {
      case 'lookupqtn_detail':
        $client = $config['params']['row']['client'];
        $data = $this->coreFunctions->opentable('select trno,docno,yourref from qshead where client = ? and crtrno=0 ', [$client]);
        $table = $config['params']['table'];
        $rowindex = $config['params']['index'];
        return ['status' => true, 'msg' => 'ok', 'data' => $data, 'lookupsetup' => $lookupsetup, 'cols' => $cols, 'plotsetup' => $plotsetup, 'table' => $table, 'rowindex' => $rowindex];
        break;
      case 'lookupaccountingqtn':
        $clientid = 0;
        if (isset($config['params']['trno'])) {
          $clientid = $this->othersClass->getclientid($config);
        }

        $data = $this->coreFunctions->opentable('select head.trno, head.docno, head.yourref from qshead as head left join client on client.client = head.client where client.clientid = ? and head.crtrno=0 ', [$clientid]);
        return ['status' => true, 'msg' => 'ok', 'data' => $data, 'lookupsetup' => $lookupsetup, 'cols' => $cols, 'plotsetup' => $plotsetup];
        break;

      default:
        $client = $config['params']['addedparams'][0];
        $data = $this->coreFunctions->opentable('select trno,docno,yourref from qshead where client = ? and crtrno=0 ', [$client]);
        return ['status' => true, 'msg' => 'ok', 'data' => $data, 'lookupsetup' => $lookupsetup, 'cols' => $cols, 'plotsetup' => $plotsetup];
        break;
    }
  }



