  public function lookupsoref_void($config)
  {
    $lookupsetup = array(
      'type' => 'single',
      'title' => 'List of Sales Order',
      'style' => 'width:900px;max-width:900px;'
    );

    $plotsetup = array(
      'plottype' => 'plothead',
      'plotting' => array(
        'yourref' => 'yourref',
        'wh' => 'wh',
        'whname' => 'whname',
        'dwhname' => 'dwhname',
        'agent' => 'agent',
        'agentname' => 'agentname',
        'dagentname' => 'dagentname',
        'branchcode' => 'branchcode',
        'branchname' => 'branchname',
        'dbranchname' => 'dbranchname',
        'dept' => 'dept',
        'deptname' => 'deptname',
        'ddeptname' => 'ddeptname',
        'sotrno' => 'trno',
        'podate' => 'due',
        'deldate' => 'deldate',
        'cur' => 'cur',
        'forex' => 'forex',
      )
    );

    $cols = array(
      array('name' => 'yourref', 'label' => 'PO No.', 'align' => 'left', 'field' => 'yourref', 'sortable' => true, 'style' => 'font-size:16px;'),
      array('name' => 'agentname', 'label' => 'Agent', 'align' => 'left', 'field' => 'agentname', 'sortable' => true, 'style' => 'font-size:16px;'),
      array('name' => 'branchname', 'label' => 'Branch', 'align' => 'left', 'field' => 'branchname', 'sortable' => true, 'style' => 'font-size:16px;'),
      array('name' => 'deptname', 'label' => 'Department', 'align' => 'left', 'field' => 'deptname', 'sortable' => true, 'style' => 'font-size:16px;'),
    );

    $client = $config['params']['addedparams'][0];
    $qryselect = "select 
      num.center,
      head.trno, 
      head.docno,
      client.client,
      qt.terms,
      qt.cur,
      qt.forex,
      qt.yourref,
      qt.ourref,
      left(head.dateid,10) as dateid, 
      left(qt.dateid,10) as qtdateid, 
      left(qt.deldate,10) as deldate, 
      qt.clientname,
      qt.address, 
      qt.shipto, 
      qt.rem,
      ifnull(qt.agent, '') as agent, 
      ifnull(agent.clientname, '') as agentname,
      concat(qt.agent, '~', agent.clientname) as dagentname, 
      qt.wh as wh,
      warehouse.clientname as whname,
      concat(qt.wh, '~', warehouse.clientname) as dwhname, 
      left(qt.due,10) as due, 
      client.groupid, qt.trno as qtrno,
      ifnull(b.client,'') as branchcode,
      ifnull(b.clientname,'') as branchname, 
      concat(b.client, '~', b.clientname) as dbranchname,
      qt.deptid,
      ifnull(d.client,'') as dept,
      ifnull(d.clientname,'') as deptname,
      concat(d.client, '~', d.clientname) as ddeptname";

    $qry = $qryselect . " 
    from hsqhead as head
    left join transnum as num on num.trno = head.trno
    left join hqshead as qt on qt.sotrno=head.trno
    left join hqsstock as qtstock on qtstock.trno = qt.trno
    left join client on qt.client = client.client
    left join client as warehouse on warehouse.client = qt.wh
    left join client as agent on agent.client = qt.agent
    left join client as b on b.clientid = qt.branch
    left join client as d on d.clientid = qt.deptid 
    where qt.client = '" . $client . "' and num.center=?
    and qtstock.iss != (qtstock.sjqa + qtstock.voidqty) and qtstock.void != 1
    group by num.center, head.trno, 
    head.docno, client.client,
    qt.terms, qt.cur, qt.forex, qt.yourref,
    qt.ourref, head.dateid, qt.dateid, qt.deldate, qt.clientname,
    qt.address, qt.shipto, qt.rem, qt.agent, agent.clientname,
    qt.wh, warehouse.clientname, qt.due, client.groupid, qt.trno,
    b.client, b.clientname, qt.deptid, d.client, d.clientname";

    $data = $this->coreFunctions->opentable($qry, [$config['params']['center']]);
    return ['status' => true, 'msg' => 'ok', 'data' => $data, 'lookupsetup' => $lookupsetup, 'cols' => $cols, 'plotsetup' => $plotsetup];
  }

