      array('name' => 'agentname', 'label' => 'Agent', 'align' => 'left', 'field' => 'agentname', 'sortable' => true, 'style' => 'font-size:16px;'),
      array('name' => 'branchname', 'label' => 'Branch', 'align' => 'left', 'field' => 'branchname', 'sortable' => true, 'style' => 'font-size:16px;'),
      array('name' => 'deptname', 'label' => 'Department', 'align' => 'left', 'field' => 'deptname', 'sortable' => true, 'style' => 'font-size:16px;'),
    );

    $client = $config['params']['addedparams'][0];
    $qryselect = "select 
      num.center,
      head.trno, 
      head.docno,
      client.client,
      qt.terms,
      qt.cur,
      qt.forex,
      qt.yourref,
      qt.ourref,
      left(head.dateid,10) as dateid, 
      left(qt.dateid,10) as qtdateid, 
      qt.clientname,
      qt.address, 
      qt.shipto, 
      qt.rem,
      ifnull(qt.agent, '') as agent, 
      ifnull(agent.clientname, '') as agentname,'' as dagentname,
      qt.wh as wh,
      warehouse.clientname as whname,
      '' as dwhname, 
      left(qt.due,10) as due, 
      client.groupid, qt.trno as qtrno, 
      ifnull(b.client,'') as branchcode, 
      ifnull(b.clientname,'') as branchname, 
      qt.branch,'' as dbranchname,
      ifnull(d.client,'') as dept, 
      ifnull(d.clientname,'') as deptname, 
      qt.deptid,
      '' as ddeptname ";

    $qry = $qryselect . " 
    from hsshead as head
    left join transnum as num on num.trno = head.trno
    left join hsrhead as qt on qt.sotrno=head.trno
    left join hsrstock as stock on stock.trno=qt.trno 
    left join client on qt.client = client.client
    left join client as warehouse on warehouse.client = qt.wh
    left join client as agent on agent.client = qt.agent
    left join client as b on b.clientid = qt.branch
    left join client as d on d.clientid = qt.deptid 
    where qt.client = '" . $client . "' and num.center=? 
    and   stock.iss > (stock.sjqa+stock.voidqty) and 
    stock.void = 0
    group by num.center, head.trno, head.docno, client.client,
    qt.terms, qt.cur, qt.forex, qt.yourref,
    qt.ourref, head.dateid, qt.dateid, qt.clientname,
