  public function lookupsjref($config)
  {
    $lookupsetup = array(
      'type' => 'single',
      'title' => 'List of PO#',
      'style' => 'width:400px;max-width:400px;'
    );

    $plotsetup = array(
      'plottype' => 'plothead',
      'plotting' => array(
        'yourref' => 'yourref',
        'yourrefname' => 'yourrefname'
      )
    );

    $cols = array(
      array('name' => 'yourref', 'label' => 'PO No.', 'align' => 'left', 'field' => 'yourref', 'sortable' => true, 'style' => 'font-size:16px;')
    );


    $qry = "
        select distinct sqh.trno as yourrefname, sqh.docno as yourref from arledger as ar
        left join glhead as sjh on sjh.trno = ar.trno
        left join gldetail as sjd on ar.trno = sjd.trno and ar.line = sjd.line
        left join glstock as sjs on sjd.trno = sjs.trno
        left join hqshead as qsh on sjs.refx = qsh.trno
        left join hsqhead as sqh on sqh.trno = qsh.sotrno
        where ar.bal = 0 and sqh.trno is not null
      ";
    $data = $config['params']['addedparams'][0] == "Office Use" ? [] : $this->coreFunctions->opentable($qry);

    return ['status' => true, 'msg' => 'ok', 'data' => $data, 'lookupsetup' => $lookupsetup, 'cols' => $cols, 'plotsetup' => $plotsetup];
  } //end function

