      array('name' => 'dateid', 'label' => 'Invoice Date', 'align' => 'left', 'field' => 'dateid', 'sortable' => true, 'style' => 'font-size:16px;')
    );

    $sjtrno = $config['params']['trno'];
    $center = $config['params']['center'];

    $client = '';
    $filter = '';
    if (isset($config['params']['addedparams'][0])) {
      $client = $config['params']['addedparams'][0];
      $filter = " and head.clientid = '$client'";
    }

    $qry = "
    select head.docno as cmdocno,date(head.dateid) as dateid,head.trno as cmtrno
    from glhead as head
    left join cntnum on cntnum.trno=head.trno
    left join arledger as ar on ar.trno=head.trno
    where head.doc='CM' and cntnum.center = '$center' and ar.bal<>0  $filter";

    $data = $this->coreFunctions->opentable($qry);
    return ['status' => true, 'msg' => 'ok', 'data' => $data, 'lookupsetup' => $lookupsetup, 'cols' => $cols, 'plotsetup' => $plotsetup];
