    $cols = array(
      array('name' => 'docno', 'label' => 'Doc #', 'align' => 'left', 'field' => 'docno', 'sortable' => true, 'style' => 'font-size:16px;'),
      array('name' => 'yourref', 'label' => 'PO No.', 'align' => 'left', 'field' => 'yourref', 'sortable' => true, 'style' => 'font-size:16px;')
    );

    $client = '';
    $filter = '';
    if (isset($config['params']['addedparams'][0])) {
      $client = $config['params']['addedparams'][0];
      $filter = " and qs.client = '" . $client . "'";
    }

    if ($doc == 'PX') {
      $qry = "select 0 as trno,'' as docno,'NO PO YET' as yourref union all
      select qs.trno, qs.docno, qs.yourref from hqshead as qs
      where qs.yourref <> ''  $filter
      union all
      select qs.trno, qs.docno, qs.yourref from qshead as qs
      where qs.yourref <> '' $filter ";

      $plotsetup = array(
        'plottype' => 'plothead',
        'plotting' => array(
          'potrno' => 'trno',
          'poref' => 'yourref'
        )
      );
    } else {
      $qry = "
      select so.trno, so.docno, qs.yourref from hqshead as qs
      left join hsqhead as so on qs.sotrno = so.trno
      where qs.yourref <> '' and so.trno is not null $filter
      union all
      select so.trno, so.docno, qs.yourref from hqshead as qs
      left join sqhead as so on qs.sotrno = so.trno
      where qs.yourref <> '' and so.trno is not null $filter 
      union all 
      select so.trno, so.docno, qs.yourref from hsrhead as qs
      left join hsshead as so on qs.sotrno = so.trno
      where qs.yourref <> '' and so.trno is not null $filter
      union all
      select so.trno, so.docno, qs.yourref from hsrhead as qs
      left join sshead as so on qs.sotrno = so.trno
      where qs.yourref <> '' and so.trno is not null $filter ";
    }



    $data = $this->coreFunctions->opentable($qry);
    return ['status' => true, 'msg' => 'ok', 'data' => $data, 'lookupsetup' => $lookupsetup, 'cols' => $cols, 'plotsetup' => $plotsetup];
  }

  public function lookupdtcno($config)
  {
    $lookupsetup = array(
      'type' => 'single',
      'title' => 'List of DTC#',
      'style' => 'width:400px;max-width:400px;'
    );

    $doc = $config['params']['doc'];
    $trno = $config['params']['trno'];
    $agent = $this->coreFunctions->getfieldvalue("qshead", "agent", "trno= ?", [$trno]);
    $agentid = $this->coreFunctions->getfieldvalue("client", "clientid", "client= ?", [$agent]);

    $plotsetup = array(
      'plottype' => 'plotledger',
      'plotting' => array(
        'dtctrno' => 'trno',
        'dtcno' => 'dtcno',
        'instructions' => 'actual'
      )
    );

    $cols = array(
      array('name' => 'dtcno', 'label' => 'DTC #', 'align' => 'left', 'field' => 'dtcno', 'sortable' => true, 'style' => 'font-size:16px;'),
    );

    $qry = "select qs.trno, qs.dtcno,qs.pcfno,qs.projectid from hpxhead as qs
      where qs.agentid =  " . $agentid . " and qs.potrno =0";


    $data = $this->coreFunctions->opentable($qry);
    $c = 1;

    if (!empty($data)) {
      foreach ($data as $k => $v) {
        $ins = "";
        $q = $this->coreFunctions->opentable("select p.actual, e.category as expensename  from hpxchecking as p left join reqcategory as e on e.line = p.expenseid where p.trno = " . $data[$k]->trno);
        if (!empty($q)) {
          foreach ($q as $x => $y) {
            if ($data[$k]->projectid == "" || $data[$k]->projectid == "N/A") {
              if ($data[$k]->pcfno != "") {
                if ($ins == "") {
                  $ins  = $data[$k]->pcfno . "/" . $data[$k]->dtcno . "\n" .
                    "Approved Expenses:\n" . $c . ". " . $q[$x]->expensename . "- PHP" . number_format($q[$x]->actual, 2);
                } else {
                  $ins  = $ins . "\n" . $c . ". " . $q[$x]->expensename . "- PHP" . number_format($q[$x]->actual, 2);
                }
              } else {
                if ($ins == "") {
                  $ins  = $data[$k]['dtcno'] . "\n" .
                    "Approved Expenses:\n" . $c . ". " . $q[$x]->expensename . "- PHP" . number_format($q[$x]->actual, 2);
                } else {
                  $ins  = $ins . "\n" . $c . ". " . $q[$x]->expensename . "- PHP" . number_format($q[$x]->actual, 2);
                }
              }
            } else {
              if ($data[$k]->pcfno != "") {
                if ($ins == "") {
                  $ins  = "Project ID:" . $data[$k]->projectid . "" .
                    $data[$k]->pcfno . "/" . $data[$k]->dtcno . "\n" .
                    "Approved Expenses:\n" . $c . ". " . $q[$x]->expensename . "- PHP" . number_format($q[$x]->actual, 2);
                } else {
                  $ins  = $ins . "\n" . $c . ". " . $q[$x]->expensename . "- PHP" . number_format($q[$x]->actual, 2);
                }
              } else {
                if ($ins == "") {
                  $ins  = "Project ID:" . $data[$k]->projectid . "\n" .
                    $data[$k]->dtcno .
                    "Approved Expenses:\n" . $c . ". " . $q[$x]->expensename . "- PHP" . number_format($q[$x]->actual, 2);
                } else {
                  $ins  = $ins . "\n" . $c . ". " . $q[$x]->expensename . "- PHP" . number_format($q[$x]->actual, 2);
                }
              }
            }
            $c += 1;
          }
        }

        $data[$k]->actual = $ins;
      }
    }

    return ['status' => true, 'msg' => 'ok', 'data' => $data, 'lookupsetup' => $lookupsetup, 'cols' => $cols, 'plotsetup' => $plotsetup];
  }


