      array('name' => 'client', 'label' => 'Code', 'align' => 'left', 'field' => 'client', 'sortable' => true, 'style' => 'font-size:16px;'),
      array('name' => 'clientname', 'label' => 'Name', 'align' => 'left', 'field' => 'clientname', 'sortable' => true, 'style' => 'font-size:16px;')
    );

    $plotsetup = array(
      'plottype' => 'callback',
      'action' => 'addcustomergrid',
    );

    $qry = "select c.clientid as keyid, c.clientid, c.client, c.clientname,
    if(s.isinactive = 0, s.addr,'') as address, if(s.isinactive = 0, ifnull(s.line,0),0) as shipid,
    concat(con.salutation,' ',con.fname,' ',con.mname,' ',con.lname) as contact, ifnull(con.line,0) as shipcontactid
    from client as c 
    left join billingaddr as s on c.shipid = s.line
    left join contactperson as con on con.line = c.shipcontactid
    where c.iscustomer = 1 order by c.clientname";
    $data = $this->coreFunctions->opentable($qry);

    return ['status' => true, 'msg' => 'ok', 'data' => $data, 'lookupsetup' => $lookupsetup, 'cols' => $cols, 'plotsetup' => $plotsetup];
