    );


    $qry = "select genitem.line, genitem.barcode, genitem.uom, genitem.itemname, 
    genitem.groupid, genitem.model, genitem.class, 
    genitem.type, genitem.brand, genitem.sizeid, brand.brand_desc as brandname, groups.stockgrp_name as groupname,
    genitem.model, model.model_name as modelname,genitem.class, classi.cl_name as classname
    from item as genitem
    left join frontend_ebrands as brand on brand.brandid = genitem.brand
    left join stockgrp_masterfile as groups on groups.stockgrp_id = genitem.groupid
    left join model_masterfile as model on model.model_id = genitem.model
    left join item_class as classi on classi.cl_id = genitem.class
    where genitem.isgeneric=1";

