  public function lookupsadesc($config)
  {
    $plottype = 'plothead';
    $colname = 'SA No.';
    switch ($config['params']['lookupclass']) {
      case 'lookupsadesc':
        $plotting = array('sano' => 'line', 'sadesc' => 'sano');
        $title = 'LIST OF SA NO.';
        $where = " and s.issa= 1 ";
        break;
      case 'lookupsvsdesc':
        $plotting = array('svsno' => 'line', 'svsdesc' => 'sano');
        $title = 'LIST OF SVS NO.';
        $colname = 'SVS No.';
        $where = " and s.issvs= 1 ";
        break;
      case 'lookuppodesc':
        $plotting = array('pono' => 'line', 'podesc' => 'sano');
        $title = 'LIST OF PO NO.';
        $colname = 'PO No.';
        $where = " and s.ispo= 1 ";
        break;
    }

    if (isset($config['params']['addedparams'])) {
      $addedparams = $config['params']['addedparams'];
      $client = $addedparams[0];
    } else {
      $client = $this->coreFunctions->getfieldvalue('hprhead', 'client', 'trno=?', [$config['params']['trno']]);
      $plottype = 'plotledger';
    }


    $lookupsetup = array(
      'type' => 'single',
      'title' => $title,
      'style' => 'width:900px;max-width:900px;'
    );

    $plotsetup = array(
      'plottype' =>  $plottype,
      'action' => '',
      'plotting' => $plotting
    );

    $cols = [
      ['name' => 'sano', 'label' => $colname, 'align' => 'left', 'field' => 'sano', 'sortable' => true, 'style' => 'font-size:16px;'],
    ];

    $qry = " select 0 as line, '' as sano 
    union all
    select s.line, s.sano from clientsano as s 
    left join client on client.clientid=s.clientid 
    where client.client='" . $client . "' $where order by sano";
    $data = $this->coreFunctions->opentable($qry);

    return ['status' => true, 'msg' => 'ok', 'data' => $data, 'lookupsetup' => $lookupsetup, 'cols' => $cols, 'plotsetup' => $plotsetup];
  }

