        ['name' => 'docno', 'label' => 'Document #', 'align' => 'left', 'field' => 'docno', 'sortable' => true, 'style' => 'font-size:16px;'],
        ['name' => 'yourref', 'label' => 'Customer PO #', 'align' => 'left', 'field' => 'yourref', 'sortable' => true, 'style' => 'font-size:16px;'],
      ];
    }


    if ($config['params']['companyid'] == 40 && $config['params']['doc'] == 'MJ') { //cdo
      $lookupsetup = array(
        'type' => 'single',
        'title' => $title,
        'style' => 'width:1200px;max-width:1200px;'
      );
      $plotsetup = array(
        'plottype' => 'callback',
        'action' => 'getserialoutsingle'
      );
      $cols = [
        ['name' => 'serial', 'label' => 'Engine#', 'align' => 'left', 'field' => 'serial', 'sortable' => true, 'style' => 'font-size:16px;'],
        ['name' => 'chassis', 'label' => 'Chassis #', 'align' => 'left', 'field' => 'chassis', 'sortable' => true, 'style' => 'font-size:16px;'],
        ['name' => 'color', 'label' => 'Color', 'align' => 'left', 'field' => 'color', 'sortable' => true, 'style' => 'font-size:16px;'],
        ['name' => 'pnp', 'label' => 'PNP#', 'align' => 'left', 'field' => 'pnp', 'sortable' => true, 'style' => 'font-size:16px;'],
        ['name' => 'csr', 'label' => 'CSR#', 'align' => 'left', 'field' => 'csr', 'sortable' => true, 'style' => 'font-size:16px;'],
      ];
    }

    $trno = $config['params']['row']['trno'];
    $sline = $config['params']['row']['line'];
    $itemid = $config['params']['row']['itemid'];
    $whid = $config['params']['row']['whid'];
    $reqty = $config['params']['row']['isqty'];

    if ($config['params']['companyid'] == 40) { //cdo
      $filter = "";
    }

    if ($config['params']['lookupclass'] == 'lookupserialoutrf') {
      $trno = $config['params']['row']['refx'];
      $line = $config['params']['row']['linex'];
      $qry = "select serialin.serial as keyid,glstock.itemid,serialin.serial,glhead.docno,glstock.trno,glstock.line,serialin.sline,glhead.yourref," . $sline . " as stockline 
      from serialout as serialin
      left join glstock on glstock.trno = serialin.trno and  glstock.line = serialin.line
      left join glhead on glhead.trno = glstock.trno
      where glstock.trno=? and glstock.line = ? and serialin.rftrno =0
      group by glstock.trno,glstock.line,glstock.itemid,serialin.serial,glhead.docno,serialin.sline,glhead.yourref";
      $data = $this->coreFunctions->opentable($qry, [$trno, $line]);
    } else {
      $qry = "select serialin.serial as keyid,glstock.itemid,serialin.serial,glhead.docno,glstock.trno,
      glstock.line,serialin.sline,glhead.yourref," . $sline . " as stockline,serialin.color,serialin.chassis,serialin.pnp,
      serialin.csr," . $trno . " as stocktrno,glstock.whid,glstock.loc,item.barcode," . $reqty . " as reqty from serialin
      left join rrstatus as glstock on glstock.trno = serialin.trno and glstock.line = serialin.line
      left join glhead on glhead.trno = glstock.trno
      left join item on item.itemid = glstock.itemid
      where serialin.outline =0 and glstock.itemid = ? and glstock.whid = ? " . $filter . " 
      group by glstock.trno,glstock.line,glstock.itemid,serialin.serial,glhead.docno,
      serialin.sline,glhead.yourref,serialin.color,serialin.chassis,serialin.pnp,serialin.csr,glstock.whid,glstock.loc,item.barcode";
      $data = $this->coreFunctions->opentable($qry, [$itemid, $whid]);
    }


    return ['status' => true, 'msg' => 'ok', 'data' => $data, 'lookupsetup' => $lookupsetup, 'cols' => $cols, 'plotsetup' => $plotsetup];
  } // end function

