  public function lookupassignedpodocno($config)
  {
    $lookupsetup = [
      'type' => 'single',
      'title' => 'Assigned PO Docno',
      'style' => 'width:900px;max-width:900px;'
    ];
    $plotsetup = [
      'plottype' => 'plothead',
      'plotting' => ['assignedpodocno' => 'docno', 'potrno' => 'trno']
    ];
    $cols = [
      ['name' => 'docno', 'label' => 'Document #', 'align' => 'left', 'field' => 'docno', 'sortable' => true, 'style' => 'font-size:16px;']
    ];


    $qry = "select distinct docno,trno from (
      select head.docno,i.barcode,i.itemname,head.trno,stock.line,info.printdate,stock.void
      from pohead as head
      left join postock as stock on stock.trno=head.trno
      left join item as i on i.itemid=stock.itemid
      left join headinfotrans as info on info.trno=head.trno
      union all
      
      select head.docno,i.barcode,i.itemname,head.trno,stock.line,info.printdate,stock.void
      from hpohead as head
      left join hpostock as stock on stock.trno=head.trno
      left join item as i on i.itemid=stock.itemid
      left join hheadinfotrans as info on info.trno=head.trno
      ) as a where a.printdate is not null or a.void=1 
      order by trno";
    $data = $this->coreFunctions->opentable($qry);
    return ['status' => true, 'msg' => 'ok', 'data' => $data, 'lookupsetup' => $lookupsetup, 'cols' => $cols, 'plotsetup' => $plotsetup];
  }

