    ];
    $cols = [
      ['name' => 'docno', 'label' => 'Document #', 'align' => 'left', 'field' => 'docno', 'sortable' => true, 'style' => 'font-size:16px;'],
      ['name' => 'barcode', 'label' => 'Barcode', 'align' => 'left', 'field' => 'barcode', 'sortable' => true, 'style' => 'font-size:16px;'],
      ['name' => 'itemname', 'label' => 'Item Name', 'align' => 'left', 'field' => 'itemname', 'sortable' => true, 'style' => 'font-size:16px;'],
      ['name' => 'qty', 'label' => 'Qty', 'align' => 'center', 'field' => 'qty', 'style' => 'font-size:16px;'],
      ['name' => 'uom', 'label' => 'UOM', 'align' => 'left', 'field' => 'uom', 'style' => 'font-size:16px;'],
    ];

    $add = '';
    $grp = '';
    $filter = 'stock.qty>stock.qa ';
    if ($config['params']['doc'] == 'PN') {
      array_push($cols, ['name' => 'pending', 'label' => 'Pending Qty', 'align' => 'center', 'field' => 'pending', 'style' => 'font-size:16px;']);
      $add = ',round(head.qty-head.qa,2) as pending';
      $grp = ',head.qa';
      $filter = 'head.qty>head.qa';
    }
    $qry = "select head.trno, head.docno, head.itemid, item.barcode,item.itemname, head.uom, 
                   head.qty, head.wh $add
            from hprhead as head 
            left join item on item.itemid=head.itemid 
            left join hprstock as stock on stock.trno = head.trno 
            where $filter
            group by head.trno, head.docno, head.itemid, item.barcode,item.itemname, head.uom, head.qty, 
                  head.wh $grp 
            order by trno";
    $data = $this->coreFunctions->opentable($qry);
    return ['status' => true, 'msg' => 'ok', 'data' => $data, 'lookupsetup' => $lookupsetup, 'cols' => $cols, 'plotsetup' => $plotsetup];
