  public function lookuppendingpdsummary($config)
  {
    $center = $config['params']['center'];
    $lookupsetup = [
      'type' => 'multi',
      'rowkey' => 'keyid',
      'title' => 'List of Pending Production Order Summary',
      'btns' => ['summary' => ['label' => 'Show Details', 'lookupclass' => 'lookupsetup', 'action' => 'lookuppendingpd']],
      'style' => 'width:1200px;max-width:1200px;'
    ];
    $plotsetup = [
      'plottype' => 'callback',
      'action' => 'getpdsummary'
    ];
    $cols = [
      ['name' => 'docno', 'label' => 'Document#', 'align' => 'left', 'field' => 'docno', 'sortable' => true, 'style' => 'font-size:16px;'],
      ['name' => 'dateid', 'label' => 'Date', 'align' => 'left', 'field' => 'dateid', 'sortable' => true, 'style' => 'font-size:16px;'],
      ['name' => 'fg', 'label' => 'Finished Good', 'align' => 'left', 'field' => 'fg', 'sortable' => true, 'style' => 'font-size:16px;'],
      ['name' => 'stage', 'label' => 'Process', 'align' => 'left', 'field' => 'stage', 'style' => 'font-size:16px;'],
      ['name' => 'rem', 'label' => 'Notes', 'align' => 'left', 'field' => 'rem', 'style' => 'font-size:16px;']
    ];
    $data = [];
    $qry = "select concat(head.trno,st.stageid) as keyid,head.trno,st.stageid, head.docno, left(head.dateid,10) as dateid, head.rem,stage.stage,item.itemname as fg
      from hpdhead as head
      left join hpiprocess as st on st.trno=head.trno
      left join stagesmasterfile as stage on stage.line=st.stageid
      left join hpdstock as stock on stock.trno=head.trno
      left join transnum on transnum.trno=head.trno
      left join item on item.itemid = head.itemid
      where transnum.center='" . $center . "' and stock.qty>stock.qa and stock.void=0
      group by head.trno, head.docno, head.dateid, head.rem,stage.stage,item.itemname,st.stageid";
    $data = $this->coreFunctions->opentable($qry);
    return ['status' => true, 'msg' => 'ok', 'data' => $data, 'lookupsetup' => $lookupsetup, 'cols' => $cols, 'plotsetup' => $plotsetup];
  }

  public function lookuppendingpd($config)
  {
    $center = $config['params']['center'];
    $doc = $config['params']['doc'];
    $btns = [];

    if ($doc != 'RM') {
      $btns = ['summary' => ['label' => 'Show Summary', 'lookupclass' => 'lookupsetup', 'action' => 'lookuppendingpdsummary']];
    }
    $lookupsetup = [
      'type' => 'multi',
      'rowkey' => 'keyid',
      'title' => 'List of Pending Production Order Details',
      'btns' => $btns,
      'style' => 'width:100%;max-width:100%;'
    ];
    $plotsetup = [
      'plottype' => 'callback',
      'action' => 'getpddetails'
    ];
    $cols = [
      ['name' => 'docno', 'label' => 'Document#', 'align' => 'left', 'field' => 'docno', 'sortable' => true, 'style' => 'font-size:16px;'],
      ['name' => 'dateid', 'label' => 'Date', 'align' => 'left', 'field' => 'dateid', 'sortable' => true, 'style' => 'font-size:16px;'],
      ['name' => 'fg', 'label' => 'Finished Good', 'align' => 'left', 'field' => 'fg', 'sortable' => true, 'style' => 'font-size:16px;'],
      ['name' => 'stage', 'label' => 'Process', 'align' => 'left', 'field' => 'stage', 'sortable' => true, 'style' => 'font-size:16px;'],
      ['name' => 'barcode', 'label' => 'Barcode', 'align' => 'left', 'field' => 'barcode', 'sortable' => true, 'style' => 'font-size:16px;'],
      ['name' => 'itemname', 'label' => 'Itemname', 'align' => 'left', 'field' => 'itemname', 'sortable' => true, 'style' => 'font-size:16px;'],
      ['name' => 'qty', 'label' => 'OrderQty', 'align' => 'left', 'field' => 'isqty', 'sortable' => true, 'style' => 'font-size:16px;'],
      ['name' => 'qa', 'label' => 'Served', 'align' => 'left', 'field' => 'qa', 'sortable' => true, 'style' => 'font-size:16px;'],
      ['name' => 'pending', 'label' => 'Pending', 'align' => 'left', 'field' => 'pending', 'sortable' => true, 'style' => 'font-size:16px;']
    ];
    $data = [];
    $trno = $pdtrno = $stageid = $otherfilter = '';
    switch ($config['params']['doc']) {
      case 'RM':
        $trno = $config['params']['trno'];
        $pdtrno = $this->coreFunctions->getfieldvalue('lahead', 'pdtrno', 'trno=?', [$trno]);
        $stageid = $this->coreFunctions->getfieldvalue('lahead', 'stageid', 'trno=?', [$trno]);
        $otherfilter = " and head.trno='" . $pdtrno . "' and st.stageid='" . $stageid . "'";
        break;
    }
    $qry = "select concat(s.trno, s.line) as keyid, s.line, head.wh, head.trno, head.docno, date(head.dateid) as dateid, st.stageid, stage.stage, head.wh, s.itemname,
      s.barcode, s.uom, format(s.qty," . $this->companysetup->getdecimal('qty', $config['params']) . ") as qty,
      format(s.qa," . $this->companysetup->getdecimal('qty', $config['params']) . ") as qa,
      round(s.qty-s.qa," . $this->companysetup->getdecimal('qty', $config['params']) . ") as pending,item.itemname as fg
      from hpdhead as head
      left join hpiprocess as st on st.trno=head.trno
      left join stagesmasterfile as stage on stage.line=st.stageid
      left join hpdstock as s on s.trno=head.trno and s.stageid=st.stageid
      left join item on item.itemid = head.itemid
      left join transnum on transnum.trno=head.trno
      where s.qty>s.qa and s.void=0 and transnum.center='" . $center . "'" . $otherfilter;
    $data = $this->coreFunctions->opentable($qry);
    return ['status' => true, 'msg' => 'ok', 'data' => $data, 'lookupsetup' => $lookupsetup, 'cols' => $cols, 'plotsetup' => $plotsetup];
  }

