  public function lookuprepsortby($config)
  {
    //default
    $filter = '';

    $plotting = array('repsortby' => 'repsortby', 'name' => 'name');
    $plottype = 'plothead';
    $title = 'Sort by';

    $lookupsetup = array(
      'type' => 'single',
      'title' => $title,
      'style' => 'width:900px;max-width:900px;'
    );
    $plotsetup = array(
      'plottype' => $plottype,
      'action' => '',
      'plotting' => $plotting
    );
    // lookup columns
    $cols = [
      ['name' => 'repsortby', 'label' => 'Options', 'align' => 'left', 'field' => 'repsortby', 'sortable' => true, 'style' => 'font-size:16px;']
    ];


    switch ($config['params']['lookupclass']) {
      case 'oraclerepsortby':
        $qry = "select 'customer' as name,'CUSTOMER' as repsortby
            union all
            select 'sanodesc' as name, 'SA#' as repsortby
            union all
            select 'ctrlno' as name,'CTRL NO.' as repsortby
            union all
            select 'docno' as name,'DOC#' as repsortby
            union all
            select 'prdocno' as name,'PR#' as repsortby
            union all
            select 'dateid' as name,'DATE' as repsortby
            union all
            select 'barcode' as name,'BARCODE' as repsortby
            union all
            select 'itemname' as name,'ITEM NAME' as repsortby
            union all
            select 'itemdesc' as name,'TEMP DESC' as repsortby
            union all
            select 'deadline' as name,'DEADLINE' as repsortby
            union all
            select 'category' as name,'CATEGORY' as repsortby";
        break;
      case 'podrepsortby':
        $qry = "select 'head.clientname' as name, 'SUPPLIER' as repsortby
            union all
            select 'prinfo.ctrlno' as name,'CTRL NO.' as repsortby
            union all
            select 'head.docno' as name,'DOC#' as repsortby
            union all
            select 'stock.ref' as name,'PR#' as repsortby
            union all
            select 'sa.sano' as name,'SA#' as repsortby
            union all
            select 'head.dateid' as name,'DATE' as repsortby
            union all
            select 'item.barcode' as name,'BARCODE' as repsortby
            union all
            select 'item.itemname' as name,'ITEM NAME' as repsortby
            union all
            select 'prinfo.itemdesc' as name,'TEMP DESC' as repsortby
            union all
            select 'prinfo.deadline' as name,'DEADLINE' as repsortby
            union all
            select 'reqcat.category' as name,'CATEGORY' as repsortby";
        break;
      case 'pfarepsortby':
        $qry = "select 'head.dateid' as name,'DATE' as repsortby
            union all
            select 'head.clientname' as name,'SUPPLIER' as repsortby
            union all
            select 'head.docno' as name,'DOC#' as repsortby
            union all
            select 'emp.clientname' as name,'USER' as repsortby
            union all
            select 'head.dateid' as name,'TRANSACTION DATE' as repsortby
            union all
            select 'headinfo.deadline' as name,'PO DEADLINE' as repsortby
            union all
            select 'prinfo.deadline' as name,'DEADLINE' as repsortby
            union all
            select 'cat.category' as name,'CATEGORY' as repsortby";
        break;
      case 'cprrepsortby':
        $qry = "select 'clientname' as name,'SUPPLIER' as repsortby
            union all
            select 'dateid' as name,'PO DATE' as repsortby
            union all
            select 'rrdate' as name,'DATE RECEIVED' as repsortby
            union all
            select 'barcode' as name,'BARCODE' as repsortby
            union all
            select 'itemname' as name,'ITEM NAME' as repsortby
            union all
            select 'specs' as name,'SPECS' as repsortby
            union all
            select 'deadline' as name,'DEADLINE' as repsortby
            union all
            select 'category' as name,'CATEGORY' as repsortby";
        break;
      case 'csirepsortby':
        $qry = "select 'dateid' as name,'DATE CHECKED' as repsortby
            union all
            select 'deadline' as name,'DEADLINE' as repsortby
            union all
            select 'clientname' as name,'SUPPLIER' as repsortby
            union all
            select 'docno' as name,'DOC#' as repsortby
            union all
            select 'barcode' as name,'BARCODE' as repsortby
            union all
            select 'itemname' as name,'ITEM NAME' as repsortby
            union all
            select 'itemdesc' as name,'TEMP DESC' as repsortby";
        break;
      case 'createRRSortBy':
        $qry = "
          select a.name,a.repsortby from(
            select 'source' as name, 'SOURCE.' as repsortby
            union all
            select 'docno','DOC#'
            union all
            select 'dateid','DATE'
            union all
            select 'barcode','BARCODE'
            union all
            select 'itemname','ITEM NAME'
            union all
            select 'itemdesc','TEMP DESC.'          
            union all
            select 'deadline','DEADLINE'
            union all
            select 'cvdocno,cvadvdocno','CV REF'
            union all
            select 'modeofpayment,cvadvmop','PAYMENT TYPE'
            union all
            select 'salestype,cvadvst','PAYMENT TERMS'
            union all
            select 'category','CATEGORY'
          ) as a
        ";
        break;
      case 'createCVSortBy':
        $qry = "
          select a.name,a.repsortby from(
            select 'clientname' as name, 'SUPPLIER' as repsortby
            union all 
            select 'ctrlno', 'CTRL NO.'
            union all 
            select 'docno', 'DOC#'
            union all 
            select 'dateid', 'DATE'
            union all 
            select 'barcode', 'BARCODE'
            union all 
            select 'itemname', 'ITEMNAME'
            union all 
            select 'itemdesc', 'TEMP DESCRIPTION'
            union all 
            select 'deadline', 'DEADLINE'
            union all 
            select 'modeofpayment', 'PAYMENT TYPE'
            union all 
            select 'salestype', 'PAYMENT TERMS'
            union all 
            select 'category', 'CATEGORY'
          ) as a
        ";
        break;
      case 'repsortby':
        if ($config['params']['companyid'] == 16) { //ati
          $qry = "
          select a.name,a.repsortby from(
            select 'docno' as name, 'CV#' as repsortby
            union all 
            select 'deptname' as name, 'DEPARTMENT' as repsortby
            union all 
            select 'datereleased' as name , 'DATE CASH RELEASED' as repsortby
            union all 
            select 'pono' as name, 'PO#' as repsortby
            union all 
            select 'sino' as name, 'SI#' as repsortby
            union all 
            select 'yourref' as name , 'YOURREF' as repsortby
            union all 
            select 'ourref' as name , 'OURREF' as repsortby
            
          ) as a
        ";
        } else {
          goto defaultsort;
        }

        break;
      default:
        defaultsort:
        $qry = "select 'info.ctrlno' as name, 'CTRL NO.' as repsortby
            union all
            select 'canvasstatus' as name,'STATUS MODULE' as repsortby
            union all
            select 'head.docno' as name,'DOC#' as repsortby
            union all
            select 'head.dateid' as name,'DATE' as repsortby
            union all
            select 'item.barcode' as name,'BARCODE' as repsortby
            union all
            select 'item.itemname' as name,'ITEM NAME' as repsortby
            union all
            select 'info.itemdesc' as name,'TEMP DESC' as repsortby
            union all
            select 'info.deadline' as name,'DEADLINE' as repsortby
            union all
            select 'canvasstatus' as name,'STATUS' as repsortby
            union all
            select 'reqcat.category' as name,'CATEGORY' as repsortby";
        break;
    }

    $data = $this->coreFunctions->opentable($qry);
    return ['status' => true, 'msg' => 'ok', 'data' => $data, 'lookupsetup' => $lookupsetup, 'cols' => $cols, 'plotsetup' => $plotsetup];
  } //end function

