      ['name' => 'oraclecode', 'label' => 'Oracle Code', 'align' => 'left', 'field' => 'oraclecode', 'sortable' => true, 'style' => 'font-size:16px;']
    ];


    $qry = "
      select * from (   
      select distinct stock.oraclecode, svs.sano as svsnum from oqstock as stock
