      'title' => 'List of Unpaid Accounts',
      'style' => 'width:1000px;max-width:1000px;'
    );

    $plotsetup = array(
      'plottype' => 'show',
      'action' => '',
      'callbackfieldhead' => [],
      'callbackfieldlookup' => [],
      'plotting' => []
    );

    $trno = $config['params']['trno'];
    $doc = $config['params']['doc'];
    $client = $config['params']['client'];
    $projectid = 0;
    $phaseid = 0;
    $modelid = 0;
    $blklotid = 0;

    if (isset($config['params']['addedparams'])) {
      $projectid = $config['params']['addedparams'][0];
      $phaseid = $config['params']['addedparams'][1];
      $modelid = $config['params']['addedparams'][2];
      $blklotid = $config['params']['addedparams'][3];
    }


    // lookup columns
    $cols = [
      ['name' => 'rem', 'label' => 'Term', 'align' => 'left', 'field' => 'rem', 'sortable' => true, 'style' => 'font-size:16px;'],
      ['name' => 'postdate', 'label' => 'Due Date', 'align' => 'left', 'field' => 'postdate', 'sortable' => true, 'style' => 'font-size:16px;'],
      ['name' => 'db', 'label' => 'Amount', 'align' => 'left', 'field' => 'db', 'sortable' => true, 'style' => 'font-size:16px;']
    ];

    $qry = "select left(detail.postdate,10) as postdate,detail.trno,detail.line,coa.alias,format(detail.db,2) as db,detail.rem,head.projectid,head.phaseid,head.modelid,head.blklotid,hinfo.dueday,hinfo.reservationdate, ifnull(hinfo.reservationfee,0) as reservationfee, ifnull(hinfo.farea,0) as farea, ifnull(hinfo.fpricesqm,0) as fpricesqm, ifnull(hinfo.ftcplot,0) as ftcplot,
    ifnull(hinfo.ftcphouse,0) as ftcphouse, ifnull(hinfo.fma1,0) as fma1, ifnull(hinfo.fma2,0) as fma2, ifnull(hinfo.fma3,0) as fma3,
    ifnull(hinfo.finterestrate,0) as finterestrate, ifnull(hinfo.termspercentdp,0) as termspercentdp, ifnull(hinfo.termsmonth,0) as termsmonth, ifnull(hinfo.termspercent,0) as termspercent, 
    ifnull(hinfo.termsyear,0) as termsyear, ifnull(hinfo.fsellingpricegross,0) as fsellingpricegross, ifnull(hinfo.fdiscount,0) as fdiscount,
    ifnull(hinfo.fsellingpricenet,0) as fsellingpricenet, ifnull(hinfo.fmiscfee,0) as fmiscfee, ifnull(hinfo.fcontractprice,0) as fcontractprice, ifnull(hinfo.fmonthlydp,0) as fmonthlydp, ifnull(hinfo.fmonthlyamortization,0) as fmonthlyamortization,
   ifnull(hinfo.ffi,0) as ffi, ifnull(hinfo.fmri,0) as fmri,ifnull(hinfo.loanamt,0) as loanamt,di.fi,di.mri,di.interest,di.principal,di.lotbal,di.housebal,di.hlbal,di.ortrno,di.checkno,di.payment,di.principalcol,di.percentage,di.paymentdate
    from glhead as head left join hcntnuminfo as hinfo on hinfo.trno = head.trno left join gldetail as detail on detail.trno = head.trno left join coa on coa.acnoid = detail.acnoid
    left join hdetailinfo as di on di.trno = detail.trno and di.line = detail.line
    left join client as c on c.clientid = head.clientid where di.ortrno = 0 and c.client = '" . $client . "' ";

    if (isset($config['params']['addedparams'])) {
      $qry = $qry . " and detail.projectid = " . $projectid . " and detail.phaseid = " . $phaseid . " and detail.modelid = " . $modelid . " and detail.blklotid =" . $blklotid;
    }

    $data = $this->coreFunctions->opentable($qry . " order by trno,line ");
    return ['status' => true, 'action' => 'load', 'msg' => 'ok', 'data' => $data, 'lookupsetup' => $lookupsetup, 'cols' => $cols];
  }


