  public function lookuprchecks($config)
  {
    $filter = '';
    $doc = $config['params']['doc'];
    $plotting = array('rctrno' => 'trno', 'rcline' => 'line', 'rccheck' => 'checkno', 'db' => 'amount');

    $plottype = 'callback';
    $title = 'List of Received Checks';

    $lookupsetup = array(
      'type' => 'multi',
      'rowkey' => 'keyid',
      'title' => $title,
      'style' => 'width:900px;max-width:900px;'
    );
    $plotsetup = array(
      'plottype' => $plottype,
      'action' => 'getrc',
      'plotting' => $plotting
    );
    // lookup columns
    $cols = [
      ['name' => 'docno', 'label' => 'Document #', 'align' => 'left', 'field' => 'docno', 'sortable' => true, 'style' => 'font-size:16px;'],
      ['name' => 'checkdate', 'label' => 'Check Date', 'align' => 'left', 'field' => 'checkdate', 'sortable' => true, 'style' => 'font-size:16px;'],
      ['name' => 'checkno', 'label' => 'Check No.', 'align' => 'left', 'field' => 'checkno', 'sortable' => true, 'style' => 'font-size:16px;'],
      ['name' => 'db', 'label' => 'Amount', 'align' => 'left', 'field' => 'db', 'sortable' => true, 'style' => 'font-size:16px;']
    ];

    $qry = "select concat(d.trno,d.line) as keyid,date(h.dateid) as dateid,d.trno,d.line,h.docno,left(d.checkdate,10) as checkdate,
          d.checkno,d.amount as db,d.bank,'CR1' as contra 
            from hrcdetail as d 
            left join hrchead as h on h.trno = d.trno 
            where d.ortrno =0 and d.orline=0 " . $filter . "
            union all
            select concat(d.trno,d.line) as keyid,date(h.dateid) as dateid,d.trno,d.line,h.docno,left(h.dateid,10) as checkdate,
            '' as checkno,d.amount as db,d.bank ,'CA1' as contra
            from hrhdetail as d 
            left join hrhhead as h on h.trno = d.trno 
            where d.ortrno =0 and d.orline=0 " . $filter;

    $data = $this->coreFunctions->opentable($qry);
    return ['status' => true, 'msg' => 'ok', 'data' => $data, 'lookupsetup' => $lookupsetup, 'cols' => $cols, 'plotsetup' => $plotsetup];
  } //end function  

