         case when info.isprc=0 then '0' else '1' end as isprc,
         case when info.isdriverlisc=0 then '0' else '1' end as isdriverlisc,         
         case when info.isotherid=0 then '0' else '1' end as isotherid,  
         info.idno,
         info.expiration,
