  public function lookupprovcity($config)
  {

    $filter = '';
    $prov = '';
    $city = '';
    $lookupclass = $config['params']['lookupclass'];

    switch ($lookupclass) {
      case 'city':
      case 'rcity':
      case 'pcity':
        if (isset($config['params']['addedparams'][0])) {
          $prov = $config['params']['addedparams'][0];
        }
        break;
      case 'brgy':
      case 'rbrgy':
      case 'pbrgy':
      case 'rzipcode':
      case 'zipcode':
      case 'pzipcode':
        if (isset($config['params']['addedparams'][0])) {
          $city = $config['params']['addedparams'][0];
        }
        break;
    }

    if ($prov != '') {
      $prov = $this->coreFunctions->getfieldvalue("refprovince", "provcode", "provdesc=?", [$prov]);
      $filter = " and provcode = '$prov' ";
    }

    if ($city != '') {
      $city = $this->coreFunctions->getfieldvalue("refcitymun", "citymuncode", "citymundesc=?", [$city]);
      $filter = " and citymuncode='" . $city . "' ";
    }

    //default
    $field = 'province';
    $title = 'List of Province';
    $label = 'Province';

    switch ($lookupclass) {
      case 'rcity':
      case 'pcity':
      case 'city':
        $field = 'city';
        $title = 'List of Cities';
        $label = 'City';
        if ($prov == '') {
          return ['status' => false, 'msg' => 'Please select province..'];
        }
        $qry = "select r.citymundesc as city,case (select count(zipcode) from zipcode as z where z.citycode = r.citymuncode) when 1 then
        (select zipcode from zipcode as z where z.citycode = r.citymuncode) else '' end as zipcode
         from refcitymun as r where ''='' $filter order by citymundesc ";

        if ($lookupclass == 'rcity') {
          $plotting = array($lookupclass => $field, 'zipcode' => 'zipcode', 'rzipcode' => 'zipcode');
        } else {
          $plotting = array($lookupclass => $field, 'zipcode' => 'zipcode', 'pzipcode' => 'zipcode');
        }

        $plottype = 'plothead';
        break;
      case 'pprovince':
      case 'rprovince':
      case 'province':
        $field = 'province';
        $title = 'List of Provinces';
        $qry = "select provdesc as province from refprovince order by provdesc";

        $plotting = array($lookupclass => $field);
        $plottype = 'plothead';
        break;
      case 'brgy':
      case 'rbrgy':
      case 'pbrgy':
        $field = 'brgy';
        $title = 'List of Barangays';
        $label = 'Barangay';
        if ($city == '') return ['status' => false, 'msg' => 'Please select city...'];
        $qry = "select brgydesc as brgy from refbrgy where 1=1 " . $filter . " order by brgydesc";

        $plotting = array($lookupclass => $field);
        $plottype = 'plothead';
        break;
      case 'rzipcode':
      case 'zipcode':
      case 'pzipcode':
        $field = 'zipcode';
        $title = 'List of Zipcodes';
        $label = 'Zipcode';
        $filter = " and citycode='" . $city . "' ";
        if ($city == '') return ['status' => false, 'msg' => 'Please select city...'];
        $qry = "select distinct zipcode as zipcode from zipcode where 1=1 " . $filter . " order by zipcode";
        $plotting = array($lookupclass => $field);
        $plottype = 'plothead';
        break;
    }

    $lookupsetup = array(
      'type' => 'single',
      'title' => $title,
      'style' => 'width:900px;max-width:900px;'
    );
    $plotsetup = array(
      'plottype' => $plottype,
      'action' => '',
      'plotting' => $plotting
    );
    // lookup columns
    $cols = [
      ['name' => $field, 'label' => $label, 'align' => 'left', 'field' => $field, 'sortable' => true, 'style' => 'font-size:16px;']
    ];

    $data = $this->coreFunctions->opentable($qry);
    return ['status' => true, 'msg' => 'ok', 'data' => $data, 'lookupsetup' => $lookupsetup, 'cols' => $cols, 'plotsetup' => $plotsetup];
  } //end function

