  public function lookuptrnxtype($config)
  {
    $lookupsetup = array(
      'type' => 'single',
      'title' => 'Transaction Types',
      'style' => 'width:900px;max-width:900px;'
    );
    $plotsetup = array(
      'plottype' => 'plothead',
      'plotting' => array('trnxtype' => 'trnxtype')
    );
    $cols = [['name' => 'trnxtype', 'label' => 'Transaction Type', 'align' => 'left', 'field' => 'trnxtype', 'sortable' => true, 'style' => 'font-size:16px;']];

    switch ($config['params']['companyid']) {
      case 39: //cbbsi
        switch ($config['params']['doc']) {
          case 'AJ':
            $data = [
              ['trnxtype' => 'Packaging'],
              ['trnxtype' => 'Recosting'],
              ['trnxtype' => 'Inventory Adj']
            ];
            break;
          case 'SM':
            $data = [
              ['trnxtype' => 'Regular'],
              ['trnxtype' => 'Direct Delivery'],
              ['trnxtype' => 'Packaging']
            ];
            break;
          default:
            goto datadefault;
            break;
        }
        break;
      case 40: //cdo
        switch ($config['params']['doc']) {
          case 'MC':
            $data = [
              ['trnxtype' => 'Cash'],
              ['trnxtype' => 'MA Collection'],
              ['trnxtype' => 'Downpayment-MC'],
              ['trnxtype' => 'Downpayment-Spareparts'],
              ['trnxtype' => 'Advance Payment'],
              ['trnxtype' => 'Spareparts']
            ];
            break;
          default:
            $plotsetup = array(
              'plottype' => 'plothead',
              'plotting' => array('pline' => 'line', 'trnxtype' => 'name')
            );
            $cols = [['name' => 'name', 'label' => 'Mode of Transaction', 'align' => 'left', 'field' => 'name', 'sortable' => true, 'style' => 'font-size:16px;']];
            $qry = "select name ,line from mode_masterfile where issp = 1 and isactive = 0";
            $data = $this->coreFunctions->opentable($qry);
            break;
        }

        break;
      case 48: //SEASTAR
        $data = [
          ['trnxtype' => 'COLLECT'],
          ['trnxtype' => 'ACCOUNT'],
          ['trnxtype' => 'PREPAID']
        ];
        break;
      default:
        datadefault:
        $data = [
          ['trnxtype' => 'PICKUP'],
          ['trnxtype' => 'DELIVERY'],
          ['trnxtype' => 'SHIPMENT']
        ];
        break;
    }

    return ['status' => true, 'msg' => 'ok', 'data' => $data, 'lookupsetup' => $lookupsetup, 'cols' => $cols, 'plotsetup' => $plotsetup];
  }

