  public function lookupmccollection($config)
  {
    $client = $config['params']['client'];
    $center = $config['params']['center'];
    $doc = $config['params']['doc'];
    //$trno = $config['params']['trno'];
    $lookupsetup = array(
      'type' => 'multi',
      'rowkey' => 'keyid',
      'title' => 'MC Collection',
      'style' => 'width:100%;max-width:100%;'
    );

    $plotsetup = array(
      'plottype' => 'callback',
      'action' => 'getmccollection',
      //'callbackfieldlookup' => array('trno')
    );
    $cols = array(
      array('name' => 'docno', 'label' => 'Document#', 'align' => 'left', 'field' => 'docno', 'sortable' => true, 'style' => 'font-size:16px;'),
      array('name' => 'dateid', 'label' => 'Date', 'align' => 'left', 'field' => 'dateid', 'sortable' => true, 'style' => 'font-size:16px;'),
      array('name' => 'clientname', 'label' => 'Name', 'align' => 'left', 'field' => 'clientname', 'sortable' => true, 'style' => 'font-size:16px;'),
      array('name' => 'amount', 'label' => 'Amount', 'align' => 'left', 'field' => 'amount', 'sortable' => true, 'style' => 'font-size:16px;'),
      array('name' => 'drno', 'label' => 'DR#', 'align' => 'left', 'field' => 'drno', 'sortable' => true, 'style' => 'font-size:16px;'),
      array('name' => 'sino', 'label' => 'SI#', 'align' => 'left', 'field' => 'sino', 'sortable' => true, 'style' => 'font-size:16px;')
    );

    $filter = '';
    $union = '';
    if ($doc == 'CR') {
      $qry = "select mch.trno as keyid,mch.trno as mctrno,mch.amount,mch.docno,h.yourref as drno,h.ourref as sino,mch.yourref,mch.ourref,mch.dateid,client.client,mch.clientname,mch.trnxtype,
      cnum.center as arcenter,num.center,mch.checkinfo,mch.checkdate,mcd.acnoid,mch.rem as hrem
      from hmchead as mch left join hmcdetail as mcd on mcd.trno = mch.trno
      left join glhead as h on h.trno = mcd.refx
      left join arledger as ar on ar.trno = h.trno and ar.dateid = mcd.dateid
      left join client as client on client.clientid = ar.clientid
      left join cntnum as cnum on cnum.trno = ar.trno
      left join transnum as num on num.trno = mch.trno
      where  mch.crtrno =0 and mcd.refx<> 0 and ar.bal<>0 and client.client = '" . $client . "'
      group by mch.trno,mch.amount,mch.docno,h.yourref,h.ourref,mch.dateid,client.client,mch.clientname,mch.trnxtype,cnum.center,num.center,mch.checkinfo,mch.checkdate,mch.yourref,mch.ourref,mcd.acnoid,mch.rem
      union all
      select mch.trno as keyid,mch.trno as mctrno,mch.amount,mch.docno,h.yourref as drno,h.ourref as sino,mch.yourref,mch.ourref,mch.dateid,client.client,client.clientname,mch.trnxtype,
      num.center as arcenter,num.center,mch.checkinfo,mch.checkdate,mcd.acnoid,mch.rem as hrem
      from hmchead as mch left join hmcdetail as mcd on mcd.trno = mch.trno
      left join glhead as h on h.trno = mcd.refx
      left join client as client on client.clientid = mch.clientid      
      left join transnum as num on num.trno = mch.trno
      where  mch.crtrno = 0 and mcd.refx= 0 and client.client = '" . $client . "'
      group by mch.trno,mch.amount,mch.docno,h.yourref,h.ourref,mch.dateid,client.client,client.clientname,mch.trnxtype,num.center,mch.checkinfo,mch.checkdate,mch.yourref,mch.ourref,mcd.acnoid,mch.rem";
    } else {
      $qry = "select concat(mch.trno) as keyid,mch.trno as mctrno,ar.trno,mch.docno,case cntnum.recontrno when 0 then ar.docno else gldetail.ref end as sjdocno,
      client.client,client.clientname,num.center,cntnum.center as arcenter,format(mch.amount,2) as amount,mch.yourref,mch.ourref,mcd.line,
      mch.dateid,format(mcd.amount,2) as damount,mcd.penalty,mcd.acnoid,mch.checkinfo,mch.checkdate,mcd.rem,mch.rem as hrem
      from hmchead as mch left join hmcdetail as mcd on mcd.trno = mch.trno
      left join transnum as num on num.trno = mch.trno
      left join gldetail on gldetail.mctrno = mch.trno    
      left join glhead as head on head.trno = gldetail.trno
      left join arledger as ar on ar.trno = gldetail.trno and ar.line = gldetail.line
      left join cntnum on cntnum.trno = head.trno
      left join client on client.clientid=head.clientid
      where  mcd.refx<> 0 and ar.bal<>0 and client.client = '" . $client . "' and mch.isok = 0 and mch.crtrno <>0
      group by mch.trno,ar.trno,cntnum.recontrno,mch.docno, ar.docno, gldetail.ref,client.client,client.clientname,
      mch.dateid,mcd.amount,mcd.penalty,num.center,cntnum.center,mcd.line,mch.amount,mch.yourref,mch.ourref,mcd.acnoid,mch.checkdate,mch.checkinfo,mcd.rem,mch.rem ";
    }
    // lookup columns 



    $data = $this->coreFunctions->opentable($qry, [$config['params']['center']]);
    return ['status' => true, 'msg' => 'ok', 'data' => $data, 'lookupsetup' => $lookupsetup, 'cols' => $cols, 'plotsetup' => $plotsetup];
  }
