  public function addcor($config)
  {

    $trno = $config['params']['trno'];
    $center = $config['params']['center'];
    $title = 'List of Material Issuance';
    if ($config['params']['companyid'] == 50) { //unitech
      $title = 'List of Raw Material Issuance';
    }
    $lookupsetup = array(
      'type' => 'multi',
      'rowkey' => 'keyid',
      'title' => $title,
      'style' => 'width:100%;max-width:100%;'
    );

    $action = 'getpendingco';
    if ($config['params']['companyid'] == 50) { //unitech
      $action = 'getpendingpe';
    }
    $plotsetup = array(
      'plottype' => 'callback',
      'action' => $action
    );
    $cols = array(
      array('name' => 'docno', 'label' => 'Document#', 'align' => 'left', 'field' => 'docno', 'sortable' => true, 'style' => 'font-size:16px;'),
      array('name' => 'dateid', 'label' => 'Date', 'align' => 'left', 'field' => 'dateid', 'sortable' => true, 'style' => 'font-size:16px;'),
      array('name' => 'clientname', 'label' => 'Client Name', 'align' => 'left', 'field' => 'clientname', 'sortable' => true, 'style' => 'font-size:16px;'),
      array('name' => 'barcode', 'label' => 'Barcode', 'align' => 'left', 'field' => 'barcode', 'sortable' => true, 'style' => 'font-size:16px;'),
      array('name' => 'itemname', 'label' => 'Itemname', 'align' => 'left', 'field' => 'itemname', 'sortable' => true, 'style' => 'font-size:16px;'),
      array('name' => 'rem', 'label' => 'Remarks', 'align' => 'left', 'field' => 'rem', 'sortable' => true, 'style' => 'font-size:16px;'),

    );
    // proj, phase, model,blklot
    $filterq = "select projectid, phaseid, modelid, blklotid 
    from lahead 
    where trno = $trno";
    $filterd = json_decode(json_encode($this->coreFunctions->opentable($filterq)), true);
    $filter = '';

    $filter .= isset($filterd[0]['projectid']) ? " and head.projectid = " . $filterd[0]['projectid'] : '';
    $filter .= isset($filterd[0]['phaseid']) ? " and head.phaseid = " . $filterd[0]['phaseid'] : '';
    $filter .= isset($filterd[0]['modelid']) ? " and head.modelid = " . $filterd[0]['modelid'] : '';
    $filter .= isset($filterd[0]['blklotid']) ? " and head.blklotid = " . $filterd[0]['blklotid'] : '';

    $table = 'hcostock';
    $table2 = 'hcohead';
    $condition = 'and stock.qa<>0 ';
    $addedfield = ',stock.barcode,stock.amenity,stock.subamenity,stock.projectid,stock.phaseid,stock.modelid,stock.blklotid';
    $qa = 'stock.miqa';
    $join = ' left join item on item.barcode = stock.barcode';
    if ($config['params']['companyid'] == 50) { //unitech
      $table = 'hprstock';
      $table2 = 'hprhead';
      $condition = " and head.doc='PE'";
      $join = 'left join item on item.itemid = stock.itemid';
      $addedfield = ',item.barcode,stock.ext,stock.rrcost';
      $qa = 'stock.qa';
    }
    $qry = "select concat(stock.trno,stock.line) as keyid,head.docno,left(head.dateid,10) as dateid,
                stock.trno, stock.line,stock.uom,
                stock.rem,stock.rrqty as isqty,stock.qty as iss,stock.qa,stock.refx,stock.linex,
                FORMAT(($qa / case when ifnull(uom.factor,0)=0 then 1 else uom.factor end)," . $this->companysetup->getdecimal('qty', $config['params']) . ") as qa,
                FORMAT(((stock.qty-$qa)/ case when ifnull(uom.factor,0)=0 then 1 else uom.factor end)," . $this->companysetup->getdecimal('qty', $config['params']) . ") as pending,
                stock.ref,stock.itemid,stock.whid,
                client.clientname,head.rem,item.itemname $addedfield
                from $table as stock
                left join transnum as num on num.trno = stock.trno
                $join
                left join uom on uom.itemid = item.itemid and uom.uom = stock.uom
                left join $table2 as head on head.trno = stock.trno
                left join client on client.client = head.client
                where  stock.qty>$qa and num.pctrno =0 $condition $filter";
    $data = $this->coreFunctions->opentable($qry);
    return ['status' => true, 'msg' => 'ok', 'data' => $data, 'lookupsetup' => $lookupsetup, 'cols' => $cols, 'plotsetup' => $plotsetup];
  }


