  public function plbyitemlookup($config) //print label by item
  {
    $plotting = array('itemdesc' => 'itemdesc', 'barcode' => 'barcode');
    $plottype = 'plothead';
    $title = 'Print Label by Item';

    $lookupsetup = array(
      'type' => 'single',
      'title' => $title,
      'style' => 'width:900px;max-width:900px;'
    );

    $plotsetup = array(
      'plottype' => $plottype,
      'action' => '',
      'plotting' => $plotting
    );
    $cols = [
      ['name' => 'itemdesc', 'label' => 'Description', 'align' => 'left', 'field' => 'itemdesc', 'sortable' => true, 'style' => 'font-size:16px;'],
      ['name' => 'barcode', 'label' => 'Barcode', 'align' => 'left', 'field' => 'barcode', 'sortable' => true, 'style' => 'font-size:16px;']

    ];
    $trno = $config['params']['dataid'];
    $qry = "select item.itemname as itemdesc,fa.barcode  from rrfams as rr
    left join lastock as s on s.trno=rr.trno and s.line=rr.line
    left join item on item.itemid=s.itemid
    left join item as fa on fa.itemid=rr.itemid where s.trno=$trno
    union all
    select item.itemname as itemdesc,fa.barcode  from hrrfams as rr
    left join glstock as s on s.trno=rr.trno and s.line=rr.line
    left join item on item.itemid=s.itemid
    left join item as fa on fa.itemid=rr.itemid where s.trno=$trno
    ";
    $data = $this->coreFunctions->opentable($qry);
    return ['status' => true, 'msg' => 'ok', 'data' => $data, 'lookupsetup' => $lookupsetup, 'cols' => $cols, 'plotsetup' => $plotsetup];
  }


