  public function lookupledocno($config)
  {

    $clientid = $config['params']['clientid'];

    $plotting = array('ledocno' => 'docno', 'trno' => 'dptrno');
    $plottype = 'plotledger';
    $title = 'LIST OF LOAN APPLICATION';


    $lookupsetup = array(
      'type' => 'single',
      'title' => $title,
      'style' => 'width:900px;max-width:900px;'
    );

    $plotsetup = array(
      'plottype' => $plottype,
      'action' => '',
      'plotting' => $plotting
    );

    $cols = array();
    array_push($cols, array('name' => 'docno', 'label' => 'Application #', 'align' => 'left', 'field' => 'docno', 'sortable' => true, 'style' => 'font-size:16px;'));
    array_push($cols, array('name' => 'dateid', 'label' => 'Date', 'align' => 'left', 'field' => 'dateid', 'sortable' => true, 'style' => 'font-size:16px;'));
    array_push($cols, array('name' => 'client', 'label' => 'Borrower Code', 'align' => 'left', 'field' => 'client', 'sortable' => true, 'style' => 'font-size:16px;'));
    array_push($cols, array('name' => 'clientname', 'label' => 'Borrower', 'align' => 'left', 'field' => 'clientname', 'sortable' => true, 'style' => 'font-size:16px;'));

    $qry = "select ar.docno,num.dptrno,sum(ar.bal) as bal,cl.client,head.clientname from arledger as ar
           left join cntnum as num on num.trno = ar.trno
           left join glhead as head on head.trno = num.trno
           left join client as cl on cl.clientid = head.clientid
           where head.doc = 'CV' and ar.clientid = $clientid
           group by ar.docno,num.dptrno,head.clientname,cl.client";
    $data = $this->coreFunctions->opentable($qry);
    return ['status' => true, 'msg' => 'ok', 'data' => $data, 'lookupsetup' => $lookupsetup, 'cols' => $cols, 'plotsetup' => $plotsetup];
  }

  public function lookupappdocno($config)
  {
    //default
    $doc = $config['params']['doc'];

    $plotting = array('appref' => 'docno', 'aftrno' => 'trno', 'amount' => 'bal');
    $plottype = 'plothead';
    $title = 'List of Issued Loans';
    $addfields = "";

    if ($doc == 'POSTINGPDC') {
      $plotting = array('yourref' => 'docno', 'apptrno' => 'trno', 'principal' => 'principal', 'otherinc' => 'otherinc');
      $plottype = 'plotgrid';
      $table = $config['params']['table'];
      $rowindex = $config['params']['index'];
      $addfields = ",(select principal from htempdetailinfo where trno = apphead.trno limit 1) as principal,
      (select interest+pfnf+nf from htempdetailinfo where trno = apphead.trno limit 1) as otherinc";
    }

    $lookupsetup = array(
      'type' => 'single',
      'title' => $title,
      'style' => 'width:900px;max-width:900px;'
    );
    $plotsetup = array(
      'plottype' => $plottype,
      'action' => '',
      'plotting' => $plotting
    );

    $cols = array(
      array('name' => 'docno', 'label' => 'Document#', 'align' => 'left', 'field' => 'docno', 'sortable' => true, 'style' => 'font-size:16px;'),
      array('name' => 'client', 'label' => 'Code', 'align' => 'left', 'field' => 'client', 'sortable' => true, 'style' => 'font-size:16px;'),
      array('name' => 'clientname', 'label' => 'Borrower', 'align' => 'left', 'field' => 'clientname', 'sortable' => true, 'style' => 'font-size:16px;'),
      array('name' => 'loantype', 'label' => 'Loan Type', 'align' => 'left', 'field' => 'loantype', 'sortable' => true, 'style' => 'font-size:16px;')
    );

    $clientid = 0;
    if (isset($config['params']['addedparams'][0])) {
      $clientid = $config['params']['addedparams'][0];
    }

    $filter = "";
    if ($clientid != 0) {
      $filter = " where ar.clientid = " . $clientid;
    }

    if ($doc == 'POSTINGPDC') {
      $clientid = $config['params']['row']['clientid'];
      $filter = " where ar.clientid = " . $clientid;
    }



    $qry = "select ar.docno,ar.trno,c.reqtype as loantype,i.amortization as bal,apphead.clientname,apphead.client " . $addfields . " from arledger as ar 
    left join transnum as app on app.cvtrno = ar.trno left join heahead as apphead on apphead.trno = app.trno left join heainfo as i on i.trno = app.trno
    left join reqcategory as c on c.line = apphead.planid  " . $filter . " group by ar.docno,ar.trno,c.reqtype,apphead.clientname,apphead.client,i.amortization,apphead.trno ";


    $data = $this->coreFunctions->opentable($qry);
    if ($doc == 'POSTINGPDC') {
      return ['status' => true, 'msg' => 'ok', 'data' => $data, 'lookupsetup' => $lookupsetup, 'cols' => $cols, 'plotsetup' => $plotsetup, 'table' => $table, 'rowindex' => $rowindex];
    } else {
      return ['status' => true, 'msg' => 'ok', 'data' => $data, 'lookupsetup' => $lookupsetup, 'cols' => $cols, 'plotsetup' => $plotsetup];
    }
  } //end function

