  public function lookupstationreport($config)
  {

    $branchid = isset($config['params']['addedparams'][0]) ? $config['params']['addedparams'][0] : '';
    // $center = isset($config['params']['addedparams'][0]) ? $config['params']['addedparams'][0] : '';

    $plotting = array('stationline' => 'line',  'stationid' => 'clientid', 'stationname' => 'station');
    $plottype = 'plothead';
    $title = 'List of Station';

    $lookupsetup = array(
      'type' => 'single',
      'title' => $title,
      'style' => 'width:900px;max-width:900px;'
    );
    $plotsetup = array(
      'plottype' => $plottype,
      'action' => '',
      'plotting' => $plotting
    );
    // lookup columns
    $cols = [
      ['name' => 'station', 'label' => 'Station', 'align' => 'left', 'field' => 'station', 'sortable' => true, 'style' => 'font-size:16px;'],
    ];
    switch ($config['params']['lookupclass']) {
      case 'station':
        $query = "select '' as line, '' as clientid, '' as station
                  union all
                  select line, clientid, station from branchstation where clientid";
        $data = $this->coreFunctions->opentable($query);
        break;
      default:
        $qry = "
            select 0 as line,  0 as clientid, '' as station
            union all
            select line, clientid,station from branchstation
            where clientid = ? ";
        $data = $this->coreFunctions->opentable($qry, [$branchid]);
        break;
    }
    return ['status' => true, 'msg' => 'ok', 'data' => $data, 'lookupsetup' => $lookupsetup, 'cols' => $cols, 'plotsetup' => $plotsetup];
  } //end function

