  public function lookuppurposeofpayment($config)
  {
    $title = 'List of Purpose of Payment';
    $fieldid = 'ppid';
    $field = 'purposeofpayment';
    $label = 'Payment Purpose';
    $condition = 'ispaytype=1';
    $accessid = 5039;
    $entry = 'entrypurposeofpayment';

    switch ($config['params']['action']) {
      case 'lookuptrnxtype2':
        $title = 'List of Transaction Type';
        $fieldid = 'trnxtid';
        $field = 'trnxtype2';
        $label = 'Transaction type';
        $condition = 'isttype=1';
        $accessid = 5038;
        $entry = 'entrytransactiontype';
        break;
      case 'lookupmodeofpayment2':
        $title = 'List of Mode of Payment';
        $fieldid = 'mpid';
        $field = 'modeofpayment2';
        $label = 'Payment Mode';
        $condition = 'ispaymode=1';
        $accessid = 5040;
        $entry = 'entrymodeofpayment';
        break;
    }

    $lookupsetup = array(
      'type' => 'single',
      'title' => $title,
      'style' => 'width:600px;max-width:600px;'
    );

    $plotsetup = array(
      'plottype' => 'plothead',
      'plotting' => array($fieldid => 'line', $field => 'category')
