  public function lookupbank($config)
  {
    $lookupsetup = [
      'type' => 'single',
      'title' => 'List of Bank',
      'style' => 'width:100%;max-width:100%;'
    ];
    $plotsetup = [
      'plottype' => 'plotgrid',
      'plotting' => ['bank' => 'bank', 'branch' => 'branch']
    ];
    $cols = [
      ['name' => 'bank', 'label' => 'Bank', 'align' => 'left', 'field' => 'bank', 'sortable' => true, 'style' => 'font-size:16px;'],
      ['name' => 'branch', 'label' => 'Branch', 'align' => 'left', 'field' => 'branch', 'sortable' => true, 'style' => 'font-size:16px;']
    ];
    $data = $this->coreFunctions->opentable("select bank, branch from rcdetail union all select bank, branch from hrcdetail group by bank, branch order by bank");
    $table = $config['params']['table'];
    $rowindex = $config['params']['index'];
    return ['status' => true, 'msg' => 'ok', 'data' => $data, 'lookupsetup' => $lookupsetup, 'cols' => $cols, 'plotsetup' => $plotsetup, 'table' => $table, 'rowindex' => $rowindex];
  }
