      'plottype' => $plottype,
      'action' => '',
      'plotting' => $plotting
    ];

    $cols = [
      ['name' => 'label', 'label' => 'Payment Type', 'align' => 'left', 'field' => 'label', 'sortable' => true, 'style' => 'font-size:16px;'],
    ];

    $data = $this->paymentTypes();

    return ['status' => true, 'msg' => 'ok', 'data' => $data, 'lookupsetup' => $lookupsetup, 'cols' => $cols, 'plotsetup' => $plotsetup];
