  public function lookupgroup($config)
  {
    //default
    $lookupclass = $config['params']['lookupclass'];

    switch ($lookupclass) {
      case 'lookupgroup1':
        $plotting = array('pltrno' => 'line', 'salesgroup' => 'category', 'mmname' => 'reqtype', 'sname' => 'code', 'ename' => 'position');
        break;
      case 'lookupgroup':
        $plotting = array('partreqtypeid' => 'line', 'subgroup' => 'category', 'fname' => 'reqtype', 'mname' => 'code', 'lname' => 'position', 'fname' => 'reqtype', 'mname' => 'code', 'lname' => 'position');
        break;
    }

    $plottype = 'plothead';

    $title = 'List of Groups';
    $lookupsetup = array(
      'type' => 'single',
      'title' => $title,
      'style' => 'width:900px;max-width:900px;'
    );
    $plotsetup = array(
      'plottype' => $plottype,
      'action' => '',
      'plotting' => $plotting
    );
    // lookup columns
    $cols = [
      ['name' => 'category', 'label' => 'Groups', 'align' => 'left', 'field' => 'category', 'sortable' => true, 'style' => 'font-size:16px;'],
      ['name' => 'reqtype', 'label' => 'Repacker 1', 'align' => 'left', 'field' => 'reqtype', 'sortable' => true, 'style' => 'font-size:16px;'],
      ['name' => 'code', 'label' => 'Repacker 2', 'align' => 'left', 'field' => 'code', 'sortable' => true, 'style' => 'font-size:16px;'],
      ['name' => 'position', 'label' => 'Repacker 3', 'align' => 'left', 'field' => 'position', 'sortable' => true, 'style' => 'font-size:16px;']
    ];

    $qry = "select  line, category,reqtype,code,position from reqcategory where isrepacker=1 order by line";
    $data = $this->coreFunctions->opentable($qry);
    return ['status' => true, 'msg' => 'ok', 'data' => $data, 'lookupsetup' => $lookupsetup, 'cols' => $cols, 'plotsetup' => $plotsetup];
  } //end function


  public function multiitem($config)
  {
    $companyid = $config['params']['companyid'];
    $doc = $config['params']['doc'];
    $systemtype = $this->companysetup->getsystemtype($config['params']);

    $lookupsetup = array(
      'type' => 'multi',
      'rowkey' => 'keyid',
      'title' => 'List of Item',
      'btns' => [],
      'style' => 'width:100%;max-width:100%;'
    );

    $plotsetup = array(
      'plottype' => 'callback',
      'action' => 'getitem'
    );

    $path = '';
    switch ($config['params']['doc']) {
      case 'DM':
        $path = 'App\Http\Classes\modules\purchase\dm';
        break;
      case 'SJ':
        $path = 'App\Http\Classes\modules\sales\sj';
        if ($companyid == 63) { //ericco
          $path = 'App\Http\Classes\modules\e4c3fe3674108174825a187099e7349f6\sj';
        }
        break;
      case 'CH':
        $path = 'App\Http\Classes\modules\e4c3fe3674108174825a187099e7349f6\ch';
        break;
      case 'SO':
        $path = 'App\Http\Classes\modules\sales\so';
        break;
      case 'CM':
        $path = 'App\Http\Classes\modules\sales\cm';
        break;
      case 'PO':
        $path = 'App\Http\Classes\modules\purchase\po';
        break;
      case 'RR':
        $path = 'App\Http\Classes\modules\purchase\rr';
        break;
    }
    // lookup columns
    $cols = array();
    array_push($cols, array('name' => 'barcode', 'label' => 'Barcode', 'align' => 'left', 'field' => 'barcode', 'sortable' => true, 'style' => 'font-size:16px;'));
    array_push($cols, array('name' => 'itemname', 'label' => 'Itemname', 'align' => 'left', 'field' => 'itemname', 'sortable' => true, 'style' => 'font-size:16px;'));
    array_push($cols, array('name' => 'brandname', 'label' => 'Brand', 'align' => 'left', 'field' => 'brandname', 'sortable' => true, 'style' => 'font-size:16px;'));
    array_push($cols, array('name' => 'amt', 'label' => 'Amount', 'align' => 'right', 'field' => 'amt', 'sortable' => true, 'style' => 'font-size:16px;'));


    //testqry
    switch ($companyid) {
      case 63: //ericco
        switch ($doc) {
          case 'SJ':
          case 'SO':
          case 'CH':
          case 'CM':
            $client = $this->coreFunctions->getfieldvalue(app($path)->head, "client", "trno=?", [$config['params']['trno']]);
            $outlet = $this->coreFunctions->getfieldvalue("client", "groupid", "client=?", [$client]);
            if ($outlet != "") {
              $data = $this->coreFunctions->opentable("select item.itemid as keyid, sizeid,barcode,item.itemid as itemid,item.category,grp.stockgrp_name as groupid,item.othcode,
              item.itemname,s.uom2 as uom,uom1.factor,item.amt,brand,ifnull(cls.cl_name,'') as class,body,
              ifnull(part.part_name,'') as part,ifnull(model.model_name,'') as model,item.disc, item.partno,item.shortname,
              round(item.amt - (item.amt * (REPLACE(item.disc,'%','')/100)),2) as netprice, ifnull(brand.brand_desc,'') as brandname,item.color
              from sku as s join item on item.itemid = s.itemid and s.groupid = '" . $outlet . "' and s.issku = 1
              left join item_class as cls on cls.cl_id=item.class
              left join uom as uom1 on item.itemid = uom1.itemid and uom1.uom = s.uom2
              left join stockgrp_masterfile as grp on grp.stockgrp_id = item.groupid
              left join model_masterfile as model on model.model_id = item.model
              left join part_masterfile as part on part.part_id = item.part
              left join frontend_ebrands as brand on brand.brandid = item.brand
              left join itemcategory as icat on icat.line=item.category");
            } else {
              $data = [];
            }
            break;
          case 'PO':
          case 'RR':
          case 'DM':
            $client = $this->coreFunctions->getfieldvalue(app($path)->head, "client", "trno=?", [$config['params']['trno']]);
            $clientid = $this->coreFunctions->getfieldvalue("client", "clientid", "client=?", [$client]);
            $data = $this->coreFunctions->opentable("select item.itemid as keyid, sizeid,barcode,item.itemid as itemid,item.category,grp.stockgrp_name as groupid,item.othcode,
              item.itemname,s.uom2 as uom,uom1.factor,item.amt,brand,ifnull(cls.cl_name,'') as class,body,
              ifnull(part.part_name,'') as part,ifnull(model.model_name,'') as model,item.disc, item.partno,item.shortname,
              round(item.amt - (item.amt * (REPLACE(item.disc,'%','')/100)),2) as netprice, ifnull(brand.brand_desc,'') as brandname,item.color
              from sku as s join item on item.itemid = s.itemid and s.clientid = '" . $clientid . "' and s.issupplier = 1
              left join item_class as cls on cls.cl_id=item.class
              left join uom as uom1 on item.itemid = uom1.itemid and uom1.uom = s.uom2
              left join stockgrp_masterfile as grp on grp.stockgrp_id = item.groupid
              left join model_masterfile as model on model.model_id = item.model
              left join part_masterfile as part on part.part_id = item.part
              left join frontend_ebrands as brand on brand.brandid = item.brand
              left join itemcategory as icat on icat.line=item.category");
            break;
        }

        break;
      default:
        $data = $this->coreFunctions->opentable("select item.itemid as keyid, sizeid,barcode,item.itemid as itemid,item.category,grp.stockgrp_name as groupid,item.othcode,
      item.itemname,s.uom,uom1.factor,item.amt,brand,ifnull(cls.cl_name,'') as class,body,
      ifnull(part.part_name,'') as part,ifnull(model.model_name,'') as model,item.disc, item.partno,item.shortname,
      round(item.amt - (item.amt * (REPLACE(item.disc,'%','')/100)),2) as netprice, ifnull(brand.brand_desc,'') as brandname,item.color
      from item
      left join item_class as cls on cls.cl_id=item.class
      left join uom as uom1 on item.itemid = uom1.itemid and uom1.uom = item.uom
      left join stockgrp_masterfile as grp on grp.stockgrp_id = item.groupid
      left join model_masterfile as model on model.model_id = item.model
      left join part_masterfile as part on part.part_id = item.part
      left join frontend_ebrands as brand on brand.brandid = item.brand
      left join itemcategory as icat on icat.line=item.category limit 100");

        break;
    }


    return ['status' => true, 'msg' => 'ok', 'data' => $data, 'lookupsetup' => $lookupsetup, 'cols' => $cols, 'plotsetup' => $plotsetup];
  }

