      'style' => 'width:1000px;max-width:1000px;'
    );

    $plotsetup = array(
      'plottype' => 'show',
      'action' => '',
      'callbackfieldhead' => [],
      'callbackfieldlookup' => [],
      'plotting' => []
    );

    $cols = array();
    array_push($cols, array('name' => 'barcode', 'label' => 'Item Code', 'align' => 'left', 'field' => 'barcode', 'sortable' => true, 'style' => 'font-size:16px;'));
    array_push($cols, array('name' => 'itemname', 'label' => 'Item Name', 'align' => 'left', 'field' => 'itemname', 'sortable' => true, 'style' => 'font-size:16px;'));
    array_push($cols, array('name' => 'isqty', 'label' => 'Quantity', 'align' => 'right', 'field' => 'isqty', 'sortable' => true, 'style' => 'font-size:16px;'));
    array_push($cols, array('name' => 'uom', 'label' => 'UOM', 'align' => 'left', 'field' => 'uom', 'sortable' => true, 'style' => 'font-size:16px;'));

    $qry = "select item.barcode,item.itemname,s.uom,s.isqty from lastock as s left join item on item.itemid = s.itemid where s.trno=? and s.cline =?
    union all
    select item.barcode,item.itemname,s.uom,s.isqty from glstock as s left join item on item.itemid = s.itemid where s.trno=? and s.cline =?";

    $trno = isset($config['params']['trno']) ? $config['params']['trno'] : $config['params']['row']['trno'];
    $line = $config['params']['row']['line'];

    $data =  $this->coreFunctions->opentable($qry, [$trno, $line, $trno, $line]);
    return ['status' => true, 'msg' => 'ok', 'data' => $data, 'lookupsetup' => $lookupsetup, 'cols' => $cols, 'plotsetup' => $plotsetup];
  }

  public function lookupqt($config)
  {
    //default
    $lookupclass = $config['params']['lookupclass'];

    $plotting = array('optrno' => 'optrno', 'qtno' => 'docno');
    $client = isset($config['params']['addedparams'][0]) ? $config['params']['addedparams'][0] : '';

    $plottype = 'plothead';

    $title = 'List of Quotations';
    $lookupsetup = array(
      'type' => 'single',
      'title' => $title,
      'style' => 'width:900px;max-width:900px;'
    );
    $plotsetup = array(
      'plottype' => $plottype,
      'action' => '',
      'plotting' => $plotting
    );
    // lookup columns
    $cols = [
      ['name' => 'docno', 'label' => 'Quotation', 'align' => 'left', 'field' => 'docno', 'sortable' => true, 'style' => 'font-size:16px;'],
      ['name' => 'yourref', 'label' => 'PO#', 'align' => 'left', 'field' => 'yourref', 'sortable' => true, 'style' => 'font-size:16px;'],
      ['name' => 'clientname', 'label' => 'Name', 'align' => 'left', 'field' => 'clientname', 'sortable' => true, 'style' => 'font-size:16px;']
    ];

    $qry = "select distinct qshead.docno,qshead.optrno,qshead.yourref,qshead.clientname from qshead left join qsstock on qsstock.trno = qshead.trno where qshead.optrno=0 and qsstock.refx= 0  and qshead.client = ?
            union all
            select distinct  qshead.docno,qshead.optrno,qshead.yourref,qshead.clientname from hqshead as qshead left join hqsstock as qsstock on qsstock.trno = qshead.trno where qshead.optrno=0  and qsstock.refx= 0  and qshead.client = ?
            order by docno";
    $data = $this->coreFunctions->opentable($qry, [$client, $client]);
    return ['status' => true, 'msg' => 'ok', 'data' => $data, 'lookupsetup' => $lookupsetup, 'cols' => $cols, 'plotsetup' => $plotsetup];
  } //end function

