      array('name' => 'address1', 'label' => 'Collection Address', 'align' => 'left', 'field' => 'address1', 'sortable' => true, 'style' => 'font-size:16px;'),
      array('name' => 'cperson', 'label' => 'Collection contact person', 'align' => 'left', 'field' => 'cperson', 'sortable' => true, 'style' => 'font-size:16px;'),
      array('name' => 'contactno2', 'label' => 'Collection contact #', 'align' => 'left', 'field' => 'contactno2', 'sortable' => true, 'style' => 'font-size:16px;')
    );

    $qry = "select address1, cperson, contactno2
      from billingaddr as b 
      where address1<>'' and  b.isinactive <> 1  and b.clientid=?";

    if (isset($config['params']['trno'])) {
      $clientid = $this->othersClass->getclientid($config);
