    }

    $data = $this->coreFunctions->opentable($qry, [$clientid]);
    return ['status' => true, 'msg' => 'ok', 'data' => $data, 'lookupsetup' => $lookupsetup, 'cols' => $cols, 'plotsetup' => $plotsetup];
  }
  public function lookuptruledger($config){

    $plotting = array('client' => 'client', 'clientid' => 'clientid', 'address' => 'address', 'addressno' => 'addressno',
     'clientname' => 'clientname', 'make' => 'make','plateno' => 'plateno', 'color' => 'color', 'motorno' => 'motorno',
     'chassisno' => 'chassisno', 'sidecarno' => 'sidecarno'
    );

    $lookupsetup = array(
      'type' => 'single',
      'title' => 'List of TRU Ledger',
      'style' => 'width:900px;max-width:900px;'
    );
    $plotsetup = array(
      'plottype' => 'plothead',
      'action' => '',
      'plotting' => $plotting
    );

    // lookup columns
    $cols = [
      ['name' => 'clientname', 'label' => 'Client Name', 'align' => 'left', 'field' => 'clientname', 'sortable' => true, 'style' => 'font-size:16px;'],
      ['name' => 'client', 'label' => 'Code', 'align' => 'left', 'field' => 'client', 'sortable' => true, 'style' => 'font-size:16px;'],
    ];
   
  $query = "  
    select client,concat(info.lname,', ',info.fname,' ',info.mname) as clientname,addressno,client.clientid as keyid,
    client.clientid,client.addr as address,client.make,client.plateno,client.color,client.motorno,info.chassisno,info.sidecarno
    from client
    left join clientinfo as info on info.clientid = client.clientid 
    where istru = 1";
    $data = $this->coreFunctions->opentable($query);

    return ['status' => true, 'msg' => 'ok', 'data' => $data, 'lookupsetup' => $lookupsetup, 'cols' => $cols, 'plotsetup' => $plotsetup];
  }

